('2brightsparks-syncbackfree', 'SyncBackFree', 'Windows Backup Software that is free for personal, educational, charity, government, and commercial use.', 'Utilities', '2brightsparks-syncbackfree-icon', ''),
('2brightsparks-syncbackpro', 'SyncBackPro', 'SyncBackPro backup software, the professional''s tool to backup, synchronize, and restore data files.', 'Utilities', '2brightsparks-syncbackpro-icon', ''),
