('ashleystone-sitdownmw', 'SitdownMW', 'Automatically lowers Modern Warfare priority.', 'Utilities', 'ashleystone-sitdownmw-icon', ''),
('asiasoftonline-playparkdownloader', 'Playpark Downloader', 'Playpark Downloader lets you download games from playpark.com. You can also use it to download and apply game updates/patches.', 'Games', 'asiasoftonline-playparkdownloader-icon', ''),
('astrocomma-astrogrep', 'AstroGrep', 'AstroGrep is a Microsoft Windows GUI File Searching (grep) utility. Its features include regular expressions, versatile printing options, stores most recent used paths and has a "context" feature which is very nice for looking at source code.', 'Development', 'astrocomma-astrogrep-icon', ''),
('astronomer-astro', 'Astro CLI', 'To build and run Airflow DAGs locally and interact with the Astronomer API', 'Utilities', 'astronomer-astro-icon', ''),
('asus-armourycrate', 'ArmouryCrate', 'A program that allows you to unify the configuration and control of all ASUS and ROG software and gear.', 'Utilities', 'asus-armourycrate-icon', ''),
('atlassian-sourcetree', 'Sourcetree', 'Sourcetree is a free Git desktop client for developers on Windows. Say goodbye to the command line and use the full capabilities of Git through Sourcetree''s beautifully simple interface (and stop being jealous of what your Mac friends are using).', 'Development', 'atlassian-sourcetree-icon', ''),
('atola-findandmount', 'Find and Mount', 'Partition Find & Mount implements a new concept of deleted or lost partition recovery. It works in the most convenient way possible — by locating and mounting partitions into the system, thus making those lost partitions available to you like any generic disk volume. Partition Find & Mount will also work in case any Boot Record (including the Master Boot Record) is missing, damaged or overwritten.', 'Design', 'atola-findandmount-icon', ''),
('atomixproductions-virtualdj', 'VirtualDJ', 'VirtualDJ is audio and video mixing software.', 'Development', 'atomixproductions-virtualdj-icon', ''),
('atrix-atrixlauncher', 'Artix Game Launcher', 'Artix Entertainment develops free to play browser based video games as well as mobile games!', 'Games', 'atrix-atrixlauncher-icon', ''),
('atticus64-juice', 'Juice', 'A fresh and sweet script to configure and personalize windows terminal', 'Utilities', 'atticus64-juice-icon', ''),
('audacious-mediaplayer', 'Audacious', 'Open source audio player', 'Audio', 'audacious-mediaplayer-icon', ''),
('audacity-audacity', 'Audacity', 'Audacity is a free, easy-to-use, multi-track audio editor and recorder for Windows, macOS, GNU/Linux and other operating systems.', 'Audio', 'audacity-audacity-icon', ''),
