('audius-audius', 'Audius', 'The Audius decentralized application', 'Audio', 'audius-audius-icon', ''),
('auraside-mantle', 'Mantle', 'Mantle is the awesome cape system which works with your favorite clients', 'Utilities', 'auraside-mantle-icon', ''),
