('austinleath-r6rc', 'R6RC', 'A Minimalistic Rank Calculator For Rainbow Six: Siege', 'Utilities', 'austinleath-r6rc-icon', ''),
('authpass-authpass', 'AuthPass', 'Free and Open Source password manager for Android, iOS, MacOS, Linux and Windows. Compatible with KeePass.', 'Office', 'authpass-authpass-icon', ''),
('autohotkey-autohotkey', 'AutoHotkey', 'AutoHotkey is a free, open source macro-creation and automation software utility that allows users to automate repetitive tasks. It is driven by a custom scripting language that has special provision for defining keyboard shortcuts, otherwise known as hotkeys.', 'Utilities', 'autohotkey-autohotkey-icon', ''),
('autoit-autoit', 'AutoIt', 'AutoIt v3 is a freeware BASIC-like scripting language designed for automating the Windows GUI and general scripting. It uses a combination of simulated keystrokes, mouse movement and window/control manipulation in order to automate tasks in a way not possible or reliable with other languages (e.g. VBScript and SendKeys). AutoIt is also very small, self-contained and will run on all versions of Windows out-of-the-box with no annoying “runtimes” required!', 'Design', 'autoit-autoit-icon', ''),
('autodesk-desktopapp', 'Autodesk Desktop App', 'Autodesk desktop app provides lightweight, easy access to products, updates, and security fixes by simplifying the install and update experience on your Windows system.', 'Development', 'autodesk-desktopapp-icon', ''),
('autodesk-eagle', 'EAGLE', 'EAGLE is electronic design automation (EDA) software that lets printed circuit board (PCB) designers seamlessly connect schematic diagrams, component placement, PCB routing and comprehensive library content.', 'Design', 'autodesk-eagle-icon', ''),
('autodesk-sketchbook', 'Sketchbook', 'Application for Artists', 'Design', 'autodesk-sketchbook-icon', ''),
