('automattic-simplenote', 'Simplenote', 'Simplenote is an easy way to keep notes, lists, ideas and more. Your notes stay in sync with all your devices for free.', 'Development', 'automattic-simplenote-icon', ''),
('automattic-wordpress', 'WordPress.com', 'A control panel for all your WordPress sites.', 'Design', 'automattic-wordpress-icon', 'LibreOffice Writer / ONLYOFFICE'),
('autonomoussoftware-metronomewallet', 'Metronome Wallet', 'Metronome Wallet for desktop devices', 'Utilities', 'autonomoussoftware-metronomewallet-icon', ''),
('aveeksaha-duskplayer', 'DuskPlayer', 'A minimal music player for your desktop', 'Audio', 'aveeksaha-duskplayer-icon', ''),
('avisynth-avisynth', 'AviSynth', 'Script-based frameserver for video editing and processing', 'Development', 'avisynth-avisynth-icon', ''),
('avisynth-avisynthplus', 'AviSynth+', 'AviSynth+ is a fork of the well-known frameserver, but with community contributions that avoided mainline inclusion until now. In the hope of modernizing AviSynth to meet present day needs and expectations, the project encourages everybody to help reach our goals: add long-sought features, energize the community, and improve developer and user friendliness. AviSynth+ is fully compatible with plugins and scripts written for AviSynth.', 'Development', 'avisynth-avisynthplus-icon', ''),
('avidemux-avidemux', 'Avidemux', 'Avidemux is a free video editor designed for simple cutting, filtering and encoding tasks.
It supports many file types, including AVI, DVD compatible MPEG files, MP4 and ASF, using a variety of codecs.
Tasks can be automated using projects, job queue and powerful scripting capabilities.', 'Development', 'avidemux-avidemux-icon', ''),
('avocode-avocode', 'Avocode', 'One workspace open to all designers and developers', 'Development', 'avocode-avocode-icon', ''),
('avogadro-avogadro', 'Avogadro', 'Avogadro is an advanced molecular editor designed for cross-platform use in computational chemistry, molecular modeling, bioinformatics, materials science, and related areas. It offers flexible rendering and a powerful plugin architecture.', 'Design', 'avogadro-avogadro-icon', ''),
('awthwathje-steascree', 'SteaScree', 'SteaScree is a simple cross-platform open-source utility app, which makes screenshots, taken without the use of Steam''s in-game overlay, uploadable to the Steam Cloud. You just pick pics, a game and SteaScree will do the rest.', 'Games', 'awthwathje-steascree-icon', ''),
('axcrypt-axcrypt', 'AxCrypt', 'AxCrypt File Encryption Software - Free Personal Privacy and Security for Windows 2000/XP/Vista or later with AES-128 File Encryption, Compression and transparent Decrypt and Open in the original application.', 'Utilities', 'axcrypt-axcrypt-icon', ''),
