('acrosync-duplicacyweb', 'Duplicacy Web Edition', 'This version can be used without a license if you only need the restore, check, copy, and prune operations. If you do need to run backups, a fully functional 30-day trial license will be automatically downloaded to enable the backup operation. After 30 days, a personal or commercial license can be purchased.', 'Utilities', 'acrosync-duplicacyweb-icon', '');

INSERT INTO apps (id, name, description, category, icon, linux_alternative) VALUES
('advancedfx-hlae', 'HLAE', 'Half-Life Advanced Effects (HLAE) is a tool to enrich Source (mainly CS:GO) engine based movie making.', 'Utilities', 'advancedfx-hlae-icon', ''),
('afractal-echo', 'Echo', 'Text to speech desktop app', 'Utilities', 'afractal-echo-icon', ''),
