('agalwood-motrix', 'Motrix', 'Motrix is a full-featured download manager that supports downloading HTTP, FTP, BitTorrent, Magnet, etc.', 'Utilities', 'agalwood-motrix-icon', ''),
('ahkohd-switch', 'Switch', 'Switch between your favourite lightning fast. (Windows, MacOS)', 'Utilities', 'ahkohd-switch-icon', ''),
