('bluejteam-bluej', 'BlueJ', 'A free Java Development Environment designed for beginners, used by millions worldwide.', 'Development', 'bluejteam-bluej-icon', ''),
('bluejeans-bluejeans', 'BlueJeans', 'Empower Your Remote Workforce with Secure Video Conferencing', 'Development', 'bluejeans-bluejeans-icon', ''),
('bluemarblegeographics-globalmapper', 'Global Mapper', 'Global Mapper® is a cutting-edge GIS software that provides both novice and experienced geospatial professionals with a comprehensive array of spatial data processing tools, with access to an unparalleled variety of data formats.', 'Development', 'bluemarblegeographics-globalmapper-icon', ''),
('bluemicrophones-bluesherpa', 'Blue Sherpa', 'Sherpa allows users to control parameters such as microphone gain, mute and headphone volume from the desktop. It also allows updating the microphone firmware.', 'Utilities', 'bluemicrophones-bluesherpa-icon', ''),
('bluestack-bluestacks', 'BlueStacks', 'Experience ultimate gameplay on your PC with the fastest & lightest Android App Player ever built.', 'Games', 'bluestack-bluestacks-icon', ''),
('bluebeam-revu-21', 'Bluebeam Revu 21', 'Revu is Bluebeam''s foundational project efficiency and collaboration solution that allows you to create, edit, mark up, and organize PDFs with project partners on desktop.', 'Design', 'bluebeam-revu-21-icon', ''),
('blueberry-flashbackpro', 'FlashBack Pro 5', 'FlashBack Pro 5 Screen Recorder and Editor for Windows', 'Design', 'blueberry-flashbackpro-icon', ''),
