('crowtranslate-crowtranslate', 'Crow Translate', 'Crow Translate is a simple and lightweight translator written in C++ / Qt that allows you to translate and speak text using Google, Yandex, Bing, LibreTranslate and Lingva translate API.', 'Utilities', 'crowtranslate-crowtranslate-icon', ''),
('crowdsecurity-crowdsec', 'CrowdSec', 'CrowdSec Agent for Windows', 'Utilities', 'crowdsecurity-crowdsec-icon', ''),
