('epicgames-epicgameslauncher', 'Epic Games Launcher', 'The Epic Games Launcher is how you obtain the Unreal Game Engine, modding tools and other Epic Games like Fortnite and the new Epic Games Store.', 'Games', 'epicgames-epicgameslauncher-icon', ''),
('epilogue-epilogueoperator', 'Epilogue Operator', 'Play and manage Game Boy cartridges on your computer. Device driver and operator for the GB Operator.', 'Games', 'epilogue-epilogueoperator-icon', ''),
('epsitec-colobot', 'Colobot: Gold Edition', 'Colobot: Gold Edition is a real-time strategy game, where you can program your units (bots) in a language called CBOT, which is similar to C++ and Java. Your mission is to find a new planet to live and survive. You can save the humanity and get programming skills!', 'Games', 'epsitec-colobot-icon', ''),
('epsitec-planetblupi', 'Planet Blupi', 'Planet Blupi (known as Planet Eggbert too) is a strategy and adventure game. It subtly blends action with thought-provoking challenges. Behind the quiet and gentle facade, you''ll enjoy a fascinating diversion full of surprises.', 'Games', 'epsitec-planetblupi-icon', ''),
