('freefem-freefem', 'FreeFem', 'FreeFEM is a partial differential equation solver for non-linear multi-physics systems in 2D and 3D using the finite element method.', 'Design', 'freefem-freefem-icon', ''),
('freemat-freemat', 'FreeMat', 'FreeMat is a free environment for rapid engineering and scientific prototyping and data processing. It is similar to commercial systems such as MATLAB from Mathworks, and IDL from Research Systems, but is Open Source.', 'Utilities', 'freemat-freemat-icon', ''),
('freepascal-freepascalcompiler', 'Free Pascal Compiler', 'Free Pascal is a mature, versatile, open source Pascal compiler. It can target many processor architectures: Intel x86 (16 and 32 bit), AMD64/x86-64, PowerPC, PowerPC64, SPARC, SPARC64, ARM, AArch64, MIPS, Motorola 68k, AVR, and the JVM. Supported operating systems include Windows (16/32/64 bit, CE, and native NT), Linux, Mac OS X/iOS/iPhoneSimulator/Darwin, FreeBSD and other BSD flavors, DOS (16 bit, or 32 bit DPMI), OS/2, AIX, Android, Haiku, Nintendo GBA/DS/Wii, AmigaOS, MorphOS, AROS, Atari TOS, and various embedded platforms.', 'Development', 'freepascal-freepascalcompiler-icon', ''),
