INSERT INTO apps (id, name, description, category, icon, linux_alternative) VALUES
('futureglobe-dashy', 'Dashy', 'Organize and manage all your files from everywhere on your pc inside one application', 'Development', 'futureglobe-dashy-icon', ''),
('futureglobe-gibu', 'Gibu', 'The easiest way to backup all your github repositories with just a few clicks', 'Development', 'futureglobe-gibu-icon', ''),
('futureglobe-northreader', 'NorthReader', 'A RSS Feed Reader created with love and determination of progression in a pioneer world of digital media.', 'Development', 'futureglobe-northreader-icon', ''),
('fuze-fuze', 'Fuze', 'Per-Machine Installer for Fuze Desktop application', 'Utilities', 'fuze-fuze-icon', ''),
('fxsoundllc-fxsound', 'FxSound', 'Amazing sound for everything you listen to', 'Audio', 'fxsoundllc-fxsound-icon', ''),
('fairdataihub-fairshare', 'FAIRshare', 'FAIRshare is a cross-platform desktop software that allows researchers to easily organize and share their biomedical research data according to applicable FAIR guidelines. In our first phase of development we are implementing a process for making biomedical research software FAIR and also working on supporting the FAIRification of COVID-19 and other infectious disease related research data (immunology, genomics, epidemiology, etc.). Learn more about FAIRshare, its impact, the development timeline, and related resources on our group''s website at https://fairdataihub.org/fairshare.', 'Development', 'fairdataihub-fairshare-icon', ''),
('fairdataihub-soda-for-sparc', 'SODA for SPARC', 'SODA (Software to Organize Data Automatically) for SPARC is an open-source and free cross-platform desktop software intended to facilitate the data organization and submission process for SPARC investigators according to the FAIR SPARC data curation guidelines. The idea for a computer software that assists researchers in curating and sharing their data originated during the SPARC Hackathon in December 2018, where it won the Public''s Choice Award, before receiving support from the National Institutes of Health (NIH) for further development. SODA for SPARC is designed such that users can accomplish all the requirements to submit a SPARC dataset rapidly through a single interface. Moreover, requirements have been broken down into easy-to-perform steps and automation has been integrated to reduce users'' effort to a bare minimum during each step, often to just a few clicks.', 'Development', 'fairdataihub-soda-for-sparc-icon', ''),
('feliskio-sleep-timer', 'Sleep Timer', 'A tool that automatically changes your PC’s power state after a set amount of time', 'Utilities', 'feliskio-sleep-timer-icon', ''),
('felixgborrego-simple-docker-ui', 'SimpleDockerUI', 'Docker UI for Windows, macOS and Linux implemented using Scala.js, React and Electron', 'Utilities', 'felixgborrego-simple-docker-ui-icon', ''),
('fetacore-infinitex', 'InfiniTex', 'A new age editor for academics who seek freedom and people with cryptography needs in rich text environments.', 'Design', 'fetacore-infinitex-icon', ''),
('feugy-melodie', 'Mélodie', 'Melodie is a portable, simple-as-pie music player', 'Audio', 'feugy-melodie-icon', ''),
('filips-firefoxpwa', 'PWAsForFirefox', 'Progressive Web Apps (PWAs) are web apps that use web APIs and features along with progressive enhancement strategy to bring a native app-like user experience to cross-platform web applications. Although Firefox supports many of Progressive Web App APIs, it does not support functionality to install them as a standalone system app with an app-like experience.
This project creates a custom modified Firefox runtime to allow websites to be installed as standalone apps and provides a console tool and browser extension to install, manage and use them.
This package contains only the native part of the FirefoxPWA project. You should also install the browser extension if you haven''t already. You can download it from <https://addons.mozilla.org/firefox/addon/pwas-for-firefox/>.', 'Development', 'filips-firefoxpwa-icon', ''),
('fjsoft-myphoneexplorer', 'MyPhoneExplorer', 'Connect your phone via WiFi, cable or bluetooth and you will be surprised how easy and efficient it will be to manage your phone with our software.', 'Design', 'fjsoft-myphoneexplorer-icon', ''),
('floating-frame', 'Frame', 'Frame is a web3 interface that lets you sign data, manage accounts, run your own connections to Ethereum/IPFS and securely and transparently interact with dapps and web3 protocols.', 'Utilities', 'floating-frame-icon', ''),
('flux-flux', 'f.lux', 'Software to warm up your computer display at night, to match your indoor lighting.', 'Utilities', 'flux-flux-icon', ''),
('fnordsoftware-webmforpremiere', 'WebM for Premiere', 'Download our free Premiere plug-in for WebM, the open movie format created by Google. WebM is the HTML-5 standard video format that relies exclusively on open source and patent-free technology. It uses the VP8 and VP9 video codecs together with the Vorbis and Opus audio codecs, wrapped up in a Matroska container. Like WebM itself, this plug-in is completely open source.', 'Development', 'fnordsoftware-webmforpremiere-icon', 'DaVinci Resolve / Kdenlive'),
('fotor-fotor', 'Fotor', 'Fotor is a powerful image editing program', 'Design', 'fotor-fotor-icon', ''),
('foxglove-studio', 'Foxglove Studio', 'Use interactive visualizations in customizable layouts to quickly understand what your robot is doing.
Foxglove Studio comes with a rich suite of built-in panels that can be arranged into the perfect layout for your task.
Connect directly to a live robot, or inspect pre-recorded data files.', 'Utilities', 'foxglove-studio-icon', ''),
