('giorgiotani-peazip', 'PeaZip', 'PeaZip is a free file archiver utility and rar extractor for Windows and Linux, work with 200+ archive types and variants (7z, ace, arc, bz2, cab, gz, iso, paq, pea, rar, tar, wim, zip, zipx...), handle spanned archives (001, r01, z01...) and support multiple archive encryption standards.', 'Utilities', 'giorgiotani-peazip-icon', ''),
('git-git', 'Git', 'Git for Windows focuses on offering a lightweight, native set of tools that bring the full feature set of the Git SCM to Windows while providing appropriate user interfaces for experienced Git users and novices alike.', 'Development', 'git-git-icon', ''),
('git-mingit', 'MinGit', 'MinGit is an intentionally minimal, non-interactive distribution of Git for Windows, with third-party applications as its intended audience.', 'Development', 'git-mingit-icon', ''),
('gitahead-gitahead', 'GitAhead', 'GitAhead is a graphical Git client designed to help you understand and manage your source code history', 'Development', 'gitahead-gitahead-icon', ''),
('gitextensionsteam-gitextensions', 'Git Extensions', 'Git Extensions is a graphical user interface for Git that allows you to control Git without using the commandline', 'Development', 'gitextensionsteam-gitextensions-icon', ''),
('github-atom', 'Atom', 'A hackable text editor for the 21st Century, free and open source.', 'Development', 'github-atom-icon', ''),
('github-atom-beta', 'Atom Beta', 'A hackable text editor for the 21st Century, free and open source.', 'Development', 'github-atom-beta-icon', ''),
('github-classroomassistant', 'classroom-assistant', 'GitHub Classroom Assistant is a cross-platform desktop application to help you get student repositories for grading.', 'Development', 'github-classroomassistant-icon', ''),
('github-githubdesktop', 'GitHub Desktop', 'Focus on what matters instead of fighting with Git. Whether you''re new to Git or a seasoned user, GitHub Desktop simplifies your development workflow.', 'Development', 'github-githubdesktop-icon', ''),
('github-githubdesktop-beta', 'GitHub Desktop Beta', 'Focus on what matters instead of fighting with Git. Whether you''re new to Git or a seasoned user, GitHub Desktop simplifies your development workflow.', 'Development', 'github-githubdesktop-beta-icon', ''),
('github-gitlfs', 'Git LFS', 'Git Large File Storage is a command line extension and specification for managing large files with Git.', 'Development', 'github-gitlfs-icon', ''),
('github-cli', 'GitHub CLI', 'gh is GitHub on the command line. It brings pull requests, issues, and other GitHub concepts to the terminal next to where you are already working with git and your code.', 'Development', 'github-cli-icon', ''),
('gitlab-gitter', 'Gitter', 'Gitter is a chat and networking platform that helps to manage, grow and connect communities through messaging, content and discovery.', 'Development', 'gitlab-gitter-icon', ''),
('gitlab-runner', 'GitLab Runner', 'GitLab Runner is the open source project that is used to run your CI/CD jobs and send the results back to GitLab.', 'Development', 'gitlab-runner-icon', ''),
('giuspen-cherrytree', 'CherryTree', 'A hierarchical note taking application, featuring rich text and syntax highlighting, storing data in a single xml or sqlite file.', 'Development', 'giuspen-cherrytree-icon', ''),
('glarysoft-filerecoveryfree', 'Glarysoft File Recovery', 'Free File recovery tool', 'Utilities', 'glarysoft-filerecoveryfree-icon', ''),
('glarysoft-glaryutilities', 'Glary Utilities', 'Glary Utilities offers multiple system tools to fix, maintain, and protect your PC.', 'Utilities', 'glarysoft-glaryutilities-icon', ''),
('glasswire-glasswire', 'GlassWire', 'GlassWire is a modern personal firewall and network monitor.', 'Utilities', 'glasswire-glasswire-icon', ''),
('glasswire-glasswire-lite', 'GlassWire', 'GlassWire Lite uses less than 1/3 the memory and writes 1/20th of the disk write operations.', 'Utilities', 'glasswire-glasswire-lite-icon', ''),
('glavsoft-tightvnc', 'TightVNC', 'TightVNC is a free remote desktop application. With TightVNC, you can see the desktop of a remote machine and control it with your local mouse and keyboard, just like you would do it sitting in the front of that computer.', 'Utilities', 'glavsoft-tightvnc-icon', ''),
('glecun-soundboard', 'soundboard', 'A simple soundboard desktop app (like EXP Soundboard).', 'Audio', 'glecun-soundboard-icon', ''),
('glensawyer-mp3gain', 'MP3Gain', 'MP3Gain analyzes and losslessly adjusts mp3 files to a specified target volume.', 'Audio', 'glensawyer-mp3gain-icon', ''),
('glenndelahoy-snappydriverinstallerorigin', 'Snappy Driver Installer Origin', 'Snappy Driver Installer Origin is a portable Windows tool to install and update device drivers. It can be used offline to install drivers where Internet isn’t available. No more searching for drivers after a clean install, just let Snappy Driver Installer Origin do it’s thing and your job will be done in no time. The perfect technician’s tool.', 'Utilities', 'glenndelahoy-snappydriverinstallerorigin-icon', ''),
('glimpse-glimpse', 'Glimpse', 'Glimpse Image Editor is a “fork” or “respin” of the GNU Image Manipulation Program, and it is also an open source image editing application.', 'Design', 'glimpse-glimpse-icon', ''),
('glodon-cadreader', 'CADReader', 'CAD Reader is a fast and easy-to-use DXF & DWG drawing viewer, which can open, view, mark, measure, and share your AutoCAD files easily.', 'Design', 'glodon-cadreader-icon', ''),
('gluon-scenebuilder', 'SceneBuilder', 'Scene Builder is free and open source, but is backed by Gluon. Drag & Drop user interface design allows for rapid iteration.', 'Design', 'gluon-scenebuilder-icon', ''),
('gluon-scenebuilder-18', 'SceneBuilder 18', 'Scene Builder is free and open source, but is backed by Gluon. Drag & Drop user interface design allows for rapid iteration.', 'Design', 'gluon-scenebuilder-18-icon', ''),
('glyphrstudio-desktop', 'Glyphr Studio', 'Glyphr Studio is a free, web based font designer', 'Design', 'glyphrstudio-desktop-icon', ''),
('gnucash-gnucash', 'GnuCash', 'Personal and small-business financial-accounting software', 'Utilities', 'gnucash-gnucash-icon', ''),
('gnupg-gnupg', 'GNU Privacy Guard', 'GnuPG is a complete and free implementation of the OpenPGP standard as defined by RFC4880 (also known as PGP). GnuPG allows you to encrypt and sign your data and communications; it features a versatile key management system, along with access modules for all kinds of public key directories. GnuPG, also known as GPG, is a command line tool with features for easy integration with other applications. A wealth of frontend applications and libraries are available. GnuPG also provides support for S/MIME and Secure Shell (ssh).', 'Development', 'gnupg-gnupg-icon', ''),
('gnupg-gpg4win', 'Gpg4win', 'Gpg4win enables users to securely transport emails and files with the help of encryption and digital signatures. Encryption protects the contents against an unwanted party reading it. Digital signatures make sure that it was not modified and comes from a specific sender.', 'Development', 'gnupg-gpg4win-icon', ''),
('gnuwin32-findutils', 'GnuWin32: FindUtils', '`find'' is a program which searches a directory tree to find a file or group of files. It walks the directory tree and reports all occurences of a file matching the user''s specifications.', 'Utilities', 'gnuwin32-findutils-icon', ''),
('gnuwin32-gettext', 'GnuWin32: GetText', 'GetText: library and tools for native language support', 'Utilities', 'gnuwin32-gettext-icon', ''),
('gnuwin32-grep', 'GnuWin32: Grep', 'Grep searches one or more input files for lines containing a match to a specified pattern. By default, grep prints the matching lines.', 'Utilities', 'gnuwin32-grep-icon', ''),
('gnuwin32-make', 'GnuWin32: Make', 'Make is a tool which controls the generation of executables and other non-source files of a program from the program''s source files. Make gets its knowledge of how to build your program from a file called the makefile, which lists each of the non-source files and how to compute it from other files. When you write a program, you should write a makefile for it, so that it is possible to use Make to build and install the program.', 'Utilities', 'gnuwin32-make-icon', ''),
('gnuwin32-tar', 'Tar', 'The GNU Tar program provides the ability to create tar archives, as well as various other kinds of manipulation', 'Development', 'gnuwin32-tar-icon', ''),
('gnuwin32-tree', 'GnuWin32: Tree', 'A recursive directory listing program that produces a depth indented listing of files.', 'Utilities', 'gnuwin32-tree-icon', ''),
('gnuwin32-unzip', 'GnuWin32: UnZip', 'UnZip is an extraction utility for archives compressed in .zip format (also called "zipfiles"). Although highly compatible both with PKWARE''s PKZIP and PKUNZIP utilities for MS-DOS and with Info-ZIP''s own Zip program, our primary objectives have been portability and non-MSDOS functionality.
UnZip will list, test, or extract files from a .zip archive, commonly found on MS-DOS systems. The default behavior (with no options) is to extract into the current directory (and subdirectories below it) all files from the specified zipfile. A companion program, Zip, creates .zip archives; both programs are compatible with archives created by PKZIP and PKUNZIP for MS-DOS, but in many cases the program options or default behaviors differ. (For example, UnZip recreates the stored directory structure by default; PKUNZIP unpacks all files in the current directory by default.)', 'Utilities', 'gnuwin32-unzip-icon', ''),
('gnuwin32-zip', 'GnuWin32: Zip', 'Zip is a compression and file packaging/archive utility. Although \highly compatible both with PKWARE''s PKZIP and PKUNZIP utilities for MS-DOS and with Info-ZIP''s own UnZip, our primary objectives have been portability and other-than-MSDOS functionality.', 'Utilities', 'gnuwin32-zip-icon', ''),
('gocd-agent', 'GoCD Agent', 'FREE & OPEN SOURCE CI/CD SERVER Easily model and visualize complex workflows with GoCD.', 'Utilities', 'gocd-agent-icon', ''),
('gocd-server', 'GoCD Server', 'FREE & OPEN SOURCE CI/CD SERVER Easily model and visualize complex workflows with GoCD.', 'Utilities', 'gocd-server-icon', ''),
('golang-go-1-17', 'Go 1.17', 'The Go programming language is an open source project to make programmers more productive. Go is expressive, concise, clean, and efficient. Its concurrency mechanisms make it easy to write programs that get the most out of multicore and networked machines, while its novel type system enables flexible and modular program construction. Go compiles quickly to machine code yet has the convenience of garbage collection and the power of run-time reflection. It''s a fast, statically typed, compiled language that feels like a dynamically typed, interpreted language.', 'Development', 'golang-go-1-17-icon', ''),
('golang-go-1-18', 'Go 1.18', 'The Go programming language is an open source project to make programmers more productive. Go is expressive, concise, clean, and efficient. Its concurrency mechanisms make it easy to write programs that get the most out of multicore and networked machines, while its novel type system enables flexible and modular program construction. Go compiles quickly to machine code yet has the convenience of garbage collection and the power of run-time reflection. It''s a fast, statically typed, compiled language that feels like a dynamically typed, interpreted language.', 'Development', 'golang-go-1-18-icon', ''),
('golang-go-1-19', 'Go Programming Language', 'The Go programming language is an open source project to make programmers more productive. Go is expressive, concise, clean, and efficient. Its concurrency mechanisms make it easy to write programs that get the most out of multicore and networked machines, while its novel type system enables flexible and modular program construction. Go compiles quickly to machine code yet has the convenience of garbage collection and the power of run-time reflection. It''s a fast, statically typed, compiled language that feels like a dynamically typed, interpreted language.', 'Development', 'golang-go-1-19-icon', ''),
('golang-go-1-20', 'Go Programming Language', 'The Go programming language is an open source project to make programmers more productive. Go is expressive, concise, clean, and efficient. Its concurrency mechanisms make it easy to write programs that get the most out of multicore and networked machines, while its novel type system enables flexible and modular program construction. Go compiles quickly to machine code yet has the convenience of garbage collection and the power of run-time reflection. It''s a fast, statically typed, compiled language that feels like a dynamically typed, interpreted language.', 'Development', 'golang-go-1-20-icon', ''),
('golang-go-unstable', 'Go (Unstable)', 'The Go programming language is an open source project to make programmers more productive.
 Go is expressive, concise, clean, and efficient.
 Its concurrency mechanisms make it easy to write programs that get the most out of multicore and networked machines, while its novel type system enables flexible and modular program construction.
 Go compiles quickly to machine code yet has the convenience of garbage collection and the power of run-time reflection.
 It''s a fast, statically typed, compiled language that feels like a dynamically typed, interpreted language.', 'Development', 'golang-go-unstable-icon', ''),
('goto-gotoassistagentdesktopconsole', 'GoToAssist Agent Desktop Console', 'GoToAssist Agent Desktop Console is a remote support solution for live end-user support & unattended computer access, featuring: improved keyboard shortcut handling, automatic updates, and multi-session support from a single instance.', 'Utilities', 'goto-gotoassistagentdesktopconsole-icon', ''),
('goldwave-goldwave', 'GoldWave', 'GoldWave is a highly rated, professional digital audio editor that turns your computer or mobile device into a recording studio at your finger tips. Do everything from the simplest recording and editing to the most sophisticated audio processing, restoration, enhancements, and conversions. With millions of downloads over 25 years, GoldWave is a widely used, trusted and dependable program. It is easy to learn and use and is fully accessible, so get started now by downloading the fully functional evaluation version!', 'Development', 'goldwave-goldwave-icon', ''),
('goldwave-videomeld', 'VideoMeld', 'VideoMeld helps you create amazing presentations, attention grabbing YouTube and Facebook videos, and much more:
• Combine any number of audio, video, and image files into a single file
• Create impressive presentations or tutorials with background music, photos, and video
• Edit, crop, and trim videos
• Add text, captions, and scrolling credits
• Master music recordings, keeping instrument and vocal tracks separate
• Add transitions and effects, with fades, green screen, zooming, panning, colour filters, and many others
• Make video recordings of the computer screen (screencasting), ideal for software training videos or demonstrations', 'Development', 'goldwave-videomeld-icon', ''),
('golde-purplepen', 'Purple Pen', 'Simple, versatile, and free course setting software for orienteering', 'Utilities', 'golde-purplepen-icon', ''),
('goldendict-goldendict', 'GoldenDict', 'A feature-rich dictionary lookup program, supporting multiple dictionary formats (StarDict/Babylon/Lingvo/Dictd) and online dictionaries, featuring perfect article rendering with the complete markup, illustrations and other content retained, and allowing you to type in words without any accents or correct case.', 'Design', 'goldendict-goldendict-icon', ''),
('google-androidstudio', 'Android Studio', 'Android Studio is Android''s official IDE. It is purpose-built for Android to accelerate your development and help you build the highest-quality apps for every Android device.', 'Development', 'google-androidstudio-icon', ''),
('google-androidstudio-beta', 'Android Studio Beta', 'Android Studio is Android''s official IDE.
 It is purpose-built for Android to accelerate your development and help you build the highest-quality apps for every Android device.', 'Development', 'google-androidstudio-beta-icon', ''),
('google-androidstudio-canary', 'Android Studio Canary', 'Android Studio is Android''s official IDE.
 It is purpose-built for Android to accelerate your development and help you build the highest-quality apps for every Android device.', 'Development', 'google-androidstudio-canary-icon', ''),
('google-backupandsync', 'Backup and Sync from Google', 'Google Drive client for Windows PC.', 'Utilities', 'google-backupandsync-icon', ''),
('google-chrome', 'Google Chrome', 'A more simple, secure, and faster web browser than ever, with Google’s smarts built-in.', 'Design', 'google-chrome-icon', ''),
('google-chrome-beta', 'Google Chrome Beta', 'Try new features with Chrome Beta', 'Utilities', 'google-chrome-beta-icon', ''),
('google-chrome-canary', 'Google Chrome Canary', 'Get bleeding edge version of Chrome browser with Chrome Canary. Be warned - Canary can be unstable.', 'Utilities', 'google-chrome-canary-icon', ''),
('google-chrome-dev', 'Google Chrome Dev', 'A fast, secure, and free web browser built for the modern web. Chrome syncs bookmarks across all your devices, fills out forms automatically, and so much more.', 'Utilities', 'google-chrome-dev-icon', '');

INSERT INTO apps (id, name, description, category, icon, linux_alternative) VALUES
('google-chromeremotedesktop', 'Chrome Remote Desktop Host', 'This is the hosting component for Chrome Remote Desktop. After installation, follow the instructions at https://remotedesktop.google.com/headless to get connected.', 'Utilities', 'google-chromeremotedesktop-icon', ''),
('google-cloudsdk', 'Google Cloud SDK', 'Tools and libraries for interacting with Google Cloud products and services.', 'Utilities', 'google-cloudsdk-icon', ''),
('google-drive', 'Google Drive', 'Mounts Google Drive(s) as a share drive and streams files as needed from the cloud. Alternative to Google Backup and Sync.', 'Utilities', 'google-drive-icon', ''),
('google-earthpro', 'Google Earth Pro', 'Google Earth lets you fly anywhere on Earth to view satellite imagery, maps, terrain, 3D buildings, from galaxies in outer space to the canyons of the ocean.', 'Design', 'google-earthpro-icon', ''),
('google-firebasecli', 'Firebase CLI Tools', 'The Firebase CLI Tools can be used to test, manage, and deploy your Firebase project from the command line.', 'Utilities', 'google-firebasecli-icon', ''),
('google-googledesktop', 'Google Desktop', 'Google Desktop is a widget engine made by Google.', 'Utilities', 'google-googledesktop-icon', ''),
('google-iapdesktop', 'IAP Desktop', 'IAP Desktop is a Windows application that allows you to manage multiple Remote Desktop connections to Windows VM instances that run on Google Cloud. This is not an officially supported Google product.', 'Utilities', 'google-iapdesktop-icon', ''),
('google-playgames-beta', 'Google Play Games', 'Play Android games from Google Play on Windows PC', 'Games', 'google-playgames-beta-icon', ''),
('google-webdesigner', 'Google Web Designer', 'Google Web Designer gives you the power to create beautiful, engaging HTML5 content. Use animation and interactive elements to bring your creative vision to life, and enjoy seamless integration with other Google products, like Google Drive, Display & Video 360, and Google Ads.', 'Development', 'google-webdesigner-icon', ''),
('gorilladevs-gdlauncher', 'GDLauncher', 'GDLauncher is a custom open-source Minecraft launcher written from the ground up in electron/react. Its main goal is to make it easy and enjoyable to manage different Minecraft versions and install forge/fabric, bringing the playing and modding experience to the next level!', 'Games', 'gorilladevs-gdlauncher-icon', ''),
('gottcode-focuswriter', 'FocusWriter', 'FocusWriter is a simple, distraction-free writing environment. It utilizes a hide-away interface that you access by moving your mouse to the edges of the screen, allowing the program to have a familiar look and feel to it while still getting out of the way so that you can immerse yourself in your work. It’s available for Linux and Windows, and has been translated into many different languages.', 'Development', 'gottcode-focuswriter-icon', ''),
('governikus-ausweisapp2', 'AusweisApp2', 'Die AusweisApp2 ist eine Software, die Sie auf Ihrem Smartphone, Computer oder Tablet installieren, um Ihren Personalausweis, Ihren elektronischen Aufenthaltstitel oder die eID-Karte auszulesen und sich so digital auszuweisen.', 'Development', 'governikus-ausweisapp2-icon', ''),
('graebert-arescommander-2022', 'ARES Commander 2022', 'ARES Commander. Powerful, DWG-based CAD software. The n°1 alternative for CAD in DWG, trusted by industry leaders and millions of users.', 'Design', 'graebert-arescommander-2022-icon', ''),
('graebert-arescommander-2023', 'ARES Commander 2023', 'ARES Commander. Powerful, DWG-based CAD software. The n°1 alternative for CAD in DWG, trusted by industry leaders and millions of users.', 'Design', 'graebert-arescommander-2023-icon', ''),
('graebert-aresmap-2022', 'ARES Map 2022', 'ARES Map is a hybrid solution bringing together the intelligence of GIS contents and a full-featured dwg-based CAD system.', 'Design', 'graebert-aresmap-2022-icon', ''),
('graebert-aresmap-2023', 'ARES Map 2023', 'ARES Map is a hybrid solution bringing together the intelligence of GIS contents and a full-featured dwg-based CAD system.', 'Design', 'graebert-aresmap-2023-icon', ''),
('graebert-aresmechanical-2022', 'ARES Mechanical 2022', 'ARES Mechanical is a Mechanical CAD software combining the DWG-editing features of ARES Commander with industry-specific features for 2D Mechanical Design.', 'Design', 'graebert-aresmechanical-2022-icon', ''),
('graebert-aresmechanical-2023', 'ARES Mechanical 2023', 'ARES Mechanical is a Mechanical CAD software combining the DWG-editing features of ARES Commander with industry-specific features for 2D Mechanical Design.', 'Design', 'graebert-aresmechanical-2023-icon', ''),
('grafanalabs-grafana-enterprise', 'GrafanaEnterprise', 'Grafana allows you to query, visualize, alert on and understand your metrics no matter where they are stored.
Create, explore, and share dashboards with your team and foster a data driven culture.
The Enterprise Edition has the same features as the Open Source Edition and can be used free of charge.
It also has the benefit of allowing an upgrade to the full Enterprise feature set, including support for Enterprise plugins.', 'Utilities', 'grafanalabs-grafana-enterprise-icon', ''),
('grafanalabs-grafana-oss', 'GrafanaOSS', 'Grafana allows you to query, visualize, alert on and understand your metrics no matter where they are stored.
Create, explore, and share dashboards with your team and foster a data driven culture.', 'Utilities', 'grafanalabs-grafana-oss-icon', ''),
('grammarly-grammarly', 'Grammarly for Windows', 'Compose bold, clear, mistake-free writing with Grammarly’s new AI-powered desktop Windows app.', 'Utilities', 'grammarly-grammarly-icon', ''),
('grammarly-grammarly-office', 'Grammarly for Microsoft® Office Suite', 'Grammarly for Microsoft Word and Outlook', 'Office', 'grammarly-grammarly-office-icon', ''),
('gramps-gramps', 'GrampsAIO', 'Gramps is a free software project and community. We strive to produce a genealogy program that is both intuitive for hobbyists and feature-complete for professional genealogists. It is a community project, created, developed and governed by genealogists.', 'Development', 'gramps-gramps-icon', ''),
('graphcool-graphqlplayground', 'GraphQL Playground', 'GraphQL IDE for better development workflows (GraphQL Subscriptions, interactive docs & collaboration)', 'Development', 'graphcool-graphqlplayground-icon', ''),
('graphviz-graphviz', 'Graphviz', 'The Graphviz layout programs take descriptions of graphs in a simple text language, and make diagrams in useful formats, such as images and SVG for web pages; PDF or Postscript for inclusion in other documents; or display in an interactive graph browser. Graphviz has many useful features for concrete diagrams, such as options for colors, fonts, tabular node layouts, line styles, hyperlinks, and custom shapes.', 'Design', 'graphviz-graphviz-icon', ''),
('greenfootteam-greenfoot', 'Greenfoot', 'Greenfoot is an integrated development environment using Java or Stride designed primarily for educational purposes at the high school and undergraduate level. It allows easy development of two-dimensional graphical applications, such as simulations and interactive games.', 'Games', 'greenfootteam-greenfoot-icon', ''),
('greenshot-greenshot', 'Greenshot', 'Greenshot is a screenshot software tool that can be used as an alternative to the Microsoft Snipping Tool. It allows you to create screenshots of a selected region, window or fullscreen. It can also be used to easily annotate, highlight or obfuscate parts of the screenshot.', 'Design', 'greenshot-greenshot-icon', ''),
('gridcoin-client', 'Gridcoin', 'Gridcoin is an open source cryptocurrency that rewards volunteer computing for science through the BOINC platform.', 'Utilities', 'gridcoin-client-icon', ''),
('gruberquentin-stay-hydrated', 'stay-hydrated', 'Reminder to drink water', 'Utilities', 'gruberquentin-stay-hydrated-icon', ''),
('gruntwork-terragrunt', 'Terragrunt', 'Terragrunt is a thin wrapper for Terraform that provides extra tools for keeping your Terraform configurations DRY, working with multiple Terraform modules, and managing remote state.', 'Development', 'gruntwork-terragrunt-icon', ''),
('guilded-guilded', 'Guilded', 'Guilded upgrades your group chat and equips your server with integrated event calendars, forums, and more – 100% free.', 'Games', 'guilded-guilded-icon', ''),
('guinpinsoft-makemkv', 'MakeMKV', 'MakeMKV is your one-click solution to convert video that you own into free and patents-unencumbered format that can be played everywhere.', 'Development', 'guinpinsoft-makemkv-icon', ''),
('guru3d-afterburner', 'Afterburner', 'MSI Afterburner monitoring and GPU overclocking tool', 'Utilities', 'guru3d-afterburner-icon', ''),
('gydi-clashverge', 'Clash Verge', 'A Clash GUI based on tauri.', 'Utilities', 'gydi-clashverge-icon', ''),
('gyan-ffmpeg', 'FFmpeg', 'FFmpeg is a widely-used cross-platform multimedia framework which can process almost all common and many uncommon media formats. It has over 1000 internal components to capture, decode, encode, modify, combine, stream media, and it can make use of dozens of external libraries to provide more capabilities.', 'Development', 'gyan-ffmpeg-icon', ''),
('gyan-ffmpeg-shared', 'FFmpeg (Shared)', 'FFmpeg is a widely-used cross-platform multimedia framework which can process almost all common and many uncommon media formats. It has over 1000 internal components to capture, decode, encode, modify, combine, stream media, and it can make use of dozens of external libraries to provide more capabilities.', 'Development', 'gyan-ffmpeg-shared-icon', ''),
('g07cha-pomodoro', 'Pomodoro', 'Time managment tool for Windows and OS X based on Pomodoro Technique.', 'Utilities', 'g07cha-pomodoro-icon', ''),
('gaubert-gmvault', 'Gmvault', 'Backup and restore your Google Gmail account at will.', 'Utilities', 'gaubert-gmvault-icon', ''),
('gdiobjects-perspective', 'Perspective', 'A Drop-in Replacement for Windows Desktop Background Settings, Perspective is an Automatic Desktop Wallpaper Changer with 44 Eye-Catching Animated Desktop Wallpaper Transitions, and Panoramic / Dual Monitor Support.', 'Development', 'gdiobjects-perspective-icon', ''),
('gdiobjects-fotoxplorer', 'fotoXplorer', 'fotoXplorer is simply the fastest, easiest way to Explore, Organize, and Manage your entire photo collection. It includes a high-speed Photo Viewer designed and coded to leverage today''s multi-core and GPU enhanced PC hardware offerings.', 'Development', 'gdiobjects-fotoxplorer-icon', ''),
('gdiobjects-xbar', 'xBar', 'The Fast & Easy Way to Find and Launch Software Apps, Open Documents, or Access Folders, and Drives in Windows. Quickly Organize Shortcuts into User-defined Categories. View System Details and Monitor your PC’s Performance with CPU, Memory, Temperature, and Battery Sensors.', 'Development', 'gdiobjects-xbar-icon', ''),
('geeksoftwaregmbh-pdf24creator', 'PDF24 Creator', 'A free and easy to use PDF solution with many features', 'Design', 'geeksoftwaregmbh-pdf24creator-icon', ''),
('gerardog-gsudo', 'gsudo', 'A Sudo for Windows - run elevated without spawning a new Console Host Window', 'Utilities', 'gerardog-gsudo-icon', ''),
