('gileli121-windowtop', 'WindowTop', 'Set window on top, make it dark, transparent and more', 'Utilities', 'gileli121-windowtop-icon', ''),
('gitthermal-thermal', 'Thermal', 'Thermal is an open source Electron-based app. It is written in JavaScript and uses Vue.js.', 'Utilities', 'gitthermal-thermal-icon', ''),
('gnome-dia', 'Dia', 'Dia is a GTK+ based diagram creation program for GNU/Linux, MacOS X, Unix, and Windows, and is released under the GPL license.', 'Design', 'gnome-dia-icon', ''),
('gnome-gedit', 'gedit Text Editor', 'A powerful general purpose text editor', 'Design', 'gnome-gedit-icon', ''),
('gnome-gitg', 'gitg', 'gitg is the GNOME GUI client to view git repositories.', 'Development', 'gnome-gitg-icon', ''),
('gnuplot-gnuplot', 'gnuplot', 'A famous scientific plotting package, features include 2D and 3D plotting, a huge number of output formats, interactive input or script-driven options, and a large set of scripted examples.', 'Design', 'gnuplot-gnuplot-icon', ''),
('goatcorp-xivlauncher', 'XIVLauncher', 'XIVLauncher (abbreviated as XL) is a faster launcher for Final Fantasy XIV, with various available addons and enhancements to the game!', 'Games', 'goatcorp-xivlauncher-icon', ''),
('gokcehan-lf', 'lf', 'lf (as in "list files") is a terminal file manager written in Go with a heavy inspiration from ranger file manager.', 'Utilities', 'gokcehan-lf-icon', ''),
('gpodder-gpodder', 'gPodder - Media aggregator and podcast client', 'gPodder is a simple, open source podcast client.', 'Audio', 'gpodder-gpodder-icon', ''),
('gsass1-ntop', 'NTop', 'htop-like system-monitor for Windows with Vi-keybindings', 'Utilities', 'gsass1-ntop-icon', ''),
('gstreamerproject-gstreamer', 'GStreamer', 'GStreamer is a library for constructing graphs of media-handling components.', 'Utilities', 'gstreamerproject-gstreamer-icon', ''),
('gtamas-etcdmanager', 'etcd-manager', 'Modern, efficient and multi-platform GUI for ETCD.', 'Utilities', 'gtamas-etcdmanager-icon', ''),
('guideguide-zxpinstaller', 'ZXPInstaller', 'ZXPInstaller is a simple cross platform (OS X and Windows) installer for third party Adobe extensions (.zxp files). It serves as a replacement for the Extension Manager which no longer is not supported after CC 2014. It provides a drag-and-drop GUI for installation, and a website to which extension developers can point users to download the installer.', 'Development', 'guideguide-zxpinstaller-icon', ''),
('gumengyu-vplayer-next', 'vplayer-next', 'A 163 netease music player (base on vue@3)', 'Audio', 'gumengyu-vplayer-next-icon', ''),
('gurayyarar-snipcommand', 'SnipCommand', 'A free and open source command snippets manager for organize and copy fast.', 'Utilities', 'gurayyarar-snipcommand-icon', ''),
('gurnec-hashcheckshellextension', 'HashCheck Shell Extension', 'HashCheck Shell Extension for Windows with added SHA2, SHA3, and multithreading', 'Utilities', 'gurnec-hashcheckshellextension-icon', ''),
('h2ik-joystickgremlin', 'Joystick Gremlin', 'Joystick Gremlin is a program that allows the configuration of joystick like devices, similar to what CH Control Manager and Thrustmaster''s T.A.R.G.E.T. do for their respectively supported joysticks. However, Joystick Gremlin works with any device be it from different manufacturers or custom devices that appear as a joystick to Windows. Joystick Gremlin uses the virtual joysticks provided by vJoy to map physical to virtual inputs and apply various other transformations such as response curves to analogue axes. In addition to customizing joysticks, Joystick Gremlin also provides powerful macro functionalities, a flexible mode system, scripting using Python, and many other features.', 'Games', 'h2ik-joystickgremlin-icon', ''),
('hddguru-hddllftool', 'Hard Disk Low Level Format Tool', 'This freeware HDD Low Level Format utility can erase, Low-Level Format and re-certify a SATA, IDE, SAS, SCSI, SSD hard disk drive. Will also work with any USB and FIREWIRE external drive enclosures as well as SD, MMC, MemoryStick and CompactFlash media.', 'Development', 'hddguru-hddllftool-icon', ''),
('hddguru-hddrawcopytool', 'HDD Raw Copy Tool', 'HDD Raw Copy Tool is a Windows tool similar in usage to dd on Linux. It lets you raw copy one drive or a image to another drive block by block', 'Design', 'hddguru-hddrawcopytool-icon', ''),
('hdos-hdoslauncher', 'HDOS Launcher', 'HDOS, or High-Detail Old School, is a free-to-use third party client for Old School RuneScape that emulates the aesthetic of 2009 RuneScape HD.', 'Games', 'hdos-hdoslauncher-icon', ''),
('here-olpcli', 'OLP CLI', 'With the Command Line Interface you can access HERE platform services from a command line or with scripts.', 'Utilities', 'here-olpcli-icon', ''),
('hhdsoftware-freehexeditorneo', 'HHD Software Free Hex Editor Neo', 'Freeware binary files editing tool', 'Design', 'hhdsoftware-freehexeditorneo-icon', ''),
('hhdsoftwareltd-virtualserialporttools', 'HHD Software Virtual Serial Port Tools', 'Virtual Serial Port Tools (VSPT) is the ultimate virtual serial ports creation and management application.', 'Utilities', 'hhdsoftwareltd-virtualserialporttools-icon', ''),
('hmsoft-hmnisedit', 'HM NIS Edit', 'HM NIS Edit is the best Editor/IDE for Nullsoft Scriptable Install System (NSIS). Its useful for experts and beginners in the creation of Setup programs with the NSIS. Its Script Wizard will help you to create standard Setup programs with only few clicks, also its InstallOptions designer will help you to create your own custom pages with a friendly drag and drop interface.', 'Development', 'hmsoft-hmnisedit-icon', ''),
('hp-hpcmsl', 'HP Client Management Script Library', 'HP Client Management Script Library is a collection of powershell functions for managing HP BIOS, and streamlining the download and organization of Softpaq downloads.', 'Utilities', 'hp-hpcmsl-icon', ''),
('hp-hpcloudrecoverytool', 'HP Cloud Recovery Tool', 'HP Cloud Recovery Tool allow users to download HP Recovery Media into a USB flash drive to recover their own HP personal system.', 'Utilities', 'hp-hpcloudrecoverytool-icon', ''),
('hp-primevirtualcalculator', 'HP Prime Virtual Calculator', 'Official Emulator of the HP Prime Graphing Calculator for Windows.', 'Utilities', 'hp-primevirtualcalculator-icon', ''),
('hr-crypter', 'Crypter', 'Crypter is a cross-platform crypto app that makes encryption and decryption convenient while still upholding strong security. It tackles one of the weakest links in most security systems today - weak passwords. It simplifies secure password generation and management and requires you to only remember one bit - your MasterPass.', 'Office', 'hr-crypter-icon', ''),
('httptoolkit-httptoolkit', 'HTTP Toolkit', 'HTTP Toolkit is a beautiful & open-source tool for debugging, testing and building with HTTP(S) on Windows, Linux & Mac.', 'Development', 'httptoolkit-httptoolkit-icon', ''),
('hageltechnologiesltd-dumeter', 'DU Meter', 'DU Meter is an Internet usage monitor for your computer. It shows real-time graphs and can create reports and alerts based on your downloads and uploads.', 'Utilities', 'hageltechnologiesltd-dumeter-icon', ''),
('hakuneko-hakuneko', 'HakuNeko Desktop', 'HakuNeko is a cross-platform downloader for manga and anime from various websites. HakuNeko does not host anything by itself.', 'Utilities', 'hakuneko-hakuneko-icon', ''),
('hakuneko-hakuneko-nightly', 'HakuNeko Desktop Nightly', 'HakuNeko is a cross-platform downloader for manga and anime from various websites. HakuNeko does not host anything by itself.', 'Utilities', 'hakuneko-hakuneko-nightly-icon', ''),
('hamsterbase-hamsterbase-server', 'HamsterBase', 'HamsterBase is a self-hosted, local-first web archive application. You can easy highlight and annotate pages, valuing privacy and security.', 'Utilities', 'hamsterbase-hamsterbase-server-icon', ''),
('hamsterrepublic-bobthehamstervga', 'Bob the Hamster VGA', 'Bob the Hamster is a spiffy game, inspired by old arcade classics like `Dig Dug'' and `Mr. Do''. Choose to play as Bob the Hamster and gather carrots, or as Vlad the Hamster and smite foes. Playable in both English and Japanese text modes.', 'Games', 'hamsterrepublic-bobthehamstervga-icon', ''),
('hamsterrepublic-ohrrpgce', 'OHRRPGCE', 'The OHRRPGCE is a free and open-source, cross-platform (Windows, Mac, GNU/Linux, Android), and easy-to-use utility with which you can create your own 2D RPG game in a style similar to the classic Final Fantasy games on the NES, SNES and GBA which have so shaped the RPG genre. No programming is required to create a game, though there is a scripting language for customising the engine which has been used to create many non-RPG games.', 'Games', 'hamsterrepublic-ohrrpgce-icon', ''),
('handbrake-handbrake', 'HandBrake', 'HandBrake is a tool for converting video from nearly any format to a selection of modern, widely supported codecs.', 'Development', 'handbrake-handbrake-icon', ''),
('handyorg-handywinget-gui', 'HandyWinget', 'GUI for installing apps through WinGet and Creating winget manifest file', 'Utilities', 'handyorg-handywinget-gui-icon', ''),
('harmonoid-harmonoid', 'Harmonoid', 'Plays & manages your music library. Looks beautiful & juicy. Playlists, visuals, synced lyrics, pitch shift, volume boost & more.', 'Audio', 'harmonoid-harmonoid-icon', ''),
('harshkhandeparkar-rainbowboard', 'Rainbow Board', '22nd Century Whiteboard App For Linux, Windows and Mac.', 'Utilities', 'harshkhandeparkar-rainbowboard-icon', ''),
('hashicorp-terraform', 'Hashicorp Terraform', 'Terraform enables you to safely and predictably create, change, and improve infrastructure.', 'Utilities', 'hashicorp-terraform-icon', ''),
('hashicorp-vagrant', 'Vagrant', 'Vagrant is a tool for building and distributing development environments.', 'Development', 'hashicorp-vagrant-icon', ''),
('haxefoundation-haxe', 'Haxe', 'Haxe is an open source high-level strictly-typed programming language with a fast optimizing cross-compiler.', 'Development', 'haxefoundation-haxe-icon', ''),
('headsetapp-headset', 'Headset', 'Headset is a simple music player for Mac, Windows and Linux with integrated YouTube search, a home screen with popularity list by genres and eras, and best of all, a radio powered by Reddit. Headset takes the songs that are shared in over 80 music subreddits, categorizes them and plays them automatically. It is a great and pretty unique way to find new music as it is chosen by other humans like you and not by algorithms.', 'Audio', 'headsetapp-headset-icon', ''),
('hearthsim-hearthstonedecktracker', 'Hearthstone Deck Tracker', 'A deck tracker and deck manager for Hearthstone on Windows', 'Games', 'hearthsim-hearthstonedecktracker-icon', ''),
('heaventools-flexhex', 'FlexHEX', 'FlexHEX is an awesome hex editor program specially designed to help you securely inspect and edit binary files, OLE compound files, logical devices, and physical drives.', 'Design', 'heaventools-flexhex-icon', ''),
('heaventools-peexplorer', 'PE Explorer', 'PE Explorer is the most feature-packed program for inspecting the inner workings of your own software, and more importantly, third party Windows applications and libraries for which you do not have source code.', 'Development', 'heaventools-peexplorer-icon', ''),
('heaventools-resourcetuner', 'Resource Tuner', 'Resource Tuner lets you view, extract, replace, edit, and delete the embedded resources of executable files: icons, strings, images, sounds, dialogs, menus - all that make up the visual part of your Windows programs.', 'Audio', 'heaventools-resourcetuner-icon', ''),
('heaventools-resourcetunerconsole', 'Resource Tuner Console', 'Resource Tuner Console is a command-line tool that enables developers to instantly change different resource types (version numbers, icons, images and strings) in large numbers of compiled 32- and 64-bit EXE, DLL and RES files from the batch files.', 'Development', 'heaventools-resourcetunerconsole-icon', ''),
('hedgewars-hedgewars', 'Hedgewars', 'Hedgewars is a turn-based strategy, artillery, action and comedy game, featuring the antics of pink hedgehogs with attitude as they battle from the depths of hell to the depths of space.', 'Games', 'hedgewars-hedgewars-icon', ''),
('heidisql-heidisql', 'HeidiSQL', 'A lightweight client for managing MariaDB, MySQL, SQL Server, PostgreSQL and SQLite, written in Delphi', 'Development', 'heidisql-heidisql-icon', ''),
('hekasoft-backup-restore', 'Hekasoft Backup & Restore', 'Hekasoft Backup & Restore is an all-in-one solution to manage your browser data and settings. Backup your favorite browser’s settings in a single file that you can store on external drive or cd-rom and use it to restore the profile.
Hekasoft Backup & Restore doesn’t limit to backup your softwares, you can migrate your profile from a browser to another and you can optimize your profile folder removing useless files.', 'Utilities', 'hekasoft-backup-restore-icon', ''),
('heliai-blackthunder', 'BlackThunder', 'iOS emulator for Windows, chineese', 'Utilities', 'heliai-blackthunder-icon', ''),
('helio-helioworkstation', 'Helio Workstation', 'One music sequencer for all major platforms, desktop and mobile.', 'Audio', 'helio-helioworkstation-icon', ''),
('helm-helm', 'Helm', 'The Package Manager for Kubernetes', 'Utilities', 'helm-helm-icon', ''),
('helmutbuhler-8gadgetpack', '8GadgetPack', '8GadgetPack makes it possible to use gadgets on Windows 11 / 10 / 8.1 / 7.', 'Development', 'helmutbuhler-8gadgetpack-icon', ''),
('henriwahl-nagstamon', 'Nagstamon', 'Nagstamon is a status monitor for the desktop. It connects to multiple Nagios, Icinga, Opsview, Centreon, Op5 Monitor/Ninja, Checkmk and Thruk monitoring servers.', 'Utilities', 'henriwahl-nagstamon-icon', ''),
('henry++-errorlookup', 'Error Lookup', 'Simple tool for retrieving information about Windows errors codes.', 'Development', 'henry++-errorlookup-icon', ''),
('henry++-memreduct', 'Mem Reduct', 'Lightweight real-time memory management application to monitor and clean system memory on your computer.
The program used undocumented internal system features (Native API) to clear system cache (system working set, working set, standby page lists, modified page lists) with variable result ~10-50%.
Application it is compatible with Windows XP SP3 and higher operating systems, but some general features available only since Windows Vista.', 'Office', 'henry++-memreduct-icon', ''),
('henry++-freeshooter', 'Free Shooter', 'This is old-school tool for taking screenshots without bloatware features, simple as life, light as air.', 'Utilities', 'henry++-freeshooter-icon', ''),
('henry++-simplewall', 'simplewall', 'Simple tool to configure Windows Filtering Platform (WFP) which can configure network activity on your computer.', 'Utilities', 'henry++-simplewall-icon', ''),
('hermannschinagl-linkshellextension', 'Link Shell Extension', 'Link Shell Extension (LSE) provides for the creation of Hardlinks, Junctions, Volume Mountpoints, and Symbolic Links, (herein referred to collectively as Links) a folder cloning process that utilises Hardlinks or Symbolic Links and a copy process taking care of Junctions, Symbolic Links, and Hardlinks. LSE, as its name implies is implemented as a Shell extension and is accessed from Windows Explorer, or similar file/folder managers. The extension allows the user to select one or many files or folders, then using the mouse, complete the creation of the required Links - Hardlinks, Junctions or Symbolic Links or in the case of folders to create Clones consisting of Hard or Symbolic Links. LSE is supported on all Windows versions that support NTFS, Windows 7/8/10. Hardlinks, Junctions and Symbolic Links are NOT supported on FAT file systems, and nor is the Cloning and Smart Copy process supported on FAT file systems.', 'Development', 'hermannschinagl-linkshellextension-icon', ''),
('hermannschinagl-ln', 'Ln - Command line Hardlinks', 'ln is a swiss army knife for hardlinks, symbolic links, junctions when it comes to copying. Further more it provides a incremental copy mechanism called Delorean Copy', 'Development', 'hermannschinagl-ln-icon', ''),
('heroicgameslauncher-heroicgameslauncher', 'Heroic', 'Heroic is an Open Source Game Launcher for Linux, Windows (Beta) and MacOS (Limited to Windows games using Wine/Crossover). Right now it supports launching games from the Epic Games Store using Legendary, a CLI alternative to the Epic Games Launcher. Heroic is built with Web Technologies like: TypeScript, React, NodeJS and Electron.', 'Games', 'heroicgameslauncher-heroicgameslauncher-icon', ''),
('heroku-herokucli', 'heroku', 'The Heroku Command Line Interface (CLI) makes it easy to create and manage your Heroku apps directly from the terminal. It is an essential part of using Heroku.', 'Design', 'heroku-herokucli-icon', ''),
('hesan-he3', 'He3', '200+ tools builtin with more to come. Boosts your productivity with smart search, type detection, and hotkeys. Let it be your best companion in daily dev tasks.', 'Development', 'hesan-he3-icon', ''),
('hex-rays-ida-free', 'IDA Freeware', 'This (completely!) free version of IDA offers a privilege opportunity to see IDA in action. This light but powerful tool can quickly analyze the binary code samples and users can save and look closer at the analysis results.', 'Development', 'hex-rays-ida-free-icon', ''),
('hexchat-hexchat', 'HexChat', 'HexChat is an open source, feature-rich, multi-network IRC client based on XChat. It offers a wide range of features, including Python/Perl scripting, spellcheck, proxies, SASL, DCC support. With an easy to use interface, it offers a great method of chatting online.', 'Development', 'hexchat-hexchat-icon', ''),
('hexandcube-desktopicontoggle', 'Desktop Icon Toggle', 'A simple Windows tool to hide the desktop icons by double-clicking on empty desktop space.', 'Development', 'hexandcube-desktopicontoggle-icon', ''),
('hibitsoftware-hibituninstaller', 'HiBit Uninstaller', 'Completely Uninstall Stubborn Software, Windows Apps & Browser Extension.', 'Utilities', 'hibitsoftware-hibituninstaller-icon', ''),
('hibitsoftware-startupmanager', 'HiBit Startup Manager', 'HiBit Startup Manager is a powerful Startup utility that Manage autostart programs by adding or removing apps, editing their properties and also Manage process, services, task scheduler and context menu.', 'Design', 'hibitsoftware-startupmanager-icon', ''),
('hibbiki-chromium', 'Chromium', 'Stable Chromium build for Windows 64-bit, nothing fancy.', 'Utilities', 'hibbiki-chromium-icon', ''),
('highperformancecoders-scidavis', 'SciDAVis', 'SciDAVis is a free application for Scientific Data Analysis and Visualization.', 'Utilities', 'highperformancecoders-scidavis-icon', ''),
('highresolution-x-mousebuttoncontrol', 'X-Mouse Button Control', 'X-Mouse Button Control (XMBC) allows you to create application and window specific profiles. This in turn, allows you to re-configure your mouse behaviour for individual applications or windows. For each profile you can also configure up to 10 ''layers'' of different button configurations which you can switch between using hot-keys or mouse buttons.', 'Utilities', 'highresolution-x-mousebuttoncontrol-icon', ''),
('hirosystems-clarinet', 'clarinet', 'Clarinet is a Clarity runtime packaged as a command line tool, designed to facilitate smart contract understanding, development, testing and deployment. Clarinet consists of a Clarity REPL and a testing harness, which, when used together allow you to rapidly develop and test a Clarity smart contract, with the need to deploy the contract to a local devnet or testnet.', 'Development', 'hirosystems-clarinet-icon', ''),
('hiroshifuu-onecopy', 'onecopy-electron', 'Save all information and paste them whenever you need them', 'Utilities', 'hiroshifuu-onecopy-icon', ''),
('hirschmann-notebookfancontrol', 'NoteBook FanControl', 'NBFC is a cross-platform fan control service for notebooks. It comes with a powerful configuration system, which allows to adjust it to many different notebook models.', 'Utilities', 'hirschmann-notebookfancontrol-icon', ''),
('homebank-homebank', 'HomeBank', 'HomeBank is a free, open source, personal finance and money management application that can be used to manage your daily and monthly finance details easily as well as effectively.
It has built-in powerful filtering tools and graphs that will help you to analyze your everyday transactions.
It is a cross platform tool which will work on almost all common devices and operating systems, including Linux, Windows, FreeBSD, and Mac OS X.', 'Utilities', 'homebank-homebank-icon', ''),
('huawei-hisuite', 'HiSuite', 'HiSuite lets you manage Huawei mobile devices (such as phones and tablets) from your computer. You can use it to manage, back up, and restore data on your device, such as contacts, messages, and photos, and also to update and recover your device''s system.', 'Design', 'huawei-hisuite-icon', ''),
('huawei-huaweibrowser', 'HUAWEI Browser', 'We put your browsing experience as top priority. Huawei Browser supports phone, tablet and PC users with powerful searching engine and intelligent information. Meanwhile, our powerful privacy protection technology always assures a safe and convenient browsing experience.', 'Utilities', 'huawei-huaweibrowser-icon', ''),
('huawei-huaweicloudmeeting', 'HUAWEI CLOUD Meeting', 'HUAWEI CLOUD Meeting offers secure and reliable videoconferencing with crystal-clear audio and ultra-HD video quality. Hold online meetings with staff or clients from a computer, mobile, or fixed room terminal.', 'Development', 'huawei-huaweicloudmeeting-icon', ''),
('huawei-ideashare', 'IdeaShare', 'Mirror your windows PC screen to Huawei IdeaHub', 'Development', 'huawei-ideashare-icon', ''),
('huawei-ideashareproject', 'Project', 'Huawei Ideashare for OPS computers', 'Development', 'huawei-ideashareproject-icon', ''),
('huawei-quickappide', 'Huawei Quick App IDE', 'A one-stop development tool built on the Visual Studio Code framework. Easy-to-use features include project management, programming, real-time preview, inspection, debugging, and cloud testing.', 'Development', 'huawei-quickappide-icon', ''),
('huawei-quickapppcassistant', 'HuaweiPCAssistant', 'Huawei Quick App PC Assistant allows you to load quick apps to multiple devices and test cards and HAP links. In addition, this assistant allows you to test the functions of the quick app without using IDE.', 'Development', 'huawei-quickapppcassistant-icon', ''),
('huawei-welink', 'Welink', 'A unified communication and collaboration platform that combines persistent workplace chat and video meetings.', 'Development', 'huawei-welink-icon', ''),
('huawei-appgallery', 'AppGallery', 'Software downloader and manager for windows', 'Utilities', 'huawei-appgallery-icon', ''),
('huawei-mobilecloud', 'Huawei Mobile Cloud', 'Safely store and manage your photos, contacts, notes, and other important information on the cloud, and automatically sync your data from any of your mobile devices.', 'Design', 'huawei-mobilecloud-icon', ''),
('hugin-hugin', 'Hugin', 'Panorama photo stitcher', 'Design', 'hugin-hugin-icon', ''),
('hugo-hugo', 'Hugo', 'Hugo is one of the most popular open-source static site generators. With its amazing speed and flexibility, Hugo makes building websites fun again.', 'Office', 'hugo-hugo-icon', ''),
('hugo-hugo-extended', 'Hugo (Extended)', 'Hugo is one of the most popular open-source static site generators. With its amazing speed and flexibility, Hugo makes building websites fun again.
Hugo is available in two flavors: standard and extended. With the extended flavor you can:
- Encode WebP images (decoding is also available in the standard build)
- Transpile Sass to CSS using the embedded LibSass transpiler', 'Development', 'hugo-hugo-extended-icon', ''),
('hulubulusoftware-advancedrenamer', 'Advanced Renamer', 'Batch rename files and folders in a snap. Perfect for any kind of file renaming including music and photo files.', 'Audio', 'hulubulusoftware-advancedrenamer-icon', ''),
('humanity-djv2', 'DJV2', 'DJV Professional playback and review software', 'Utilities', 'humanity-djv2-icon', ''),
('humblebundle-humbleapp', 'Humble App', 'Explore a curated, ever-expanding library of great games, all available in the Humble app while you''re a Humble Choice member.', 'Games', 'humblebundle-humbleapp-icon', ''),
('hybridsaas-hybridsaas', 'hybrid-saas', 'Of u op kantoor of onderweg bent, als u beschikt over een apparaat met een internet verbinding kunt u gebruik maken van Hybrid SaaS, zo beschikken u en uw collega’s real-time de laatste informatie over de projecten van uw bedrijf.', 'Utilities', 'hybridsaas-hybridsaas-icon', ''),
('hydraulic-conveyor', 'Conveyor', 'Conveyor makes distributing desktop and command line apps as easy as shipping a web app.
It''s a tool not a service, it generates self-upgrading packages for Windows, macOS and Linux using each platform''s native package formats without requiring you to have those operating systems.', 'Utilities', 'hydraulic-conveyor-icon', ''),
('hydrologicengineeringcenter-hec-dssvue', 'HEC-DSSVue', 'HEC-DSSVue is a Java-based visual utilities program that allows users to plot, tabulate, edit, and manipulate data in a HEC-DSS database file.', 'Development', 'hydrologicengineeringcenter-hec-dssvue-icon', ''),
('hydrologicengineeringcenter-hec-efm', 'HEC-EFM', 'The Ecosystem Functions Model (HEC-EFM) is designed to help study teams determine ecosystem responses to changes in the flow regime of a river or connected wetland.', 'Design', 'hydrologicengineeringcenter-hec-efm-icon', ''),
('hydrologicengineeringcenter-hec-efmplotter', 'HEC-EFM Plotter', 'HEC-EFM Plotter is designed to help users view, navigate, and interpret output generated by HEC-EFM.', 'Design', 'hydrologicengineeringcenter-hec-efmplotter-icon', ''),
('hydrologicengineeringcenter-hec-fda', 'HEC-FDA', 'HEC-FDA is designed to assist USACE study members in using risk analysis procedures for formulating and evaluating flood risk management measures (EM 1110-2-1619, ER 1105-2-101).', 'Design', 'hydrologicengineeringcenter-hec-fda-icon', ''),
('hydrologicengineeringcenter-hec-hms', 'HEC-HMS', 'The Hydrologic Modeling System (HEC-HMS) is designed to simulate the complete hydrologic processes of dendritic watershed system.', 'Design', 'hydrologicengineeringcenter-hec-hms-icon', ''),
('hydrologicengineeringcenter-hec-metvue', 'HEC-MetVue', 'HEC-MetVue facilitates viewing and manipulation of meteorological datasets as well as performing a variety of computations and analyses, including temporal and spatial aggregation of datasets and areal average computations.', 'Utilities', 'hydrologicengineeringcenter-hec-metvue-icon', ''),
('hydrologicengineeringcenter-hec-ras', 'HEC-RAS', 'The Hydrologic Engineering Center''s River Analysis System (or simply HEC-RAS) is for modeling water flowing through systems of rivers and open channels.
It allows the user to perform one-dimensional steady flow, one and two-dimensional unsteady flow calculations, sediment transport/mobile bed computations, and water temperature/water quality modeling.', 'Design', 'hydrologicengineeringcenter-hec-ras-icon', ''),
('hydrologicengineeringcenter-hec-rpt', 'HEC-RPT', 'Using the software involves two main steps, defining hydrologic conditions or "states" and creating flow recommendations.', 'Utilities', 'hydrologicengineeringcenter-hec-rpt-icon', ''),
('hydrologicengineeringcenter-hec-ressim', 'HEC-ResSim', ' The software simulates reservoir operations for flood management, low flow augmentation and water supply for planning studies, detailed reservoir regulation plan investigations, and real-time decision support.', 'Utilities', 'hydrologicengineeringcenter-hec-ressim-icon', ''),
('hydrologicengineeringcenter-hec-ssp', 'HEC-SSP', 'This software allows users to perform statistical analyses of hydrologic data.', 'Utilities', 'hydrologicengineeringcenter-hec-ssp-icon', ''),
('hydrusnetwork-hydrusnetwork', 'Hydrus Network', 'The hydrus network client is an application written for Anon and other internet-fluent media nerds who have large image/swf/webm collections.
It browses with tags instead of folders, a little like a booru on your desktop. Advanced users can share tags and files anonymously through custom servers that any user may run.
Everything is free and privacy is the first concern. Executable releases are available for Windows, Linux, and macOS.
The program is in python, so you can also run it straight from the source code.', 'Development', 'hydrusnetwork-hydrusnetwork-icon', '');

INSERT INTO apps (id, name, description, category, icon, linux_alternative) VALUES
('hypermodules-hyperamp', 'Hyperamp', 'Indescribable music player', 'Audio', 'hypermodules-hyperamp-icon', ''),
('hyperspacedev-hyperspacedesktop', 'Hyperspace Desktop', 'Socialize and communicate with your friends in the fediverse (ActivityPub-powered social networks like Mastodon and Pleroma) with Hyperspace Desktop. Browse your timelines, check in with friends, and share your experiences across the fediverse in a beautiful, clean, and customizable way.', 'Design', 'hyperspacedev-hyperspacedesktop-icon', ''),
('h3poteto-whalebird-desktop', 'Whalebird', 'An Electron based Mastodon, Pleroma and Misskey client for Windows, Mac and Linux', 'Utilities', 'h3poteto-whalebird-desktop-icon', ''),
('hadolint-hadolint', 'Haskell Dockerfile Linter', 'A smarter Dockerfile linter that helps you build best practice Docker images. The linter parses the Dockerfile into an AST and performs rules on top of the AST. It stands on the shoulders of ShellCheck to lint the Bash code inside RUN instructions.', 'Development', 'hadolint-hadolint-icon', ''),
('hakjav-keyprank', 'KeyPrank', 'The SPACE KeyPrank causes the spacebar on your victim''s computer keyboard to type out the characters ''SPACE'' instead of the normal space character.', 'Utilities', 'hakjav-keyprank-icon', ''),
('hello-efficiency-inc-raven-reader', 'Raven Reader', 'Raven is a open source desktop news reader with flexible settings to optimize your experience. No login is required, and no personal data is collected. Just select the websites you want to curate articles from and enjoy!', 'Design', 'hello-efficiency-inc-raven-reader-icon', ''),
('herrlichmedia-agantty', 'Agantty', 'Free project management for unlimited projects, tasks and teams neatly organized in gantt chart', 'Design', 'herrlichmedia-agantty-icon', ''),
('hfiref0x-winobjex64', 'WinObjEx64', 'WinObjEx64 is an advanced utility that lets you explore the Windows Object Manager namespace.', 'Utilities', 'hfiref0x-winobjex64-icon', ''),
