('jetbrains-hub', 'JetBrains Hub', 'The synergy between team tools. Manage users across Upsource, YouTrack and TeamCity installations, use a centralized dashboard for a quick overview of the relevant commits, issues, or tests. Conduct administrative support for groups and permissions and manage licenses between Upsource and YouTrack.', 'Utilities', 'jetbrains-hub-icon', ''),
('jetbrains-intellijidea-community', 'IntelliJ IDEA Community Edition', 'IntelliJ IDEA is undoubtedly the top-choice IDE for software developers. It makes Java and Kotlin development a more productive and enjoyable experience.', 'Development', 'jetbrains-intellijidea-community-icon', ''),
('jetbrains-intellijidea-community-eap', 'IntelliJ IDEA Community Edition (EAP)', 'IntelliJ IDEA:The Capable & Ergonomic Java IDE by JetBrains. Note, however, that because EAPs are always works in progress, some of their features might not always work as expected.', 'Development', 'jetbrains-intellijidea-community-eap-icon', ''),
('jetbrains-intellijidea-edu', 'IntelliJ IDEA Educational Edition', 'A smart IDE to help you learn and teach programming in Java, Kotlin, and Scala.', 'Development', 'jetbrains-intellijidea-edu-icon', ''),
('jetbrains-intellijidea-ultimate', 'IntelliJ IDEA Ultimate Edition', 'IntelliJ Platform is an OSS platform developed by JetBrains for building IDEs and language-aware developer tools.', 'Development', 'jetbrains-intellijidea-ultimate-icon', ''),
('jetbrains-intellijidea-ultimate-eap', 'IntelliJ IDEA Ultimate Edition (EAP)', 'IntelliJ IDEA:The Capable & Ergonomic Java IDE by JetBrains. Note, however, that because EAPs are always works in progress, some of their features might not always work as expected.', 'Development', 'jetbrains-intellijidea-ultimate-eap-icon', ''),
('jetbrains-mps', 'JetBrains MPS', 'JetBrains MPS is a language workbench developed by JetBrains. MPS is a tool to design domain-specific languages. It uses projectional editing which allows users to overcome the limits of language parsers, and build DSL editors, such as ones with tables and diagrams. It implements language-oriented programming.', 'Development', 'jetbrains-mps-icon', ''),
