('jetbrains-phpstorm', 'PhpStorm', 'PHPStorm is a perfect PHP IDE for working with Symfony, Laravel, Drupal, WordPress, Laminas, Magento, Joomla!, CakePHP, Yii, and other frameworks.', 'Development', 'jetbrains-phpstorm-icon', ''),
('jetbrains-phpstorm-earlyaccess', 'PhpStorm (EAP)', 'PHPStorm is a perfect PHP IDE for working with Symfony, Laravel, Drupal, WordPress, Laminas, Magento, Joomla!, CakePHP, Yii, and other frameworks. Note, however, that because EAPs are always works in progress, some of their features might not always work as expected.', 'Development', 'jetbrains-phpstorm-earlyaccess-icon', ''),
