('jurplel-qview', 'qView', 'qView is an image viewer designed with minimalism and usability in mind.', 'Design', 'jurplel-qview-icon', ''),
('just-install-just-install', 'just-install', 'The simple package installer for Windows', 'Utilities', 'just-install-just-install-icon', ''),
('kcsoftwares-aphemo', 'KC Softwares ApHeMo', 'ApHeMo is a Health Monitoring analyser for Apache HTTP Server. ApHeMo makes administrators able to improve security, reliability and to easily detect attacks from hackers (scans, potential backdoors...).', 'Utilities', 'kcsoftwares-aphemo-icon', ''),
('kcsoftwares-batexpert', 'KC Softwares BATExpert', 'BATExpert gives you a crystal-clear vision of your laptop battery health status. It then recommends upgrade if appropriate.', 'Utilities', 'kcsoftwares-batexpert-icon', ''),
('kcsoftwares-dumo', 'KC Softwares DUMo', 'DUMo (Drivers Update Monitor) keeps your PC up-to-date & safe by using the most recent version of required hardware drivers.', 'Utilities', 'kcsoftwares-dumo-icon', ''),
('kcsoftwares-hddexpert', 'KC Softwares HDDExpert', 'HDDExpert gives you a crystal-clear vision of your Hard Drive (HDD or SSD) health and performance and translates S.M.A.R.T. attributes into readable indication. It then recommends maintenance (fans upgrade, spare purchase, backups and more) depending on the amount of failures detected on your hard drives.', 'Utilities', 'kcsoftwares-hddexpert-icon', ''),
('kcsoftwares-idphotostudio', 'KC Softwares IDPhotoStudio', 'IDPhotoStudio is a user-friendly ID photo duplicator & printer.', 'Design', 'kcsoftwares-idphotostudio-icon', ''),
('kcsoftwares-kcleaner', 'KC Softwares KCleaner', 'KCleaner is designed to be the most efficient Hard Disk cleaner, tracking every useless byte in order to give you all the ressources you may need for your documents, music, pictures, movies etc.', 'Audio', 'kcsoftwares-kcleaner-icon', ''),
('kcsoftwares-masscert', 'KC Softwares MassCert', 'MassCert is a user-friendly batch digital signature utility.', 'Development', 'kcsoftwares-masscert-icon', ''),
('kcsoftwares-phototofilm', 'KC Softwares PhotoToFilm', 'With PhotoToFilm you can easily make small movies out of your pictures and compress them (ie : using DivX) in order to distribute your production to your friends and family.', 'Design', 'kcsoftwares-phototofilm-icon', ''),
('kcsoftwares-portexpert', 'KC Softwares PortExpert', 'PortExpert gives you a detailed vision of your personnal computer cybersecurity. It automatically monitors all applications connected to the Internet and give you all the information you might need to identify potential threats to your system.', 'Development', 'kcsoftwares-portexpert-icon', ''),
('kcsoftwares-ramexpert', 'KC Softwares RAMExpert', 'RAMExpert gives you a crystal-clear vision of your RAM (Random Access Memory) specification. It then recommends upgrade if appropriate.', 'Utilities', 'kcsoftwares-ramexpert-icon', ''),
('kcsoftwares-sumo', 'KC Softwares SUMo', 'SUMo (Software Update Monitor) keeps your PC up-to-date & safe by using the most recent version of your favorite software!', 'Utilities', 'kcsoftwares-sumo-icon', ''),
('kcsoftwares-videoinspector', 'KC Softwares VideoInspector', 'With VideoInspector you''ll know why your video files has no sound or refuses to play correctly. VideoInspector will help you installing the required CoDecs (coder/decoder software) for an optimal performance.', 'Development', 'kcsoftwares-videoinspector-icon', ''),
('kcsoftwares-dot11expert', 'KC Softwares dot11Expert', 'dot11Expert is a troubleshooting software for your WLAN (Wifi network) that gives you detailed technical information about your Wifi network adapters, your Wifi networks and their associated access points.', 'Utilities', 'kcsoftwares-dot11expert-icon', ''),
('kde-amarok', 'Amarok', 'Amarok is a powerful music player for Linux, Unix and Windows with an intuitive interface.', 'Audio', 'kde-amarok-icon', ''),
('kde-dolphin', 'Dolphin', 'Dolphin is KDE''s file manager that lets you navigate and browse the contents of your hard drives, USB sticks, SD cards, and more.', 'Utilities', 'kde-dolphin-icon', ''),
('kde-falkon', 'falkon', 'Falkon is a KDE web browser using QtWebEngine rendering engine, previously known as QupZilla. It aims to be a lightweight web browser available through all major platforms. This project has been originally started only for educational purposes. But from its start, Falkon has grown into a feature-rich browser.', 'Design', 'kde-falkon-icon', ''),
('kde-kdeconnect', 'KDE Connect', 'Enabling communication between all your devices. Made for people like you.', 'Social', 'kde-kdeconnect-icon', ''),
('kde-kdiff3', 'KDiff3', 'Utility for comparing and merging files and directories', 'Utilities', 'kde-kdiff3-icon', ''),
('kde-kate', 'Kate', 'Kate is a feature-packed text editor with syntax highlighting, multi tab view, tool for delevopers and plugins', 'Development', 'kde-kate-icon', ''),
('kde-kdenlive', 'Kdenlive', 'Kdenlive is an acronym for KDE Non-Linear Video Editor. It is primarily aimed at the GNU/Linux platform but also works on BSD and MacOS. It is currently being ported to Windows as a GSOC project.', 'Development', 'kde-kdenlive-icon', ''),
('kde-krita', 'Krita', 'Krita is a FREE and open source painting tool designed for concept artists, illustrators, matte and texture artists, and the VFX industry. Krita has been in development for over 10 years and has had an explosion in growth recently. It offers many common and innovative features to help the amateur and professional alike.', 'Development', 'kde-krita-icon', ''),
('kde-kritashellextension', 'KritaShellExtension', 'An optional add-on for Windows that allow KRA thumbnails to appear in your file browser.', 'Design', 'kde-kritashellextension-icon', ''),
('kde-labplot', 'LabPlot2', 'LabPlot is a KDE-application for interactive graphing and analysis of scientific data. LabPlot provides an easy way to create, manage and edit plots and to perform data analysis.', 'Development', 'kde-labplot-icon', ''),
('kde-marble', 'Marble', 'Explore the neighborhood with Marble''s rich set of city and street level maps. Search for addresses and places of interest. Marble takes care of querying various search backends and presents their results in a unified view. Calculate pedestrian, bike and motorcar routes with ease — online and offline, with an arbitrary number of via points.', 'Utilities', 'kde-marble-icon', ''),
('kde-okular', 'Okular', 'Okular can view and annotate documents of various formats, including PDF, Postscript, Comic Book, and various image formats. It supports native PDF annotations.', 'Design', 'kde-okular-icon', ''),
('kde-okular-nightly', 'Okular', 'Okular can view and annotate documents of various formats, including PDF, Postscript, Comic Book, and various image formats. It supports native PDF annotations.', 'Design', 'kde-okular-nightly-icon', ''),
('kde-digikam', 'digiKam', 'Professional Photo Management with the Power of Open Source', 'Design', 'kde-digikam-icon', ''),
('kde-kdevelop', 'KDevelop', 'A cross-platform IDE for C, C++, Python, QML/JavaScript and PHP', 'Development', 'kde-kdevelop-icon', ''),
('kde-kexi', 'MEXI', 'KEXI is a visual database applications creator. It can be used for designing database applications, inserting and editing data, performing queries, and processing data. Forms can be created to provide a custom interface to your data.', 'Development', 'kde-kexi-icon', ''),
('kde-kile', 'Kile', 'Kile is a user-friendly TeX/LaTeX editor by KDE. Kile gives you the ability to use all the functionality of LaTeX in a graphical interface and has interactive preview mechanisms to readily see the results of editing.', 'Design', 'kde-kile-icon', ''),
('kde-kmymoney', 'KMyMoney', 'A Personal Finance Manager for humans', 'Utilities', 'kde-kmymoney-icon', ''),
('kde-kstars', 'KStars Desktop Planetarium', 'KStars is free, open source, cross-platform Astronomy Software. It provides an accurate graphical simulation of the night sky, from any location on Earth, at any date and time. The display includes up to 100 million stars, 13,000 deep-sky objects,all 8 planets, the Sun and Moon, and thousands of comets, asteroids, supernovae, and satellites.', 'Development', 'kde-kstars-icon', ''),
('kde-rkward', 'RKWard', 'RKWard is an easy to use and easily extensible IDE/GUI for R.', 'Development', 'kde-rkward-icon', ''),
('kde-ruqola', 'Ruqola', 'Native Rocket.Chat client written with Qt', 'Social', 'kde-ruqola-icon', ''),
('kde-umbrello', 'Umbrello', 'Umbrello UML Modeller is a Unified Modelling Language (UML) diagram program based on KDE Technology. UML allows you to create diagrams of software and other systems in a standard format to document or design the structure of your programs.', 'Design', 'kde-umbrello-icon', ''),
('kdani-99-timetable', 'Timetable', 'Simple, useful timetable application', 'Utilities', 'kdani-99-timetable-icon', ''),
('kog-elsworld-en', 'Elsword', 'ELSWORD IS A FREE-TO-PLAY HACK AND SLASH ONLINE ACTION MMORPG', 'Office', 'kog-elsworld-en-icon', 'LibreOffice Writer / ONLYOFFICE'),
('kog-elsworld-es', 'Elsword', 'ELSWORD É UM MMORPG GRATUITO DE AÇÃO HACK E SLASH ONLINE', 'Office', 'kog-elsworld-es-icon', 'LibreOffice Writer / ONLYOFFICE'),
('koggames-elsword', 'Elsword', 'PLAY YOUR MANGA! With manga influenced visuals, Elsword Online is a fun side-scrolling beat ’em up game that gives you the unique virtual experience of playing a moving comic book.', 'Games', 'koggames-elsword-icon', 'LibreOffice Writer / ONLYOFFICE'),
('kook-kook', 'KOOK', 'KOOK is a free and ad-free voice chatting tool. It is available on PC, Android, iOS and web, so you can chat anywhere. There are various themes of servers on KOOK. You can also create your own servers with themes of gaming, music, reading, foreign languages, etc. according to your preferences, and invite your friends to join in chatting.', 'Games', 'kook-kook-icon', ''),
('krtirtho-spotube', 'Spotube', 'Spotube is a Flutter based lightweight spotify client. It utilizes the power of Spotify & Youtube''s public API & creates a hazardless, performant & resource friendly User Experience', 'Audio', 'krtirtho-spotube-icon', ''),
('kydronepilot-spaceeye', 'SpaceEye', 'Live satellite imagery for your desktop background', 'Design', 'kydronepilot-spaceeye-icon', ''),
('kaikramer-keystoreexplorer', 'KeyStore Explorer', 'KeyStore Explorer is a free GUI replacement for the Java command-line utilities keytool and jarsigner', 'Utilities', 'kaikramer-keystoreexplorer-icon', ''),
('kairos-duetdisplay', 'Duet Display', 'Duet Display allows you to use your iPad or iPhone as an extra display.', 'Design', 'kairos-duetdisplay-icon', ''),
('kaitai-structcompiler', 'Kaitai Struct compiler', 'Compiler for Kaitai Struct, a declarative language used to describe various binary data structures, laid out in files or in memory: i.e. binary file formats, network stream packet formats, etc.', 'Development', 'kaitai-structcompiler-icon', '');

