('kamua-tinyvid', 'TinyVid', 'Simple to use video trimmer & compressor', 'Development', 'kamua-tinyvid-icon', ''),
('kanaries-rath', 'Kanaries Rath', 'RATH is beyond an open-source alternative to Data Analysis and Visualization tools such as Tableau. It automates your Exploratory Data Analysis workflow with an Augmented Analytic engine by discovering patterns, insights, causals and presents those insights with powerful auto-generated multi-dimensional data visualization.', 'Design', 'kanaries-rath-icon', ''),
