('kaseya-liveconnect', 'Live Connect', 'This stealth-mode remote control tool features an array of gadgets to help maximize service quality and IT efficiency without disturbing end-users.', 'Utilities', 'kaseya-liveconnect-icon', ''),
('katjahoffmann-tviewer', 'TViewer', 'TViewer is a program to visualize the results of german equestrian competions based on the data of the Toris program', 'Utilities', 'katjahoffmann-tviewer-icon', ''),
