('keepassxcteam-keepassxc', 'KeePassXC', 'KeePassXC is a cross-platform password manager that allows you to store all of your passwords in one location.
A password manager is a tool that creates and stores passwords for you, so you can use many different passwords on different sites and services without having to memorize them.', 'Office', 'keepassxcteam-keepassxc-icon', ''),
('keeweb-keeweb', 'KeeWeb', 'This webapp is a browser and desktop password manager compatible with KeePass databases. It doesnt require any server or additional resources. The app can run either in browser, or as a desktop app.', 'Development', 'keeweb-keeweb-icon', ''),
('keeper-keeperdesktop', 'Keeper® Password Manager', 'Keeper is the top-rated password manager for protecting you, your family and your business from password-related data breaches and cyberthreats.', 'Office', 'keeper-keeperdesktop-icon', 'LibreOffice Writer / ONLYOFFICE'),
('kensington-kensingtonworks', 'KensingtonWorks', 'KensingtonWorks is a tool for personalising your experience with Kensington trackballs and mice', 'Utilities', 'kensington-kensingtonworks-icon', ''),
('keybase-keybase', 'Keybase', 'End-to-end encryption for things that matter. Keybase is secure messaging and file-sharing.', 'Social', 'keybase-keybase-icon', ''),
('keysight-pathwavelicensemanager', 'Keysight PathWave License Manager', 'This license management application allows the user to manage Keysight license types for many Keysight software products and instruments.', 'Utilities', 'keysight-pathwavelicensemanager-icon', ''),
('khronosgroup-vulkansdk', 'Vulkan SDK', 'The Vulkan SDK provides Vulkan application developers with essential tools to accelerate the development process.', 'Development', 'khronosgroup-vulkansdk-icon', ''),
('kicad-kicad', 'KiCad', 'KiCad is a free software suite for electronic design automation. It facilitates the design of schematics for electronic circuits and their conversion to PCB designs.', 'Design', 'kicad-kicad-icon', ''),
('kicad-kicad-lite', 'KiCad Lite EDA', 'KiCad is a free software suite for electronic design automation. It facilitates the design of schematics for electronic circuits and their conversion to PCB designs.', 'Design', 'kicad-kicad-lite-icon', ''),
('kimknight-remoteapptool', 'RemoteApp Tool', 'Create and manage RemoteApps hosted on Windows 7, 8, 10, XP and Server. Generate RDP and MSI files for clients.', 'Utilities', 'kimknight-remoteapptool-icon', ''),
('kingsgroup-kingofavalon', 'King of Avalon', 'King of Avalon is set in a fantasy medieval England bringing back the legend of King Arthur and the Knights of the Round Table.', 'Design', 'kingsgroup-kingofavalon-icon', ''),
('kingsoft-wpsoffice', 'WPS Office', 'WPS Office is a lightweight, feature-rich comprehensive office suite with high compatibility. Capable of handling texts in Writer, Presentation, Spreadsheet, and PDF files, WPS Office serves as a handy and professional office consultant to help you improve work efficiency.', 'Development', 'kingsoft-wpsoffice-icon', ''),
('kingsoft-wpsoffice-cn', 'WPS Office', 'WPS Office is a one-stop office service platform compatible with Word, Excel and PowerPoint. It supports PDF document editing and format conversion, and integrates features such as mind map, flowchart and form.', 'Development', 'kingsoft-wpsoffice-cn-icon', ''),
('kiraku-audiojam', 'Audio Jam', 'If you want to do a good job, you must first sharpen your tools. AudioJam has created a super music learning tool for you. AI separates accompaniment instrument tracks, AB loop segments, adjusts speed and tone Pick up music and practice songs more efficiently.', 'Audio', 'kiraku-audiojam-icon', ''),
('kiraku-neatify', 'Neatify', 'Neatify is a structured knowledge management software that allows you to study effectively and efficiently with tree catalog, tag system, and great reading experience.', 'Design', 'kiraku-neatify-icon', ''),
('kirillosenkov-msbuildstructuredlogviewer', 'MSBuild Structured Log Viewer', 'A logger that can be passed to MSBuild to record a detailed log file and a WPF viewer app to view the log files in a tree form.', 'Utilities', 'kirillosenkov-msbuildstructuredlogviewer-icon', ''),
('kirraenterprises-presenter-express', 'Presenter Version 5 Express Edition', 'Powerful controls, extensive support for all types of media and massive list of features make Presenter 5 the go-to solution for your presentation needs.', 'Office', 'kirraenterprises-presenter-express-icon', ''),
('kirraenterprises-presenter-personal', 'Presenter Version 5 Personal Edition', 'Powerful controls, extensive support for all types of media and massive list of features make Presenter 5 the go-to solution for your presentation needs.', 'Office', 'kirraenterprises-presenter-personal-icon', ''),
('kirraenterprises-presenter-premium', 'Presenter Version 5 Premium Edition', 'Powerful controls, extensive support for all types of media and massive list of features make Presenter 5 the go-to solution for your presentation needs.', 'Office', 'kirraenterprises-presenter-premium-icon', ''),
('kirraenterprises-presenter-standard', 'Presenter Version 5 Standard Edition', 'Powerful controls, extensive support for all types of media and massive list of features make Presenter 5 the go-to solution for your presentation needs.', 'Office', 'kirraenterprises-presenter-standard-icon', ''),
('kitware-cmake', 'CMake', 'CMake is an open-source, cross-platform family of tools designed to build, test and package software. CMake is used to control the software compilation process using simple platform and compiler independent configuration files, and generate native makefiles and workspaces that can be used in the compiler environment of your choice.', 'Development', 'kitware-cmake-icon', ''),
('kitware-paraview', 'ParaView', 'ParaView is an open-source, multi-platform data analysis and visualization application', 'Utilities', 'kitware-paraview-icon', ''),
('kiwix-kiwixjs', 'Kiwix JS', 'Kiwix is an offline reader for content from Wikipedia, Project Gutenberg, TED Talks, Wikivoyage, Stackexchange, etc. It makes knowledge available to people with limited or no Internet access. The software as well as the content is free for anyone to use. It requires an offline ZIM archive (can be downloaded in the app).', 'Office', 'kiwix-kiwixjs-icon', ''),
('kiwix-kiwixjs-electron', 'Kiwix JS Electron', 'Kiwix is an offline reader for content from Wikipedia, Project Gutenberg, TED Talks, Wikivoyage, Stackexchange, etc. It makes knowledge available to people with limited or no Internet access. The software as well as the content are free for anyone to use. It requires an offline ZIM archive (can be downloaded in the app).', 'Office', 'kiwix-kiwixjs-electron-icon', ''),
('kiwix-wikimed', 'WikiMed by Kiwix', 'WikiMed by Kiwix is an offline medical encyclopaedia with content curated by MDwiki and Wikipedia''s WikiProject Medicine. Containing more than 55,000 medical and health-related articles, it makes medical knowledge available to people with limited Internet access or anyone who needs quick reference access to in-depth medical information. The software, as well as the content, is free for anyone to use.', 'Design', 'kiwix-wikimed-icon', ''),
('kiwix-wikimed-electron', 'WikiMed by Kiwix', 'WikiMed by Kiwix is an offline medical encyclopaedia with content curated by MDwiki and Wikipedia''s WikiProject Medicine. Containing more than 55,000 medical and health-related articles, it makes medical knowledge available to people with limited Internet access or anyone who needs quick reference access to in-depth medical information. The software, as well as the content, is free for anyone to use.', 'Design', 'kiwix-wikimed-electron-icon', ''),
('kiwix-wikivoyage', 'Wikivoyage by Kiwix', 'Wikivoyage by Kiwix is an offline travel guide with content provided by Wikimedia''s Wikivoyage project. Containing entries for more than 30,000 locations around the globe, it provides offline information for travellers when on the plane, train or in a remote location with a poor Internet connection.', 'Development', 'kiwix-wikivoyage-icon', ''),
('kiwix-wikivoyage-electron', 'Wikivoyage by Kiwix Electron Edition', 'Wikivoyage by Kiwix is an offline travel guide with content provided by Wikimedia''s Wikivoyage project. Containing entries for more than 30,000 locations around the globe, it provides offline information for travellers when on the plane, train or in a remote location with a poor Internet connection.', 'Development', 'kiwix-wikivoyage-electron-icon', ''),
('klocman-bulkcrapuninstaller', 'BCUninstaller', 'Bulk Crap Uninstaller (or BCUninstaller) is a free (as in speech) program uninstaller.
It excels at removing large amounts of applications with minimal user input. It can clean up leftovers, detect orphaned applications, run uninstallers according to premade lists, and much more!
Even though BCU was made with IT pros in mind, by default it is so straight-forward that anyone can use it.

BCU is fully compatible with Windows Store Apps, Steam, Windows Features and has special support for many uninstalling systems (NSIS, InnoSetup, Msiexec, and many other).', 'Games', 'klocman-bulkcrapuninstaller-icon', ''),
('kobo-kobo', 'Kobo', 'The Kobo Desktop app lets you read and buy eBooks on your PC. You can also use Kobo Desktop to manage eBooks on your eReader.', 'Office', 'kobo-kobo-icon', ''),
('kopia-kopiaui', 'KopiaUI', 'Kopia is a fast and secure open-source backup/restore tool that allows you to create encrypted snapshots of your data and save the snapshots to remote or cloud storage of your choice, to network-attached storage or server, or locally on your machine.
Kopia does not ''image'' your whole machine. Rather, Kopia allows you to backup/restore any and all files/directories that you deem are important or critical.', 'Design', 'kopia-kopiaui-icon', ''),
('korigamik-mangu', 'ManguReader', 'A nice Manga reader with a way to quickly switch between languages. Can be an asset to learning other languages.', 'Office', 'korigamik-mangu-icon', ''),
('kotatogram-kotatogram', 'Kotatogram Desktop', 'Kotatogram Desktop, being based on Telegram Desktop, has all its features, but it also has some more useful and cosmetic features.', 'Social', 'kotatogram-kotatogram-icon', ''),
('koushiknaskar-interactivedataeditor', 'Interactive Data Editor', 'A Software to interactively edit data in a graphical manner.', 'Development', 'koushiknaskar-interactivedataeditor-icon', ''),
('kraxen72-crankshaft', 'crankshaft', 'Crankshaft Krunker Client by KraXen72', 'Utilities', 'kraxen72-crankshaft-icon', ''),
('krisp-krisp', 'Krisp', 'AI-powered app that removes background noise and echo from meetings leaving only human voice.', 'Audio', 'krisp-krisp-icon', ''),
('kristenmcwilliam-nyrna', 'Nyrna', 'Suspend games and applications', 'Games', 'kristenmcwilliam-nyrna-icon', ''),
('kubernetes-kompose', 'kompose', 'Conversion tool for Docker Compose to container orchestrators such as Kubernetes (or OpenShift).', 'Utilities', 'kubernetes-kompose-icon', ''),
('kubernetes-kubectl', 'kubectl', 'A command line tool for communicating with a Kubernetes cluster''s control plane, using the Kubernetes API', 'Utilities', 'kubernetes-kubectl-icon', ''),
('kubernetes-minikube', 'Kubernetes - Minikube - A Local Kubernetes Development Environment', 'minikube implements a local Kubernetes cluster on macOS, Linux, and Windows. minikube''s primary goals are to be the best tool for local Kubernetes application development and to support all Kubernetes features that fit.', 'Development', 'kubernetes-minikube-icon', ''),
('kurtzimmermann-hdcleaner', 'HDCleaner', 'HDCleaner is a utility used to clean potentially unwanted files and invalid Windows Registry entries and speeds up the computer in no time. Optimized for Solid-state drives (SSD) and hard disk drives (HDD). Supports winapp2.ini. Secure deletion of files, hard drives and SSDs.', 'Utilities', 'kurtzimmermann-hdcleaner-icon', ''),
('kurtzimmermann-regcool', 'RegCool', 'RegCool is a very flexible editor for the Windows registry. The program offers an attractive interface, convenient context menus and a handy tool bar, with the extensive editing functions are available at your fingertips. RegCool provides the complete functionality of the Windows own Regedit, but adds a lot of additions. Editing .reg and .hive-Files in Offline Mode (Offline Registry)', 'Development', 'kurtzimmermann-regcool-icon', ''),
('kurtzimmermann-tweakpower', 'TweakPower', 'TweakPower offers you numerous tools for optimizing Windows. All program features of TweakPower are grouped under an attractive user interface and easily accessible. The software makes complicated optimization processes easy even for inexperienced users. TweakPower provides direct access to many system settings and hidden options.', 'Development', 'kurtzimmermann-tweakpower-icon', ''),
('kurtisliggett-simpleipconfig', 'Simple IP Config', 'View and change your local IP addresses.', 'Utilities', 'kurtisliggett-simpleipconfig-icon', ''),
('k6-k6', 'k6', 'k6 is a developer-centric, free and open-source load testing tool built for making performance testing a productive and enjoyable experience. Using k6, you"ll be able to catch performance regression and problems earlier, allowing you to build resilient systems and robust applications.', 'Development', 'k6-k6-icon', ''),
('kalilinux-kalilinux', 'Kali Linux', 'Kali Linux is a Debian-derived Linux distribution designed for digital forensics and penetration testing.', 'Development', 'kalilinux-kalilinux-icon', ''),
('kamranahmedse-pennywise', 'Pennywise', 'Pennywise opens any website or media in a small floating window that remains on top of all other applications. Pennywise windows stays up all the time. No need to keep struggling with Alt + Tab, use Pennywise for easy multitasking.', 'Development', 'kamranahmedse-pennywise-icon', ''),
('kapitainsky-rclonebrowser', 'Rclone Browser', 'GUI Frontend to Rclone (updated fork)', 'Utilities', 'kapitainsky-rclonebrowser-icon', ''),
('karakun-openwebstart', 'OpenWebStart', 'Run Web Start based applications after the release of Java 11', 'Design', 'karakun-openwebstart-icon', ''),
('katahiromz-risoheditor', 'RisohEditor', '"RisohEditor" is a free resource editor for Win32 development, created by Katayama Hirofumi MZ. RisohEditor realized the ideal of resource editor. "Risoh" means "ideal" in Japanese.
RisohEditor can add, edit, extract, clone and remove the resource data in EXE/DLL/RC/RES files.
You can edit Windows resources (Dialogs, Menus, Icons, Cursors, String Tables, Message Tables etc.) by using RisohEditor.', 'Development', 'katahiromz-risoheditor-icon', ''),
('kerinlin-orangeplayer', 'OrangePlayer', 'An audio player to play local audio files and show its audio spectrum.', 'Audio', 'kerinlin-orangeplayer-icon', ''),
('kevinboss-port', 'port', 'A tool that has been designed to manage multiple docker images and / or tags of these images. 
It allows the user to run one of these images / tags in a container, creating snapshots of that running container and manage the downloaded images', 'Design', 'kevinboss-port-icon', ''),
('kilian-fromscratch', 'FromScratch', 'Autosaving Scratchpad. A simple but smart note-taking app', 'Design', 'kilian-fromscratch-icon', ''),
('kimhwan-screenrecorder', 'ScreenRecorder', 'A simple recording program with the ability to record screens and audio on your computer.', 'Audio', 'kimhwan-screenrecorder-icon', ''),
('klatexformula-klatexformula', 'Klatexformula', 'KLatexFormula is an easy-to-use graphical application for generating images (that you can drag and drop, copy and paste or save to disk) from LaTeX equations.', 'Design', 'klatexformula-klatexformula-icon', ''),
('klaussinani-ao', 'Ao', 'Ao is an unofficial, featureful, open source, community-driven, free Microsoft To-Do app.', 'Utilities', 'klaussinani-ao-icon', ''),
('klaussinani-tusk', 'Tusk', 'Refined Evernote desktop app', 'Utilities', 'klaussinani-tusk-icon', ''),
('klinker24-google-calendar-desktop', 'Google Calendar', 'A simple Electron app to display Google Calendar', 'Utilities', 'klinker24-google-calendar-desktop-icon', ''),
('kmeleonbrowser-k-meleon', 'K-Meleon', 'K-Meleon is a very lightweight and fast browser based on Mozilla Gecko.', 'Utilities', 'kmeleonbrowser-k-meleon-icon', ''),
('knoopx-feeder', 'Feeder', 'RSS/Atom Feed reader', 'Office', 'knoopx-feeder-icon', ''),
('ksnip-ksnip', 'ksnip', 'Ksnip is a Qt-based cross-platform screenshot tool that provides many annotation features for your screenshots.', 'Development', 'ksnip-ksnip-icon', ''),
('ktmouk-hackaru', 'Hackaru', 'Hackaru for desktop', 'Utilities', 'ktmouk-hackaru-icon', ''),
('kvakulo-switcheroo', 'Switcheroo', 'Open Window Search, Alt+Tab Alternative', 'Utilities', 'kvakulo-switcheroo-icon', ''),
('kymoto-innoscriptstudio', 'Inno Script Studio', 'Inno Script Studio is a new intuitive graphical interface for generating and compiling scripts for the award winning Inno Setup compiler from Jordan Russell.', 'Development', 'kymoto-innoscriptstudio-icon', ''),
('l0phtholdings-l0phtcrack', 'L0phtCrack', 'L0phtCrack Password Auditor', 'Office', 'l0phtholdings-l0phtcrack-icon', ''),
('laipic-laihuavideo', 'LaiHuaVideo', 'LaiHua Video is a real-time interactive video presentation software that lets you say goodbye to tedious slideshow presentations and makes your video speeches and presentations more vivid and interesting by combining video content and real person on camera.', 'Development', 'laipic-laihuavideo-icon', ''),
('laipic-perfoo', 'Perfoo', 'Perfoo is a presentation tool that is even more impressive than PowerPoint. You can add contents on a borderless canvas easily and create eye-catching presentations with cool animation effects, which greatly improves the efficiency of information delivery and fundamentally reduces the difficulty of audience comprehension.', 'Development', 'laipic-perfoo-icon', ''),
('lammps-lammps', 'LAMMPS -- MD Simulation Software', 'LAMMPS is a classical molecular dynamics code with a focus on materials modeling', 'Development', 'lammps-lammps-icon', ''),
('lammps-lammps-ml-pace', 'LAMMPS ML-PACE Plugin', 'ML-PACE package plugin for the LAMMPS classical molecular dynamics code', 'Development', 'lammps-lammps-ml-pace-icon', ''),
('lammps-lammps-user-aeam', 'LAMMPS USER-AEAM Plugin', 'USER-AEAM package plugin for the LAMMPS classical molecular dynamics code', 'Development', 'lammps-lammps-user-aeam-icon', ''),
('lammps-lammps-user-rebomos', 'LAMMPS USER-REBOMOS Plugin', 'USER-REBOMOS package plugin for the LAMMPS classical molecular dynamics code', 'Development', 'lammps-lammps-user-rebomos-icon', ''),
('lammps-lammps-user-vcsgc', 'LAMMPS USER-VCSGC Plugin', 'USER-VCSGC package plugin for the LAMMPS classical molecular dynamics code', 'Development', 'lammps-lammps-user-vcsgc-icon', ''),
('lbry-lbry', 'LBRY', 'The LBRY Desktop app allows you to view content, upload your digital media accessible for free or at a set price, tip your favorite creators, send/receive LBRY Credits (LBC) and earn Credits through LBRY Rewards. The app and web version run on top of the LBRY protocol which is a peer to peer (P2P), decentralized file sharing and payment network secured by blockchain technology.', 'Development', 'lbry-lbry-icon', ''),
('lego-mindstormseduev3classroom', 'LEGO® MINDSTORMS® Education EV3 Classroom', 'LEGO Mindstorms EV3 programing enviroment for education.', 'Utilities', 'lego-mindstormseduev3classroom-icon', ''),
('lgelectronics-lgbridge', 'LG Bridge', 'LG Bridge', 'Utilities', 'lgelectronics-lgbridge-icon', ''),
('lgelectronics-smartshare', 'LG SmartShare', 'LG TVs - Smart Share', 'Design', 'lgelectronics-smartshare-icon', ''),
('lgug2z-komorebi', 'komorebi', 'A tiling window manager for Windows', 'Design', 'lgug2z-komorebi-icon', ''),
('lgug2z-whkd', 'whkd', 'A simple hotkey daemon for Windows', 'Utilities', 'lgug2z-whkd-icon', ''),
('lightninguk-imgburn', 'ImgBurn', 'With ImgBurn you can burn CDs, DVDs and Blu-ray dics. The software can also read CD and DVD images and copy them. The usage is very simple. Just select the right image and the burning procedure can start.', 'Design', 'lightninguk-imgburn-icon', ''),
('line-line', 'LINE', 'LINE reshapes communication around the globe, allowing you to enjoy not only messaging but also free voice and video calls wherever you find yourself.
Download LINE and discover the reasons for its global popularity and number one ranking in 52 countries.', 'Development', 'line-line-icon', ''),
('linqpad-linqpad-5', 'LINQPad 5', 'LINQPad is not just for LINQ queries, but any C#/F#/VB expression, statement block or program. Put an end to those hundreds of Visual Studio Console projects cluttering your source folder and join the revolution of LINQPad scripters and incremental developers.', 'Development', 'linqpad-linqpad-5-icon', ''),
('linqpad-linqpad-6', 'LINQPad 6', 'LINQPad is not just for LINQ queries, but any C#/F#/VB expression, statement block or program. Put an end to those hundreds of Visual Studio Console projects cluttering your source folder and join the revolution of LINQPad scripters and incremental developers.', 'Development', 'linqpad-linqpad-6-icon', ''),
('linqpad-linqpad-7', 'LINQPad 7', 'LINQPad is not just for LINQ queries, but any C#/F#/VB expression, statement block or program.
Put an end to those hundreds of Visual Studio Console projects cluttering your source folder and join the revolution of LINQPad scripters and incremental developers.', 'Development', 'linqpad-linqpad-7-icon', ''),
('llvm-llvm', 'LLVM', 'The LLVM Project is a collection of modular and reusable compiler and toolchain technologies.', 'Development', 'llvm-llvm-icon', ''),
('lmms-lmms', 'LMMS', 'LMMS is a free cross-platform alternative to commercial programs like FL Studio®, which allow you to produce music with your computer. This includes the creation of melodies and beats, the synthesis and mixing of sounds, and arranging of samples. You can have fun with your MIDI-keyboard and much more; all in a user-friendly and modern interface.', 'Audio', 'lmms-lmms-icon', ''),
('ln-zap-zap', 'Zap', 'Zap is a free Lightning Network wallet focused on user experience and ease of use, with the overall goal of helping the cryptocurrency community scale Bitcoin.', 'Utilities', 'ln-zap-zap-icon', ''),
('loot-loot', 'LOOT', 'Setting the right load order for your TES III: Morrowind, TES IV: Oblivion, Nehrim: At Fate''s Edge, TES V: Skyrim, TES V: Skyrim Special Edition, TES V: Skyrim VR, Fallout 3, Fallout: New Vegas, Fallout 4 and Fallout 4 VR mods is a crucial step to enjoying a stable modded game. The Load Order Optimisation Tool (LOOT) can help with that, by providing automated load order sorting that''s simple to use and fully customisable.', 'Games', 'loot-loot-icon', ''),
('lsofttechnologies-activebootdisk', 'Active@ Boot Disk', 'Active@ Boot Disk is a complete and functioning computer operating system on CD/DVD/USB disk. Boot Disk does not modify the operating system already installed on a computer''s hard drive. It includes many tools to boot up a computer and fix most startup, PC configuration, and system management problems.', 'Design', 'lsofttechnologies-activebootdisk-icon', ''),
('lsofttechnologies-activedvderaser', 'Active@ DVD Eraser', 'Active@ DVD Eraser is an easy-to-use free software to erase Blu-ray, DVD-RW, DVD+RW or CD-RW media to clear the old data from the discs.', 'Utilities', 'lsofttechnologies-activedvderaser-icon', ''),
('lsofttechnologies-activedataburner', 'Active@ Data Burner', 'Active@ Data CD/DVD/Blu-ray Burner is a dialog-style software to burn Data CD/DVD/Blu-ray discs.', 'Utilities', 'lsofttechnologies-activedataburner-icon', ''),
('lsofttechnologies-activedatastudio', 'Active@ Data Studio', 'Active@ Data Studio is a set of desktop applications and a bootable CD/DVD or USB Disk for booting up any system into a Windows Recovery Environment.', 'Utilities', 'lsofttechnologies-activedatastudio-icon', ''),
('lsofttechnologies-activediskeditor', 'Active@ Disk Editor', 'Active@ Disk Editor is an advanced tool for viewing and editing of raw data (sectors) on physical hard disks. Inspect file structures and edit data directly in volumes, partitions and files with integrated support of MBR, GPT, NTFS, FAT, exFAT, HFS+, ext2, ext3, ext4, UFS and LDM structures.', 'Design', 'lsofttechnologies-activediskeditor-icon', ''),
('lsofttechnologies-activediskimage', 'Active@ Disk Image', 'Active@ Disk Image is a disk image software that makes an exact copy of any PC disk (HDD, SSD, USB, CD, DVD, Blu-ray etc.) and stores it into a folder. The disk images may be used for backups, PC upgrades or disk duplication purposes. In case of computer failure, a backup image may be used to recover your computer system or find and restore any necessary files from within an image.', 'Design', 'lsofttechnologies-activediskimage-icon', ''),
('lsofttechnologies-activediskmonitor', 'Active@ Disk Monitor', 'Active@ Disk Monitor - monitors HDD health and status', 'Utilities', 'lsofttechnologies-activediskmonitor-icon', ''),
('lsofttechnologies-activefilerecovery', 'Active@ File Recovery', 'Efficient and easy to use tool for restoring deleted or lost files, damaged or re-formatted volumes, even if your PC doesn''t boot. Recovers data from NTFS, ReFS, FAT, exFAT, HFS+, ApFS, XFS, JFS, UFS, Ext2/3/4, BtrFS. Includes advanced disk editor, Virtual RAID re-constructor (recover damaged RAID disk arrays) and File Organizer to re-organize and rename files detected by their signatures.', 'Design', 'lsofttechnologies-activefilerecovery-icon', ''),
('lsofttechnologies-activeisoburner', 'Active@ ISO Burner', 'Active@ ISO Burner is a simple-to-use dialog-style freeware application that will allow you to burn an ISO image file to CD-R, DVD-R, DVD+R, CD-RW, DVD-RW,DL DVD+RW, HD DVD and Blu-ray Discs.', 'Design', 'lsofttechnologies-activeisoburner-icon', ''),
('lsofttechnologies-activeisomanager', 'Active@ ISO Manager', 'Active@ ISO Manager is easy-to use software to author, edit and burn CD/DVD-ROM ISO images compatible with the ISO 9660 / Joliet standards. You can create ISO images from either existing CD/DVD-ROMs or from a set of existing files and folders.', 'Design', 'lsofttechnologies-activeisomanager-icon', ''),
('lsofttechnologies-activekilldisk', 'Active@ KillDisk', 'Active@ Kill Disk is a hard drive eraser software for secure formatting of hard drives without any possibility of following data recovery.', 'Utilities', 'lsofttechnologies-activekilldisk-icon', ''),
('lsofttechnologies-activelivecd', 'Active@ LiveCD', 'Active@ LiveCD combines a number of powerful tools that let you recover lost data, reset Windows passwords, make computer system backups and securely erase data.', 'Office', 'lsofttechnologies-activelivecd-icon', ''),
('lsofttechnologies-activepartitionmanager', 'Active@ Partition Manager', 'Active@ Partition Manager creates, formats and manages disks', 'Design', 'lsofttechnologies-activepartitionmanager-icon', ''),
('lsofttechnologies-activepartitionrecovery', 'Active@ Partition Recovery', 'Active@ Partition Recovery is a freeware toolkit that helps to recover deleted and damaged logical drives and partitions within Windows, WinPE (recovery boot disk) and Linux (recovery LiveCD) environments.', 'Design', 'lsofttechnologies-activepartitionrecovery-icon', ''),
('lsofttechnologies-activepasswordchanger', 'Active@ Password Changer', 'Active@ Password Changer is a solution designed for resetting local user password and account attributes on Windows XP, Vista, Server 2003 / 2008 / 2012 / 2016, Windows 7, Windows 8, Windows 10 systems in case of Administrator’s password is forgotten, lost or user account has been blocked, disabled or locked out. You will not need to re-install and re-configure operating system in this case. With Active@ Password Changer you can log in as a particular user with an empty password.', 'Design', 'lsofttechnologies-activepasswordchanger-icon', 'LibreOffice Writer / ONLYOFFICE'),
('lsofttechnologies-activeundelete', 'Active@ UNDELETE', 'Active@ UNDELETE helps you to recover deleted files and restore deleted partitions from a variety of file systems such as FAT, NTFS, NTFS + EFS, MacOS HFS+, ApFS, Linux ext2, ext3, ext4, ZFS, Unix UFS. Advanced scan algorithms help to restore files even from severely damaged disks. Sophisticated user-friendly UI makes navigation through your data a breeze.', 'Design', 'lsofttechnologies-activeundelete-icon', ''),
('lsofttechnologies-activeuneraser', 'Active@ UNERASER', 'Active@ UNERASER recovers deleted files and folders on NTFS, FAT, exFAT, Linux Ext2/Ext3/Ext4/BtrFS, Apple HFS+, ApFS and Unix UFS file systems. It can even restore files from deleted and reformatted partitions.', 'Design', 'lsofttechnologies-activeuneraser-icon', ''),
('lsofttechnologies-activezdelete', 'Active@ ZDelete', 'ZDelete is a data cleanup and erase utility that can delete selected folders and groups of files without any possibility of data recovery afterward. Conforms to US Department of Defense clearing and sanitizing standard DoD 5220.22-M.', 'Design', 'lsofttechnologies-activezdelete-icon', ''),
('lsofttechnologies-ntfsdatarecovery', 'NTFS Data Recovery', 'NTFS Data Recovery Toolkit is a set of tools for analyzing problems with NTFS partitions and files, and Data Recovering in Manual and Automated modes.', 'Design', 'lsofttechnologies-ntfsdatarecovery-icon', ''),
('lsofttechnologies-unformat', 'UNFORMAT', 'UNFORMAT is a software utility created to solve almost all data loss scenarios due to logical failure. It can recover deleted files on a disk or restore deleted or damaged partitions and volumes. As well as recovers data after using the FORMAT command.', 'Design', 'lsofttechnologies-unformat-icon', ''),
('luphysics-pymoda', 'PyMODA', 'PyMODA is a Python implementation of MODA (Multiscale Oscillatory Dynamics Analysis), a numerical toolbox developed by the Nonlinear & Biomedical Physics group at Lancaster University and the Nonlinear Dynamics and Synergetic Group at the Faculty of Electrical Engineering, University of Ljubljana, Slovenia under the supervision of Aneta Stefanovska.', 'Development', 'luphysics-pymoda-icon', ''),
('lwks-lightworks', 'Lightworks', 'Lightworks is a non-linear editing system (NLE) for editing and mastering digital video.', 'Development', 'lwks-lightworks-icon', ''),
('lx-systems-winmute', 'WinMute', 'WinMute lets you automatically mute your PC volume on certain events.', 'Utilities', 'lx-systems-winmute-icon', ''),
('lacymorrow-crossover', 'CrossOver', 'CrossOver allows you to place a customizable crosshair overlay above any application window. Improve your aim and gain a competitive advantage with a permanant colored crosshair to mark center screen.', 'Games', 'lacymorrow-crossover-icon', ''),
('lakes-screenview', 'Lakes Environmental SCREEN View', 'SCREEN View can model scenarios with simple or complex terrain, with or without building downwash and give results at discrete or automated distances. SCREEN3 is the screening version of the ISC3 model. Preliminary modeling with SCREEN View can remove the need for more complicated modeling, saving you time and resources.', 'Design', 'lakes-screenview-icon', ''),
('languagetool-languagetool', 'LanguageTool', 'LanguageTool Desktop app for Windows', 'Utilities', 'languagetool-languagetool-icon', ''),
('lansweeper-lsagent', 'LsAgent', 'LsAgent gathers the asset data locally and then sends it back to your Lansweeper installation, either by using a direct push or through Lansweeper''s cloud-hosted relay service.', 'Utilities', 'lansweeper-lsagent-icon', ''),
('lapce-lapce', 'Lapce', 'Lightning-fast and Powerful Code Editor written in Rust', 'Development', 'lapce-lapce-icon', ''),
('lastfm-lastfmdesktopscrobbler', 'Last.fm Desktop Scrobbler', 'Track the music you listen to by scrobbling', 'Audio', 'lastfm-lastfmdesktopscrobbler-icon', ''),
('laurentprenedecotret-pandoc-plot', 'pandoc-plot', 'A pandoc filter to generate figures from source code', 'Development', 'laurentprenedecotret-pandoc-plot-icon', ''),
('lauriethefish-questpatcher', 'QuestPatcher', 'QuestPatcher is a GUI based mod installer for any il2cpp unity app on the Oculus Quest that runs on Windows or Linux. It was originally created for modding Gorilla Tag.', 'Utilities', 'lauriethefish-questpatcher-icon', ''),
('lazarus-lazarus', 'Lazarus', 'Lazarus is a Delphi compatible cross-platform IDE for Rapid Application Development. It has variety of components ready for use and a graphical form designer to easily create complex graphical user interfaces.', 'Development', 'lazarus-lazarus-icon', ''),
('lazesoft-lazesoftrecovery', 'Lazesoft Recovery Suite', 'Lazesoft Recovery Suite is a very easy to use ALL-IN-ONE boot disk that repair your crashed Windows, recover data from deleted, formatted, damaged partition, clone or backup disk, reset your forgotten Windows password.', 'Design', 'lazesoft-lazesoftrecovery-icon', ''),
('legithubdetai-animeback', 'AnimeBack', 'anime your wallpaper ! and create your extensions', 'Utilities', 'legithubdetai-animeback-icon', ''),
('lengockhoa-laragon', 'Laragon', 'Laragon is a portable, isolated, fast & powerful universal development environment for PHP, Node.js, Python, Java, Go, Ruby. It is fast, lightweight, easy-to-use and easy-to-extend. It is great for building and managing modern web applications. It is focused on performance - designed around stability, simplicity, flexibility and freedom. Laragon is very lightweight and will stay as lean as possible. The core binary itself is less than 2MB and uses less than 4MB RAM when running.', 'Development', 'lengockhoa-laragon-icon', ''),
('learnpulse-screenpresso', 'Screenpresso', 'Screenpresso captures your desktop (screenshots and HD videos) for your training documents, collaborative design work, IT bug reports, and more.', 'Development', 'learnpulse-screenpresso-icon', ''),
('leawosoftware-blu-rayplayer', 'Leawo Blu-ray Player', 'All-in-one media player to watch HD movies on Windows 8 (Compatible with Windows 10)', 'Audio', 'leawosoftware-blu-rayplayer-icon', ''),
('ledgerhq-ledgerlive', 'Ledger Live', 'Ledger Live is backed up by the most trusted hardware wallet in the market. Ledger hardware wallets provide the best security & full ownership of your crypto assets.', 'Development', 'ledgerhq-ledgerlive-icon', ''),
('lelanceflamer-tlfdadidw', 'Tous les fichiers dll avec des images dans Windows (TE)', 'Tous les fichiers .dll avec des images dans Windows', 'Design', 'lelanceflamer-tlfdadidw-icon', ''),
('lenovo-dockmanager', 'Lenovo Dock Manager', 'A new solution to improve the large scale deployment of firmware updates for Lenovo docks', 'Utilities', 'lenovo-dockmanager-icon', ''),
('lenovo-legionaccessorycentral', 'Legion Accessory Central', 'A utility to help you configure some Lenovo Legion accesories.', 'Utilities', 'lenovo-legionaccessorycentral-icon', ''),
('lenovo-migrationassistant', 'Lenovo Migration Assistant', 'Seamlessly move files and settings from your old PC to your new one.', 'Utilities', 'lenovo-migrationassistant-icon', ''),
('lenovo-quickclean', 'Lenovo Quick Clean', 'Lenovo Quick Clean application allows healthcare professionals to lock keyboard and mouse input so the laptop keyboard can be wiped down to sanitize the device. The user can use the default 2 minute timer or specify an amount of time to lock out input. If the user finishes cleaning before the timer expires, pressing FN key plus Right Shift will exit the cleaning mode.', 'Utilities', 'lenovo-quickclean-icon', ''),
('lenovo-systemupdate', 'Lenovo System Update', 'Lenovo System Update downloads updates for software, drivers, and BIOS from a Lenovo server directly over the Internet without requiring specific user knowledge of where the package is located or if it is needed by the target system. System Update can determine which updates are needed and apply them. System Update can also be directed to a local repository managed by Update Retriever', 'Utilities', 'lenovo-systemupdate-icon', ''),
('lenovo-thininstaller', 'Lenovo Thin Installer', 'Lenovo Thin Installer is a smaller version of Lenovo System Update which does not require installation - it can simply be copied to the target system. Thin Installer searches for the update packages from a repository that you create. The repository can be created on your local hard drive, a network share, a web server, or external media such as a CD, DVD, or USB hard drive. When Thin Installer finishes installing applicable packages, no registry keys relating to Thin Installer exist - thus the user only needs to delete the folder containing Thin Installer to remove all files associated with Thin Installer and the associated repository', 'Development', 'lenovo-thininstaller-icon', ''),
('lenovo-updateretriever', 'Lenovo Update Retriever', 'Update Retriever is a program that enables an administrator to search for and download updates from the Lenovo Support site to a repository folder on a local drive or network share. The repository folder provides the storage for update packages. System Update or Thin Installer can be configured to search for update packages from the repository folder on a network share instead of searching the Lenovo Support site. With Update Retriever, one can manually initiate the search for update packages, or schedule an automatic search for new update packages at a specified time interval. This allows greater control of the updates that are available to managed devices.', 'Development', 'lenovo-updateretriever-icon', ''),
('leonardozide-leocad', 'LeoCAD', 'Design virtual models you can build with LEGO(R) bricks', 'Design', 'leonardozide-leocad-icon', ''),
('leonflix-leonflix', 'Leonflix', 'A multi-platform desktop app for finding media.', 'Utilities', 'leonflix-leonflix-icon', ''),
('levitsky-fontbase', 'FontBase', 'FontBase is the font manager of the new generation, built by designers, for designers.', 'Design', 'levitsky-fontbase-icon', ''),
('levminer-authme', 'Authme', 'Authme is a two-factor authentication app, you can import from QR codes or Google Authenticator QR codes.', 'Development', 'levminer-authme-icon', '');

INSERT INTO apps (id, name, description, category, icon, linux_alternative) VALUES
('lexicool-lexibar-el', 'Lexibar Greek', 'Lexibar grec permet l''accès rapide aux caractères spéciaux du grec qui ne sont peut-être pas présents sur le clavier', 'Development', 'lexicool-lexibar-el-icon', ''),
('lexicool-lexibar-es', 'Lexibar Spanish', 'Lexibar Espagnol permet l''accès rapide aux caractères spéciaux de l''espagnol qui ne sont pas présents sur le clavier', 'Development', 'lexicool-lexibar-es-icon', ''),
('lexicool-lexibar-fr', 'Lexibar French', 'Lexibar français permet l''accès rapide aux caractères spéciaux du français qui ne sont peut-être pas présent sur le clavier', 'Development', 'lexicool-lexibar-fr-icon', ''),
('lexicool-lexibar-ru', 'Lexibar Russian', 'Lexibar russe permet l''accès rapide aux caractères spéciaux du russe qui ne sont peut-être pas présents sur le clavier', 'Development', 'lexicool-lexibar-ru-icon', ''),
('lexikos-autohotkey', 'AutoHotkey', 'a free, open-source scripting language for Windows that allows users to easily create small to complex scripts for all kinds of tasks such as:form fillers, auto-clicking, macros, etc.', 'Utilities', 'lexikos-autohotkey-icon', ''),
('lierhexun-quicker', 'Quicker', 'The toolbox at your fingertips', 'Games', 'lierhexun-quicker-icon', ''),
('libgenapps-libgendesktop', 'Libgen Desktop', 'Libgen Desktop is a Windows application for browsing a local copy of LibGen catalog. The main (non-fiction), fiction and scientific articles (scimag) LibGen collections are supported.', 'Design', 'libgenapps-libgendesktop-icon', ''),
('librecad-librecad', 'LibreCAD', 'LibreCAD is a cross-platform 2D CAD program written in C++11 using the Qt framework. It can read DXF and DWG files and can write DXF, PDF and SVG files. The user interface is highly customizable, and has dozens of translations.', 'Design', 'librecad-librecad-icon', ''),
('librewolf-librewolf', 'LibreWolf', 'LibreWolf is designed to minimize data collection and telemetry as much as possible. This is achieved through hundreds of privacy/security/performance settings and patches. Intrusive integrated addons including updater, crashreporter, and pocket are removed too.', 'Design', 'librewolf-librewolf-icon', ''),
('libretro-retroarch', 'RetroArch', 'RetroArch is a frontend for emulators, game engines and media players. It enables you to run classic games on a wide range of computers and consoles through its slick graphical interface. Settings are also unified so configuration is done once and for all. In addition to this, you are able to run original game discs (CDs) from RetroArch. RetroArch has advanced features like shaders, netplay, rewinding, next-frame response times, runahead, machine translation, blind accessibility features, and more!', 'Games', 'libretro-retroarch-icon', ''),
('librevaultteam-librevault', 'Librevault', 'Librevault transfers data directly from one device to another. You can use it in your local network, and it will work even without Internet access.', 'Utilities', 'librevaultteam-librevault-icon', ''),
('lightburnsoftware-lightburn', 'LightBurn', 'LightBurn is layout, editing, and control software for your laser cutter.', 'Utilities', 'lightburnsoftware-lightburn-icon', ''),
('lightzoneproject-lightzone', 'LightZone', 'A professional-level digital darkroom and photo editor.', 'Development', 'lightzoneproject-lightzone-icon', ''),
('lightform-lightformcreator', 'Lightform Creator', 'Lightform Creator software enables you to realize your creative vision to produce eye-catching and immersive experiences using projection mapping with audio-reactive effects.​', 'Audio', 'lightform-lightformcreator-icon', ''),
('lightyearvpn-lightyearvpn', 'LightyearVPN', 'Protect your online data and hide your IP with LightyearVPN', 'Development', 'lightyearvpn-lightyearvpn-icon', ''),
('lilypond-lilypond', 'LilyPond', 'Music notation for everyone', 'Audio', 'lilypond-lilypond-icon', ''),
('lilypond-lilypond-unstable', 'LilyPond (Unstable)', 'Music notation for everyone', 'Audio', 'lilypond-lilypond-unstable-icon', ''),
('lingitas-lingdys4', 'Lingdys 4', 'LingDys 4 - Gir hjelp i lese- og skriveopplaeringen, dekker ulike behov, bidrar til oekt digital kompetanse.', 'Development', 'lingitas-lingdys4-icon', ''),
('linuxsuren-httpdownloader', 'HTTP downloader', 'A download tool that is baked for the GitHub release assets.', 'Development', 'linuxsuren-httpdownloader-icon', ''),
('linwoodcloud-butterfly', 'Butterfly', 'Butterfly is a note app where your ideas come first.', 'Development', 'linwoodcloud-butterfly-icon', ''),
('linwoodcloud-butterfly-nightly', 'Butterfly (Nightly)', 'Butterfly is a note app where your ideas come first.', 'Development', 'linwoodcloud-butterfly-nightly-icon', ''),
('lioneljouin-pip-tool', 'PiP-Tool', 'PiP tool is a software to use the Picture in Picture mode on Windows.', 'Utilities', 'lioneljouin-pip-tool-icon', ''),
('liquit-workspace-agent', 'Liquit Workspace Agent', 'Liquit Workspace offers end-users simple yet dynamic application management, ensuring a consistent, customizable user experience across any device.', 'Utilities', 'liquit-workspace-agent-icon', ''),
('liskfoundation-liskhub', 'Lisk', 'Lisk is available on desktop and mobile, focusing both on best user experience and security.', 'Utilities', 'liskfoundation-liskhub-icon', ''),
('literatureandlatte-scrivener', 'Scrivener', 'Typewriter. Ring-binder. Scrapbook. Everything you need to craft your first draft.', 'Utilities', 'literatureandlatte-scrivener-icon', ''),
('littletijn-spookyview', 'Spooky View', 'A small open-source app to make any app window transparent. Small and use minimal system resources.', 'Utilities', 'littletijn-spookyview-icon', ''),
('lizardbyte-sunshine', 'Sunshine', 'Sunshine is a self hosted, low latency, cloud gaming solution with support for AMD,
Intel, and Nvidia GPUs.
 It is an open source implementation of NVIDIA''s GameStream, as used by the NVIDIA Shield.
Connect to Sunshine from any Moonlight client, available for nearly any device imaginable.', 'Games', 'lizardbyte-sunshine-icon', ''),
('localsend-localsend', 'LocalSend', 'Share files to nearby devices. Free, open source, cross-platform. An open source cross-platform alternative to AirDrop.', 'Utilities', 'localsend-localsend-icon', ''),
