('logmein-hamachi', 'LogMeIn Hamachi', 'Easy to set up. Easy to manage. Easily create, manage and maintain virtual private networks from anywhere with LogMeIn Hamachi, a hosted VPN service, that extends secure LAN-like network connectivity to mobile users and distributed teams on-demand over the web.', 'Utilities', 'logmein-hamachi-icon', ''),
('logmein-lastpass', 'LastPass', 'LastPass is a freemium password manager that stores encrypted passwords online.', 'Office', 'logmein-lastpass-icon', ''),
