('matthijsgroen-geppetto', 'Geppetto', 'Geppetto is a free and open animation tool to embed webGL animations in a web site.', 'Utilities', 'matthijsgroen-geppetto-icon', ''),
('maxdiesel-unrealcommander', 'Unreal Commander', 'Unreal Commander - freeware unreal file manager. Characteristics: the two-panel interface; UNICODE support; search of files; synchronization of directories; support of archives, FTP client, folder tabs, support of WLX/WCX/WDX plugins and more...', 'Development', 'maxdiesel-unrealcommander-icon', ''),
('maximateam-maxima', 'Maxima computer algebra system', 'Maxima is a system for the manipulation of symbolic and numerical expressions, including differentiation, integration, Taylor series, Laplace transforms, ordinary differential equations, systems of linear equations, polynomials, sets, lists, vectors, matrices and tensors.
Maxima yields high precision numerical results by using exact fractions, arbitrary-precision integers and variable-precision floating-point numbers.
Maxima can plot functions and data in two and three dimensions.', 'Utilities', 'maximateam-maxima-icon', ''),
('maximus5-conemu', 'ConEmu', 'ConEmu aims to be handy, comprehensive, fast and reliable terminal window where you may host any console application developed either for WinAPI (cmd, powershell, far) or Unix PTY (cygwin, msys, wsl bash).', 'Development', 'maximus5-conemu-icon', ''),
('maxon-cinebenchr23', 'CinebenchR23', 'Cinebench is a tool to compare CPU and graphics performance across various systems and platforms', 'Design', 'maxon-cinebenchr23-icon', ''),
('maxthon-maxthon-5', 'MX5', 'New Maxnote, Passkeeper, and UUMail in Maxthon 5, service for you anytime and anywhere.', 'Utilities', 'maxthon-maxthon-5-icon', ''),
('maxthon-maxthon-6', 'Maxthon', 'Maxthon is a new technology browser that provides technical support for blockchain apps and makes it easier for users. Maxthon kernel is more powerful, it can be compatible with Chrome addons library and you can enjoy massive extensions.', 'Development', 'maxthon-maxthon-6-icon', ''),
('mayakron-acrylicdns', 'Acrylic DNS', 'A local DNS proxy which improves the performance of your computer', 'Utilities', 'mayakron-acrylicdns-icon', ''),
('mcserv-mcserv', 'McServ', 'CLI utility to manage MC server installations.', 'Utilities', 'mcserv-mcserv-icon', ''),
('medzed-youtubetomp3', 'Youtube-mp3', 'Electron Youtube to Mp3 Converter and downloader', 'Audio', 'medzed-youtubetomp3-icon', ''),
('medalb-v-medal', 'Medal', 'Medal.tv lets you clip your gameplay on your PC, Mac, and Mobile devices without dropping a frame. Edit your clips and share them to Medal and any other social platform with a click of a button.', 'Games', 'medalb-v-medal-icon', ''),
('mediaarea-mediainfo', 'MediaInfo-CLI', 'Convenient unified display of the most relevent technical and tag data for video and audio files from command line.', 'Development', 'mediaarea-mediainfo-icon', ''),
('mediaarea-mediainfo-gui', 'MediaInfo', 'Convenient unified display of the most relevent technical and tag data for video and audio files.', 'Development', 'mediaarea-mediainfo-gui-icon', ''),
('mediahuman-lyricsfinder', 'MediaHuman Lyrics Finder', 'MediaHuman Lyrics Finder is a free software application, which can help you find and add missing lyrics (song text) to all songs in your music library.', 'Audio', 'mediahuman-lyricsfinder-icon', ''),
('mediapress-statlookserver', 'Statlook Server', 'Statlook is a multifunctional IT Asset Management software.', 'Utilities', 'mediapress-statlookserver-icon', ''),
('mediathekviewteam-mediathekview', 'MediathekView', 'The MediathekView program searches the media libraries of various predominantly German-speaking public broadcasters, downloads articles from them or plays them back.', 'Design', 'mediathekviewteam-mediathekview-icon', ''),
('mega-megasync', 'MEGAsync', 'Easy automated synchronisation between your computer and your MEGA cloud.', 'Utilities', 'mega-megasync-icon', ''),
