('microsoft-downloadmanager', 'Download Manager', 'Learning Download Manager (LDM) is a new tool enabled on Learning Download Center to manage downloads with ease. This tool can be used to track, pause, resume downloads.', 'Utilities', 'microsoft-downloadmanager-icon', ''),
('microsoft-edge', 'Microsoft Edge', 'World-class performance with more privacy, more productivity, and more value while you browse.', 'Utilities', 'microsoft-edge-icon', ''),
('microsoft-edge-beta', 'Microsoft Edge Beta', 'World-class performance with more privacy, more productivity, and more value while you browse.', 'Utilities', 'microsoft-edge-beta-icon', ''),
('microsoft-edge-canary', 'Microsoft Edge Canary', 'World-class performance with more privacy, more productivity, and more value while you browse.', 'Utilities', 'microsoft-edge-canary-icon', ''),
('microsoft-edge-dev', 'Microsoft Edge Dev', 'Microsoft Edge is a cross-platform web browser created and developed by Microsoft. It was first released for Windows 10 and Xbox One in 2015, for Android and iOS in 2017, for macOS in 2019, and for Linux in 2020, and can replace Internet Explorer on Windows 7, Windows Server 2008 R2 and later versions but unlike IE, this browser does not support Windows Vista or earlier versions.', 'Development', 'microsoft-edge-dev-icon', ''),
('microsoft-edgewebview2runtime', 'Microsoft Edge WebView2 Runtime', 'Embed web content (HTML, CSS, and JavaScript) in your native applications with Microsoft Edge WebView2.', 'Utilities', 'microsoft-edgewebview2runtime-icon', ''),
('microsoft-git', 'Microsoft Git', 'A fork of Git containing Microsoft-specific patches.
This is microsoft/git, a special Git distribution to support monorepo scenarios. If you are not working in a monorepo, you are likely searching for Git for Windows instead of this codebase.
In addition to the Git command-line interface (CLI), microsoft/git includes the Scalar CLI to further enable working with extremely large repositories. Scalar is a tool to apply the latest recommendations and use the most advanced Git features.', 'Development', 'microsoft-git-icon', ''),
('microsoft-gitcredentialmanagercore', 'Git Credential Manager', 'Secure, cross-platform Git credential storage with authentication to GitHub, Azure Repos, and other popular Git hosting services.', 'Development', 'microsoft-gitcredentialmanagercore-icon', ''),
('microsoft-ironpython-2', 'IronPython 2', 'IronPython is an open-source implementation of the Python programming language which is tightly integrated with the .NET Framework.
IronPython can use the .NET Framework and Python libraries, and other .NET languages can use Python code just as easily.', 'Development', 'microsoft-ironpython-2-icon', ''),
('microsoft-ironpython-3', 'IronPython 3', 'An open-source implementation of the Python programming language which is tightly integrated with the .NET Framework.', 'Development', 'microsoft-ironpython-3-icon', ''),
('microsoft-laps', 'Local Administrator Password Solution', 'Provides management of local account passwords of domain joined computers. Passwords are stored in Active Directory (AD) and protected by ACL, so only eligible users can read it or request its reset.', 'Development', 'microsoft-laps-icon', 'LibreOffice Writer / ONLYOFFICE'),
('microsoft-msixcore', 'MSIX Core', 'The MSIX SDK project is an effort to enable developers on a variety of platforms to pack and unpack packages for the purposes of distribution from either the Microsoft Store, or their own content distribution networks.', 'Development', 'microsoft-msixcore-icon', ''),
('microsoft-mousewithoutborders', 'Microsoft Garage Mouse without Borders', 'Mouse without Borders (https://aka.ms/mm) is a product that makes you the captain of your computer fleet by allowing you to control up to four computers from a single mouse and keyboard. This means that with Mouse without Borders you can copy text or drag and drop files across computers.', 'Utilities', 'microsoft-mousewithoutborders-icon', ''),
('microsoft-mouseandkeyboardcenter', 'Microsoft Mouse and Keyboard Center', 'The Microsoft Mouse and Keyboard Center is an application that helps you make the most out of your Microsoft keyboard and mouse. Mouse and Keyboard Center helps you personalize and customize how you work on your PC.', 'Utilities', 'microsoft-mouseandkeyboardcenter-icon', ''),
('microsoft-multilingualapptoolkit', 'Multilingual App Toolkit', 'The Multilingual App Toolkit (MAT) 4.0 integrates with Microsoft Visual Studio 2019 to provide Windows apps with translation support, translation file management, and editor tools.', 'Development', 'microsoft-multilingualapptoolkit-icon', ''),
('microsoft-netmon', 'Microsoft Network Monitor', 'Network Monitor 3.4 is the archive versioned tool for network traffic capture and protocol analysis.', 'Utilities', 'microsoft-netmon-icon', ''),
('microsoft-nuget', 'NuGet', 'NuGet is the package manager for .NET. It enables developers to create, share, and consume useful .NET libraries. NuGet client tools provide the ability to produce and consume these libraries as "packages".', 'Development', 'microsoft-nuget-icon', ''),
('microsoft-office', 'Microsoft 365 Apps for enterprise', 'Microsoft 365 Apps for enterprise is the most productive and most secure Office experience for enterprises, allowing your teams to work together seamlessly from anywhere, anytime.', 'Office', 'microsoft-office-icon', ''),
('microsoft-officedeploymenttool', 'Office Deployment Tool', 'The Office Deployment Tool (ODT) is a command-line tool that you can use to download and deploy Click-to-Run versions of Office, such as Microsoft 365 Apps for enterprise, to your client computers.', 'Office', 'microsoft-officedeploymenttool-icon', ''),
('microsoft-onedrive', 'Microsoft OneDrive', 'Save your files and photos to OneDrive and access them from any device, anywhere.', 'Design', 'microsoft-onedrive-icon', ''),
