('microsoft-visioviewer', 'Microsoft Visio Viewer 2016', 'By using Microsoft Visio 2016 Viewer, Visio users can freely distribute Visio drawings (files with a .vsdx, .vsdm, .vsd, .vdx, .vdw, .vstx, .vstm, .vst, or .vtx extension) to team members, partners, customers, or others, even if the recipients do not have Visio installed on their computer.', 'Design', 'microsoft-visioviewer-icon', ''),
('microsoft-visualstudio-2019-buildtools', 'Visual Studio BuildTools 2019', 'An integrated, end-to-end solution for developers looking for high productivity and seamless coordination across teams of any size.', 'Development', 'microsoft-visualstudio-2019-buildtools-icon', ''),
