('microsoft-visualstudio-2022-community', 'Visual Studio Community 2022', 'The Community edition of Visual Studio, an integrated development environment (IDE) from Microsoft.  Individual developers have no restrictions on their use of the Community edition.', 'Development', 'microsoft-visualstudio-2022-community-icon', ''),
('microsoft-visualstudio-2022-community-preview', 'Visual Studio Community 2022 Preview', 'Visual Studio Community is a free, fully-featured IDE for students, open-source contributors, and individual developers.', 'Development', 'microsoft-visualstudio-2022-community-preview-icon', ''),
('microsoft-visualstudio-2022-enterprise', 'Visual Studio Enterprise 2022', 'An integrated, end-to-end solution for developers looking for high productivity and seamless coordination across teams of any size.', 'Development', 'microsoft-visualstudio-2022-enterprise-icon', ''),
('microsoft-visualstudio-2022-enterprise-preview', 'Visual Studio Enterprise 2022 Preview', 'Visual Studio Enterprise is a powerful, comprehensive IDE for developers designing, building, testing, and deploying complex applications for any platform—including the Microsoft stack.', 'Development', 'microsoft-visualstudio-2022-enterprise-preview-icon', ''),
('microsoft-visualstudio-2022-professional', 'Visual Studio Professional 2022', 'An integrated, end-to-end solution for developers looking for high productivity and seamless coordination across teams of any size.', 'Development', 'microsoft-visualstudio-2022-professional-icon', ''),
('microsoft-visualstudio-2022-professional-preview', 'Visual Studio Professional 2022 Preview', 'Visual Studio Professional is a powerful, fully-featured IDE for developers designing, building, and deploying innovative applications for any platform.', 'Development', 'microsoft-visualstudio-2022-professional-preview-icon', ''),
('microsoft-visualstudio-configfinder', 'Visual Studio Configuration Finder', 'Locate Visual Studio installation configuration files (.vsconfigs) downstream recursively and merge them all together', 'Utilities', 'microsoft-visualstudio-configfinder-icon', ''),
('microsoft-visualstudio-locator', 'Visual Studio Locator', 'Find and get information on Visual Studio versions 2017 and newer with optional additional criteria such as version, channel, or installed workloads.', 'Utilities', 'microsoft-visualstudio-locator-icon', ''),
('microsoft-visualstudiocode', 'Microsoft Visual Studio Code', 'Microsoft Visual Studio Code is a code editor redefined and optimized for building and debugging modern web and cloud applications. Microsoft Visual Studio Code is free and available on your favorite platform - Linux, macOS, and Windows.', 'Development', 'microsoft-visualstudiocode-icon', ''),
('microsoft-visualstudiocode-insiders', 'Microsoft Visual Studio Code Insiders', 'Microsoft Visual Studio Code is a code editor redefined and optimized for building and debugging modern web and cloud applications. Microsoft Visual Studio Code is free and available on your favorite platform - Linux, macOS, and Windows.', 'Development', 'microsoft-visualstudiocode-insiders-icon', ''),
('microsoft-webdeploy', 'Microsoft Web Deploy', 'Web Deploy (msdeploy) simplifies deployment of Web applications and Web sites to IIS servers. Administrators can use Web Deploy to synchronize IIS servers or to migrate to newer versions of IIS. Web Deploy Tool also enables administrators and delegated users to use IIS Manager to deploy ASP.NET and PHP applications to an IIS server.', 'Utilities', 'microsoft-webdeploy-icon', ''),
('microsoft-windowsadk', 'Windows Assessment and Deployment Kit', 'The Windows Assessment and Deployment Kit (Windows ADK) has the tools you need to customize Windows images for large-scale deployment, and to test the quality and performance of your system, its added components, and the applications running on it.', 'Design', 'microsoft-windowsadk-icon', ''),
('microsoft-windowsadmincenter', 'Windows Admin Center', 'Microsoft.WindowsAdminCenter', 'Utilities', 'microsoft-windowsadmincenter-icon', ''),
