('microsoft-windowsapplicationdriver', 'Windows Application Driver', 'Windows Application Driver (WinAppDriver) for Test Automation on Windows Applications.', 'Utilities', 'microsoft-windowsapplicationdriver-icon', ''),
('microsoft-windowsinstallationassistant', 'Windows 11 Installation Assistant', 'For installing Windows 11 on the device you’re currently using.', 'Utilities', 'microsoft-windowsinstallationassistant-icon', ''),
('microsoft-windowsjournal', 'Windows Journal', 'Create notes in your own handwriting. You can leave your notes in ink and search your handwriting or convert your notes to typed text.', 'Design', 'microsoft-windowsjournal-icon', ''),
('microsoft-windowspchealthcheck', 'Windows PC Health Check', 'Windows 11 Compatibility Checker', 'Utilities', 'microsoft-windowspchealthcheck-icon', ''),
('microsoft-windowssdk', 'Windows Software Development Kit', 'The Windows SDK (10.0.22621.1) for Windows 11 provides the latest headers, libraries, metadata, and tools for building Windows apps.', 'Development', 'microsoft-windowssdk-icon', ''),
('microsoft-windowsterminal', 'Windows Terminal', 'The new Windows Terminal, a tabbed command line experience for Windows.', 'Development', 'microsoft-windowsterminal-icon', ''),
('microsoft-windowsterminal-preview', 'Windows Terminal Preview', 'Windows Terminal is a modern terminal application for users of command line tools and shells like Command Prompt, PowerShell, and Windows Subsystem for Linux (WSL).
 Its main features include multiple tabs, panes, Unicode and UTF-8 character support, a GPU accelerated text rendering engine, and the ability to create your own themes and customize text, colors, backgrounds, and shortcut key bindings.', 'Development', 'microsoft-windowsterminal-preview-icon', ''),
('microsoft-windowsvirtualdesktopagent', 'Remote Desktop Services Infrastructure Agent', 'Install the Windows Virtual Desktop Agent
Notes
• This package always installs the latest version of the Windows Virtual Desktop Agent, regardless of the version specified in the package. 
  Microsoft do not officially offer older versions for download as the tools are self-updating.
  Because of this you may get checksum mismatch between the time Microsoft releases a new installer, and the package is automatically updated. 
• Supply the Windows Virtual Desktop Host Pool Registration Token at install time using the following command - **winget install microsoft.WindowsVirtualDesktopAgent --override ''REGISTRATIONTOKEN=\"<YOUR TOKEN>\"''
', 'Development', 'microsoft-windowsvirtualdesktopagent-icon', ''),
('microsoft-windowsvirtualdesktopbootloader', 'Remote Desktop Agent Boot Loader', 'Install the Windows Virtual Desktop Boot Loader
### Notes
* This package always installs the latest version of the Windows Virtual Desktop Bootloader, regardless of the version specified in the package. Microsoft do not officially offer older versions for download as the tools are self-updating. Because of this you may get checksum mismatch between the time Microsoft releases a new installer, and the package is automatically updated.', 'Utilities', 'microsoft-windowsvirtualdesktopbootloader-icon', ''),
('microsoft-windowswdk', 'Windows Driver Kit', 'The WDK is used to develop, test, and deploy Windows drivers.', 'Development', 'microsoft-windowswdk-icon', ''),
('microsoft-wingetcreate', 'Windows Package Manager Manifest Creator', 'Windows Package Manager Manifest Creator is an Open Source tool designed to help developers create, update, and submit manifest files to the Windows Package Manager repository.', 'Development', 'microsoft-wingetcreate-icon', ''),
('microsoft-xmlnotepad', 'XML Notepad', 'XML Notepad is the result of a promise Chris Lovett made to a friend at Microsoft. The original XML Notepad shipped in back in 1998, written by Murray Low in C++. Later on it fell behind in support for XML standards and, because we didn''t have time to fix it, we pulled the downloader. But Murray apparently did such a nice job that MSDN was inundated with requests to put the notepad back up, so they asked for a replacement.', 'Design', 'microsoft-xmlnotepad-icon', ''),
('microsoft-xnaredist', 'Microsoft XNA Framework Redistributable Refresh', 'XNA Framework Redistributable download provides game developers with the XNA Framework run-time libraries they can include with their product for redistribution on the Windows platform.', 'Games', 'microsoft-xnaredist-icon', ''),
('microsoft-bitsmanager', 'BITS Manager', 'BITS Manager is a sample GUI tool for examining and creating BITS (Background Intelligent Transfer Service) uploads and downloads.', 'Utilities', 'microsoft-bitsmanager-icon', ''),
('microsoft-dotnetuninstalltool', 'Microsoft .NET Core SDK Uninstall Tool', 'Tool to uninstall versions of the .Net Core SDK, Runtime, ASP.Net Core Runtime, and Hosting Bundles.', 'Utilities', 'microsoft-dotnetuninstalltool-icon', ''),
('microsoft-msmpi', 'Microsoft MPI', 'Microsoft MPI (MS-MPI) is a Microsoft implementation of the Message Passing Interface standard for developing and running parallel applications on the Windows platform.', 'Development', 'microsoft-msmpi-icon', ''),
('microsoft-msmpisdk', 'Microsoft MPI SDK', 'Microsoft MPI (MS-MPI) is a Microsoft implementation of the Message Passing Interface standard for developing and running parallel applications on the Windows platform.', 'Development', 'microsoft-msmpisdk-icon', ''),
('microsoft-quicreach', 'quicreach', 'A tool for determining QUIC reachability', 'Utilities', 'microsoft-quicreach-icon', ''),
('microsoft-vott', 'vott', 'Visual Object Tagging Tool (VoTT) - an annotation and labeling tool for images and video.', 'Development', 'microsoft-vott-icon', ''),
