('microstockr-desktopapp', 'Microstockr', 'Microstock photography made easy', 'Design', 'microstockr-desktopapp-icon', ''),
('mikefarah-yq', 'yq', 'yq is a lightweight and portable command-line YAML, JSON and XML processor.
yq uses jq like syntax but works with yaml files as well as json, xml, properties, csv and tsv.', 'Utilities', 'mikefarah-yq-icon', ''),
('mikrotik-thedude', 'The Dude', 'The Dude network monitor is a new application by MikroTik which can dramatically improve the way you manage your network environment.', 'Utilities', 'mikrotik-thedude-icon', ''),
('millerpuckette-puredata', 'Pure Data', 'Pure Data (or just Pd) is an open source visual programming language for multimedia', 'Development', 'millerpuckette-puredata-icon', ''),
('min-min', 'Min', 'A fast, minimal browser that protects your privacy.', 'Utilities', 'min-min-icon', ''),
('mindsetinnovationinc-enowork', 'Eno 1.0.9', 'Track your focus to build more productive habits.', 'Utilities', 'mindsetinnovationinc-enowork-icon', ''),
('minecodes-4zur3', '4zur3', 'A small payload generator for pentesting.', 'Utilities', 'minecodes-4zur3-icon', ''),
('mingo-mingo', 'Mingo', 'Manage your MongoDB databases with Mingo - a fast, reliable, safe and intuitive MongoDB admin', 'Development', 'mingo-mingo-icon', ''),
('minhloi-midterm', 'Midterm', 'Midterm is a note-taking app for you to write notes and study in one place.', 'Utilities', 'minhloi-midterm-icon', ''),
('minitool-partitionwizard-free', 'MiniTool Partition Wizard Free', 'MiniTool Partition Wizard Free helps users to repartition hard drive, format partition, check file system, align SSD partition, measure SSD performance, convert FAT to NTFS, and more on Windows 11/10/8/7', 'Design', 'minitool-partitionwizard-free-icon', ''),
('mintty-wsltty', 'WSLtty', 'Terminal for Windows Subsystem for Linux', 'Utilities', 'mintty-wsltty-icon', ''),
('mirandaim-mirandaim', 'Miranda IM', 'Miranda IM is an open source, multi-protocol instant messaging client designed to be very light on system resources, extremely fast and customizable.', 'Design', 'mirandaim-mirandaim-icon', ''),
('mirandang-mirandang', 'Miranda NG', 'Miranda NG (Next Generation) is a successor of a popular multi-protocol instant messaging client for Windows – Miranda IM.', 'Utilities', 'mirandang-mirandang-icon', ''),
('mirantis-lens', 'Lens', 'Lens is the most powerful Kubernetes IDE on the market. It is a standalone application, and it is available on macOS, Windows, and Linux.', 'Development', 'mirantis-lens-icon', ''),
('mirasoft-anyvizcloudadapter', 'AnyViz Universal Cloud Adapter', 'With the AnyViz Cloud Adapter, you can turn any IoT device into a data collector for the cloud. The connection to the industrial systems is configured via the easy-to-use web interface. The data is then bundled and transferred to your AnyViz project via an encrypted connection. If the connection fails, the data is buffered locally. The AnyViz Cloud Adapter also enables the routing of local visualizations via HTTP or VNC.', 'Design', 'mirasoft-anyvizcloudadapter-icon', ''),
('mirillis-action', 'Action!', 'Mirillis Action! screen recorder allows streaming and real-time recording of Windows desktop in a superb HD video quality.', 'Development', 'mirillis-action-icon', ''),
('mirillis-splashultimate', 'Splash', 'The only player you will ever need. Stunning video quality thanks to advanced engine. Video conversion optimized for social media. Innovative and fully customizable user interface.', 'Development', 'mirillis-splashultimate-icon', ''),
('miro-miro', 'Miro', 'The online collaborative platform to bring teams together, anytime, anywhere.', 'Utilities', 'miro-miro-icon', ''),
('misfitcode-misfitmodel3d', 'Misfit Model 3D', 'An OpenGL-based 3D model editor that works with triangle-based models.', 'Design', 'misfitcode-misfitmodel3d-icon', ''),
('misfitcode-misfitmodel3d-dev', 'Misfit Model 3D (Dev)', 'An OpenGL-based 3D model editor that works with triangle-based models.', 'Design', 'misfitcode-misfitmodel3d-dev-icon', ''),
('misitebao-yakia', 'Yakia', 'Tools for developers to manage projects.', 'Development', 'misitebao-yakia-icon', ''),
('mobatek-mobaxterm', 'MobaXterm', 'MobaXterm is your ultimate toolbox for remote computing. In a single Windows application, it provides loads of functions that are tailored for programmers, webmasters, IT administrators and pretty much all users who need to handle their remote jobs in a more simple fashion.
MobaXterm provides all the important remote network tools (SSH, RDP, X11, SFTP, FTP, Telnet, Rlogin, ...) to Windows desktop, in a single portable exe file which works out of the box. Some plugins can be used to add functions to MobaXterm such as Unix commands (bash, ls, cat, sed, grep, awk, rsync, ...).', 'Development', 'mobatek-mobaxterm-icon', ''),
('mobirise-mobirise', 'Mobirise', 'Mobirise is a free offline app for Windows and Mac to easily create small/medium websites, landing pages, online resumes and portfolios.', 'Utilities', 'mobirise-mobirise-icon', ''),
