('momento-cli', 'Momento CLI', 'Momento CLI is Momento Serverless Cache on the command line. It brings account creation, maintenance, cache control and data commands to the terminal.', 'Utilities', 'momento-cli-icon', ''),
('mongodb-compass-community', 'MongoDB Compass Community', 'The GUI for MongoDB. Visually explore your data. Run ad hoc queries in seconds. Interact with your data with full CRUD functionality. View and optimize your query performance. Available on Linux, Mac, or Windows. Compass empowers you to make smarter decisions about indexing, document validation, and more.', 'Design', 'mongodb-compass-community-icon', ''),
('mongodb-compass-full', 'MongoDB Compass', 'The GUI for MongoDB. Visually explore your data. Run ad hoc queries in seconds. Interact with your data with full CRUD functionality. View and optimize your query performance. Available on Linux, Mac, or Windows. Compass empowers you to make smarter decisions about indexing, document validation, and more.', 'Design', 'mongodb-compass-full-icon', ''),
