('mongodb-compass-readonly', 'MongoDB Compass Readonly', 'The GUI for MongoDB. Visually explore your data. Run ad hoc queries in seconds. Interact with your data with full CRUD functionality. View and optimize your query performance. Available on Linux, Mac, or Windows. Compass empowers you to make smarter decisions about indexing, document validation, and more.', 'Design', 'mongodb-compass-readonly-icon', ''),
('mongodb-databasetools', 'MongoDB Tools', 'The MongoDB Database Tools are a collection of command-line utilities for working with a MongoDB deployment.', 'Development', 'mongodb-databasetools-icon', ''),
('mongodb-mongodbatlascli', 'MongoDB Atlas CLI', 'The Atlas CLI (mongodb-atlas-cli) lets you manage your MongoDB Atlas deployments from the command line.', 'Development', 'mongodb-mongodbatlascli-icon', ''),
('mongodb-mongodbcli', 'MongoDB CLI', 'The MongoDB CLI is a modern command line interface that enables you to manage your MongoDB services from the terminal.', 'Utilities', 'mongodb-mongodbcli-icon', ''),
('mongodb-server', 'MongoDB', 'MongoDB is a general purpose, document-based, distributed database built for modern application developers and for the cloud era.', 'Development', 'mongodb-server-icon', ''),
('mongodb-shell', 'MongoDB Shell', 'The mongo shell is an interactive JavaScript interface to MongoDB. You can use the mongo shell to query and update data as well as perform administrative operations.', 'Utilities', 'mongodb-shell-icon', ''),
('monkeysaudio-monkeysaudio', 'Monkey''s Audio', 'Monkey’s Audio is a fast and easy way to compress digital music.  Unlike traditional methods such as mp3, ogg, or wma that permanently discard quality to save space, Monkey’s Audio only makes perfect, bit-for-bit copies of your music.', 'Development', 'monkeysaudio-monkeysaudio-icon', ''),
('monkilabs-notejoy', 'Notejoy', 'Powerful notes app for individuals and teams. Fast, focused, always in sync. Notejoy is available on Mac, PC, iOS, Android, and the web. Sign up free.', 'Utilities', 'monkilabs-notejoy-icon', ''),
('mono-mono', 'Mono for Windows', 'Sponsored by Microsoft, Mono is an open source implementation of Microsoft"s .NET Framework based on the ECMA standards for C# and the Common Language Runtime. A growing family of solutions and an active and enthusiastic contributing community is helping position Mono to become the leading choice for development of cross platform applications.', 'Development', 'mono-mono-icon', ''),
('mono-gtksharp', 'Gtk# for .Net', 'Gtk# is a Graphical User Interface Toolkit for mono and .Net. The project binds the gtk+ toolkit and assorted GNOME libraries, enabling fully native graphical Gnome application development using the Mono and .Net development frameworks.', 'Development', 'mono-gtksharp-icon', ''),
