('novationdms-usbmididriver', 'Novation USB Midi Driver', 'Novation USB Midi Driver Setup', 'Utilities', 'novationdms-usbmididriver-icon', ''),
('novicon-munixo-client', 'munixo Client', 'Munixo is the lean and intuitive ERP software especially for medium-sized companies in the retail, service, food and pharmaceutical industries.', 'Utilities', 'novicon-munixo-client-icon', ''),
('nozbe-nozbepersonal', 'Nozbe Personal', 'To-do, task, project and time management application', 'Utilities', 'nozbe-nozbepersonal-icon', ''),
('nulana-remotix', 'Remotix', 'Connect to all your computers from anywhere.', 'Utilities', 'nulana-remotix-icon', ''),
('nullpomino-nullpomino', 'NullpoMino', 'NullpoMino is an open-source action puzzle game that works on the Java platform. It has a wide variety of single-player modes and netplay to allow players to compete over the Internet or LAN.', 'Games', 'nullpomino-nullpomino-icon', ''),
('numere-numere', 'NumeRe - Framework für Numerische Rechnungen', 'NumeRe: Framework für Numerische Rechnungen is an application for Microsoft Windows® that can do more than the usual spreadsheets. It provides you with nonlinear fits of arbitrary functions as well as a ODE solver. It can display 1D and 2D data easily and publication-ready with a simple command. Fourier transforms are included as well as wavelet transforms. Data is managed in a table-based manner and automatically saved, so you can quickly resume after a restart. SIMPLE TASKS ARE SIMPLE - We never understood why you have to write as much code for simple things as for more complex tasks. Our mantra is therefore Keep simple things simple. SYNTAX AS INTUITIVE AS A LANGUAGE - The main goal is to be as intuitive as possible, which implies a syntax that is as simple and clear as possible. NumeRe does not try to be dynamically typed, but deliberately emphasizes that you understand what is happening as soon as you read the code. In addition, the advanced editor highlights different data structures in different colors, so the syntax may seem a bit "colorful and choppy" at first. But we can guarantee that you will appreciate it very soon. STRUCTURE BUILT IN - When writing procedures, the deeply-integrated namespaces help you to keep order right away, because each folder automatically corresponds to a namespace. This makes it possible to have several procedures with the same name that are still unique. The editor supports you by auto-completion, as well as by displaying tooltips that show documentation and signatures of functions, commands and procedures.', 'Development', 'numere-numere-icon', ''),
('nurgosoftware-aquasnap', 'AquaSnap', 'AquaSnap is a tiling window manager for Windows', 'Utilities', 'nurgosoftware-aquasnap-icon', ''),
('nushell-nushell', 'nu', 'Hello, and welcome to the Nushell project.
The goal of this project is to take the Unix philosophy of shells, where pipes connect simple commands together, and bring it to the modern style of development.
Nu takes cues from a lot of familiar territory, traditional shells like bash, object based shells like PowerShell, functional programming, systems programming, and more.', 'Development', 'nushell-nushell-icon', ''),
('nutstore-nutstore', 'Nutstore', 'Nutstore is a free cloud storage service that helps you access your files anywhere at any time and share them with friends easily.', 'Utilities', 'nutstore-nutstore-icon', ''),
('nutstore-nutstorelightapp', 'Nutstore LightApp', 'Nutstore Lightapp', 'Design', 'nutstore-nutstorelightapp-icon', ''),
('nvidia-broadcast', 'NVIDIA Broadcast', 'The NVIDIA Broadcast app transforms any room into a home studio. Take your livestreams, voice chats, and video conference calls to the next level with AI-enhanced voice and video.', 'Development', 'nvidia-broadcast-icon', ''),
('nvidia-cuda', 'NVIDIA CUDA Toolkit', 'CUDA is a parallel computing platform and programming model developed by NVIDIA for general computing on graphical processing units (GPUs).', 'Development', 'nvidia-cuda-icon', ''),
('nvidia-geforceexperience', 'NVIDIA GeForce Experience', 'GeForce Experience takes the hassle out of PC gaming by configuring your game’s graphics settings for you.', 'Games', 'nvidia-geforceexperience-icon', '');

INSERT INTO apps (id, name, description, category, icon, linux_alternative) VALUES
('nvidia-geforcenow', 'NVIDIA GeForce NOW', 'GeForce NOW instantly transforms nearly any laptop, desktop, Mac, SHIELD TV, Android device, iPhone, or iPad into the PC gaming rig you’ve always dreamed of. Play the most demanding PC games and seamlessly play across your devices.', 'Games', 'nvidia-geforcenow-icon', ''),
('nvidia-physx', 'NVIDIA PhysX System Software', 'PhysX System software provides updates necessary for some games to run PhysX content properly', 'Games', 'nvidia-physx-icon', ''),
('nvidia-physxlegacy', 'NVIDIA PhysX (Legacy)', 'NVIDIA PhysX (Legacy) is for games released around the end of 2007 and earlier.', 'Games', 'nvidia-physxlegacy-icon', ''),
('nvidia-rtxvoice', 'RTX Voice', 'NVIDIA RTX Voice is a new plugin that leverages NVIDIA RTX GPUs and their AI capabilities to remove distracting background noise from your broadcasts, voice chats, and remote video conferencing meetings. This allows users to "go live" or join a meeting without having to worry about unwanted sounds like loud keyboard typing or other ambient noise in noisy environments. RTX Voice also suppresses background noise from players in loud environments, making incoming audio easier to understand.', 'Development', 'nvidia-rtxvoice-icon', ''),
('nvidia-videoeffectssdk-20xx-turing', 'NVIDIA Video Effects', 'Video Effects SDK for NVIDIA GeForce RTX 20 Series or NVIDIA Quadro RTX', 'Development', 'nvidia-videoeffectssdk-20xx-turing-icon', ''),
('nxshellteam-nxshell', 'NxShell', 'An easy to use new terminal for Windows/Linux/MacOS platform. It like Xshell or SecureCRT or PuTTY shell client.', 'Utilities', 'nxshellteam-nxshell-icon', ''),
('n457-uncolored', 'Uncolored', 'Next generation desktop rich content editor that saves documents with themes. HTML & Markdown compatible.', 'Design', 'n457-uncolored-icon', ''),
