('nektos-act', 'act', 'Run your GitHub Actions locally!', 'Development', 'nektos-act-icon', ''),
('nepnep-neofetch-win', 'neofetch-win', 'Simple, ultra-lightweight neofetch clone for Windows 10+ written in C++ and installable through winget(?). The executable is just under 70KB and requires no dependencies other than the MS Visual C++ redists (which should be installed already, and if they''re not my installer will take care of that for you :)', 'Utilities', 'nepnep-neofetch-win-icon', ''),
('netbsd-rawrite32', 'Rawrite32', 'Rawrite32 is a tool to prepare disks or other removeable media, especially USB memory sticks, from files called file system images.', 'Design', 'netbsd-rawrite32-icon', ''),
('netless-io-flat', 'Flat', 'Project flat is the Web, Windows and macOS client of Agora Flat open source classroom.', 'Utilities', 'netless-io-flat-icon', ''),
('ngudbhav-trico', 'TriCo', 'This App Converts your correctly formatted Excel Spreadsheet to a specified table/collection in specified Database in MYSQL/MongoDB.', 'Development', 'ngudbhav-trico-icon', ''),
('ngudbhav-webkiosk-wrapper', 'Webkiosk-Wrapper', 'Wrapper for Webkiosk portal of Jaypee college, Noida.', 'Utilities', 'ngudbhav-webkiosk-wrapper-icon', ''),
('ngudbhav-lazytype', 'LazyType', 'A Software to create aliases for commands, applications to type in cmd, terminal. Just type the original command and type an alias for it', 'Utilities', 'ngudbhav-lazytype-icon', ''),
('nikolahristov-roundedcorners', 'Rounded Corners', 'This app rounds the corners of your Windows screen.', 'Utilities', 'nikolahristov-roundedcorners-icon', ''),
('nikpapa-palamedes', 'Palamedes', 'Palamedes is a project dedicated to offering expert playing computer opponents at backgammon and several other variants. Currently users of Palamedes can play the variants Portes, Plakoto, Fevga collectively called Tavli (Greek backgammon) and Narde. For position evaluation, Palamedes uses neural networks trained by a form of temporal difference learning and millions of self-play games. Palamedes also offers simple ways of storing and loading games, as well as simple analyzing tools.', 'Games', 'nikpapa-palamedes-icon', ''),
('nimblenote-nimblenote', 'nimblenote', 'nimblenote is a simple keyboard-driven note taking application. Search, create, edit and delete notes all without the mouse.', 'Utilities', 'nimblenote-nimblenote-icon', ''),
