('openjs-nodejs', 'Node.js', 'Node.js® is an open-source, cross-platform JavaScript runtime environment.', 'Development', 'openjs-nodejs-icon', ''),
('openjs-nodejs-lts', 'Node.js LTS', 'Node.js is a JavaScript runtime built on Chrome"s V8 JavaScript engine. Node.js uses an event-driven, non-blocking I/O model that makes it lightweight and efficient. Node.js" package ecosystem, npm, is the largest ecosystem of open source libraries in the world.', 'Utilities', 'openjs-nodejs-lts-icon', ''),
('openjs-nodejs-nightly', 'Node.js Nightly', 'As an asynchronous event-driven JavaScript runtime, Node.js is designed to build scalable network applications.', 'Design', 'openjs-nodejs-nightly-icon', ''),
