('ql-win-quicklook', 'QuickLook', 'Bring macOS “Quick Look” feature to Windows', 'Utilities', 'ql-win-quicklook-icon', ''),
('qmk-qmktoolbox', 'QMK Toolbox', 'A collection of keyboard flashing tools', 'Utilities', 'qmk-qmktoolbox-icon', ''),
('qmplay2-qmplay2', 'QMPlay2', 'QMPlay2 is a video and audio player. It can play all formats supported by FFmpeg, libmodplug (including J2B and SFX). It also supports Audio CD, raw files, Rayman 2 music and chiptunes. It contains YouTube and MyFreeMP3 browser.', 'Development', 'qmplay2-qmplay2-icon', ''),
('qnap-externalraidmanager', 'QNAP External RAID Manager', 'With the QNAP External RAID Manager you can set up, monitor, and view the status of your QNAP external RAID devices (such as the TR-004). All device events are recorded and desktop notifications will be sent if a system alert occurs.', 'Utilities', 'qnap-externalraidmanager-icon', ''),
('qnap-netbakreplicator', 'QNAP NetBak Replicator', 'QNAP NetBak Replicator provides several options for copying files from your Windows computer to your NAS. By simplifying the backup process, NetBak Replicator helps ensure that your files are safe even when your computer becomes unavailable.', 'Development', 'qnap-netbakreplicator-icon', ''),
('qnap-qencdecrypter', 'QENC Decrypter', 'Before sharing sensitive and/or confidential files from your NAS, use File Station to encrypt them into .qenc files.', 'Development', 'qnap-qencdecrypter-icon', ''),
('qnap-qvrproclient', 'QNAP QVR Pro Client', 'rovides 8 embedded monitoring channels, allowing you to quickly build a home surveillance environment hosted on your QNAP NAS', 'Development', 'qnap-qvrproclient-icon', ''),
('qnap-qfinderpro', 'QNAP Qfinder Pro', 'allows you to quickly find and easily access all of the QNAP NAS on the same LAN.', 'Utilities', 'qnap-qfinderpro-icon', ''),
('qnap-qsirch', 'Qsirch PC Edition', 'Qsirch is a fast, full-text search engine that enables you to find files based on filename, content, and metadata.', 'Utilities', 'qnap-qsirch-icon', ''),
('qnap-qsync', 'QNAP Qsync Client', 'Qsync enables automatic file synchronization across different devices. Simply drag and drop files in the “Qsync folder,” data on devices linked with the NAS is updated simultaneously when changes are made. Additional sync modes.', 'Utilities', 'qnap-qsync-icon', ''),
('qnap-qudedupextracttool', 'QuDedup Extract Tool', 'QNAP QuDedup Extract Tool helps restore deduplicated .qdff', 'Utilities', 'qnap-qudedupextracttool-icon', ''),
('qttabbar-qttabbar', 'QTTabBar', 'QTTabBar is extension for Windows Explorer that brings tabbed browsing to Microsoft''s file browser, along with a host of other great features.', 'Utilities', 'qttabbar-qttabbar-icon', ''),
('qtextpad-qtextpad', 'QTextPad', 'Lightweight text and code editor using KF5''s syntax highlighting repository', 'Development', 'qtextpad-qtextpad-icon', ''),
('qtodotxt-qtodotxt', 'QTodoTxt', 'a cross-platform UI client for todo.txt files', 'Utilities', 'qtodotxt-qtodotxt-icon', ''),
('qalculate-qalculate', 'Qalculate!', 'A highly versatile desktop calculator, with support for units, physical constants, uncertainty propagation, symbolic calculations, etc.', 'Utilities', 'qalculate-qalculate-icon', ''),
('qmmpdevelopmentteam-qmmp', 'Qt-based Multimedia Player', 'This program is an audio-player, written with the help of the Qt library. The user interface is similar to winamp or xmms.', 'Audio', 'qmmpdevelopmentteam-qmmp-icon', ''),
('qoppa-pdfstudio', 'PDF Studio', 'An easy to use, full-featured PDF editing software that is a reliable alternative to AdobeÂ® AcrobatÂ® and provides all PDF functions needed at a fraction of the cost. PDF Studio maintains full compatibility with the PDF Standard.', 'Development', 'qoppa-pdfstudio-icon', ''),
('qt-qtdesigner', 'Qt Designer', 'Qt Designer is a tool for quickly building graphical user interfaces with widgets from the Qt GUI framework.', 'Design', 'qt-qtdesigner-icon', ''),
('quadren-arc-prerelease', 'Arc', 'Arc is a seamless cross-platform file transfer tool by Quadren. Fast, secure and completely free, supports Windows, MacOS, Android and iOS.', 'Utilities', 'quadren-arc-prerelease-icon', ''),
('quassel-quasselirc', 'QuasselIRC', 'Quassel IRC installer containing core, client, and standalone client.', 'Utilities', 'quassel-quasselirc-icon', ''),
('questsoft-qtranslate', 'QTranslate', 'QTranslate is a free translator for Windows. With this small utility, you simply select the text you want to translate and then press the hot key (Ctrl+Q) to show translation in the popup window or Double Ctrl click to show the translation in the main window. QTranslate also has the ability to speak text (Ctrl+E) and perform a dictionary search (Ctrl+Shift+Q). Also, you can open the main window and type text manually.', 'Utilities', 'questsoft-qtranslate-icon', ''),
('questrade-iqedge', 'Questrade Edge', 'Desktop platform for stock analysis and trading with the Questrade brokerage', 'Utilities', 'questrade-iqedge-icon', ''),
('quicken-quicken', 'Quicken', 'Quicken is a personal finance management tool that can be used to record banking transactions, planning a budget and tracking investments.', 'Utilities', 'quicken-quicken-icon', ''),
('quintonreeves-redeclipse', 'Red Eclipse', 'Red Eclipse is a fun-filled new take on the first person arena shooter, featuring parkour, impulse boosts, and more.', 'Games', 'quintonreeves-redeclipse-icon', ''),
('quiterss-quiterss', 'QuiteRSS', 'QuiteRSS is a open-source cross-platform RSS/Atom news feeds reader.', 'Office', 'quiterss-quiterss-icon', ''),
('quodlibet-quodlibet', 'Quod Libet - Music Library / Editor / Player', 'Quod Libet is a cross-platform audio / music management program. It provides many ways to view your local library, and supports streaming audio and feeds (podcasts, etc.). It has extremely flexible metadata editing and searching capabilities.', 'Development', 'quodlibet-quodlibet-icon', ''),
('qv2ray-qv2ray', 'Qv2ray', 'A full-featured cross-platform GUI for V2ray', 'Utilities', 'qv2ray-qv2ray-icon', ''),
('qbittorrent-qbittorrent', 'qBittorrent', 'qBittorrent is a bittorrent client programmed in C++ / Qt that uses libtorrent (sometimes called libtorrent-rasterbar) by Arvid Norberg.
It aims to be a good alternative to all other bittorrent clients out there. qBittorrent is fast, stable and provides unicode support as well as many features.', 'Development', 'qbittorrent-qbittorrent-icon', 'qBittorrent'),
('qier222-yesplaymusic', 'YesPlayMusic', 'A third party music player for Netease Music', 'Audio', 'qier222-yesplaymusic-icon', ''),
('qishibo-anotherredisdesktopmanager', 'Another Redis Desktop Manager', 'A faster, better and more stable redis desktop manager [GUI client], compatible with Linux, Windows, Mac. What''s more, it won''t crash when loading a large number of keys.', 'Utilities', 'qishibo-anotherredisdesktopmanager-icon', ''),
('qjfoidnh-baidupcs-go', 'BaiduPCS-Go', 'A command-line Baidu Netdisk client written in Go, providing useful functionalities for operating Baidu Netdisk.
This version is based on iikira''s original BaiduPCS-Go v3.6.2, with additional ability of saving shared files.', 'Utilities', 'qjfoidnh-baidupcs-go-icon', ''),
('qotop-spaceengine', 'SpaceEngine', 'SpaceEngine is a realistic virtual Universe you can explore on your computer.', 'Utilities', 'qotop-spaceengine-icon', ''),
('quick-lint-quick-lint-js', 'quick-lint-js', 'Find bugs in JavaScript programs.', 'Development', 'quick-lint-quick-lint-js-icon', ''),
('quick123-quickredis', 'QuickRedis', 'QuickRedis is a free forever Redis Desktop manager. It supports direct connection, sentinel, and cluster mode, supports multiple languages, supports hundreds of millions of keys, and has an amazing UI.', 'Utilities', 'quick123-quickredis-icon', ''),
('qutebrowser-qutebrowser', 'qutebrowser', 'A keyboard-driven, vim-like browser based on PyQt5.', 'Utilities', 'qutebrowser-qutebrowser-icon', ''),
('rarlab-winrar', 'WinRAR', 'WinRAR is a powerful archiver (RAR and ZIP) and extractor tool that can open all popular file formats.', 'Utilities', 'rarlab-winrar-icon', 'PeaZip / Ark'),
('realix-hwinfo', 'HWiNFO', 'Comprehensive Hardware Analysis, Monitoring and Reporting for Windows and DOS.', 'Utilities', 'realix-hwinfo-icon', ''),
('redabierta-uranossoftphone', 'URANOS Softphone', 'URANOS Softphone is a complete state-of-the-art business telephone system.', 'Design', 'redabierta-uranossoftphone-icon', ''),
('redmodding-wolvenkit-nightly', 'WolvenKit Nightly', 'WolvenKit is an open-source modding tool for Cyberpunk 2077. Our vision is to develop a standalone software which is capable of reading and writing all REDengine file formats. Additionally the WolvenKit application is designed to simplify and accelerate modding workflows. This repository was created to demonstrate how CDPR''s proprietary REDengine reads and writes file formats.', 'Development', 'redmodding-wolvenkit-nightly-icon', ''),
('rhash-rhash', 'RHash', 'RHash (Recursive Hasher) is a console utility for computing and verifying hash sums of files. It supports CRC32, MD4, MD5, SHA1, SHA256, SHA512, Tiger, DC++ TTH, BitTorrent BTIH, ED2K, AICH, GOST R 34.11-94, RIPEMD-160, HAS-160, EDON-R 256/512, Whirlpool and Snefru-128/256 algorithms. Hash sums are used to ensure and verify integrity of large volumes of data for a long-term storing or transferring.', 'Utilities', 'rhash-rhash-icon', ''),
('ria-digidoc4', 'DigiDoc4 Client', 'Estonian e-ID middleware', 'Utilities', 'ria-digidoc4-icon', ''),
('ridi-ridibooks', 'Ridibooks', 'Ridibooks는 RIDI eBook의 PC 뷰어입니다.', 'Utilities', 'ridi-ridibooks-icon', ''),
('rkibria-frhed', 'Frhed', 'The Frhed Hexadecimal Editor', 'Design', 'rkibria-frhed-icon', ''),
('rproject-r', 'R for Windows', 'The base binary distribution of R statistics language.', 'Design', 'rproject-r-icon', ''),
('rproject-rtools', 'Rtools', 'Rtools is a toolchain bundle used for building R packages from source (those that need compilation of C/C++ or Fortran code) and for building R itself.  Rtools42 is used for R 4.2.x and currently for R-devel, the development version of R since revision 81360.  Rtools42 consists of Msys2 build tools, GCC 10/MinGW-w64 compiler toolchain and libraries and QPDF.  Rtools42 supports 64-bit Windows and UCRT as the C runtime.  The code compiled by earlier versions of Rtools is incompatible and has to be recompiled with Rtools42 for use in R packages.  Switching to UCRT allows to use UTF-8 as the native encoding on Windows.
', 'Development', 'rproject-rtools-icon', ''),
('rstudio-rstudio-opensource', 'RStudio Desktop Open Source Edition', 'RStudio is an integrated development environment (IDE) for R. It includes a console, syntax-highlighting editor that supports direct code execution, as well as tools for plotting, history, debugging and workspace management.', 'Development', 'rstudio-rstudio-opensource-icon', ''),
('rstudio-rstudio-professional', 'RStudio Desktop Professional Edition', 'RStudio is an integrated development environment (IDE) for R. It includes a console, syntax-highlighting editor that supports direct code execution, as well as tools for plotting, history, debugging and workspace management.', 'Development', 'rstudio-rstudio-professional-icon', ''),
('rstudio-quarto', 'Quarto', 'Main features of Quarto:
   Create dynamic content with Python, R, Julia, and Observable.
   Author documents as plain text markdown or Jupyter notebooks.
   Publish high-quality articles, reports, presentations, websites, blogs, and books in HTML, PDF, MS Word, ePub, and more.
   Author with scientific markdown, including equations, citations, crossrefs, figure panels, callouts, advanced layout, and more.', 'Design', 'rstudio-quarto-icon', ''),
('rabbit-company-passky', 'Passky', 'Passky is simple, modern, lightweight, open source and secure password manager.', 'Office', 'rabbit-company-passky-icon', ''),
('rabidviperproductions-assaultcube', 'AssaultCube', 'Semi-realistic first-person shooter based on the Cube engine', 'Games', 'rabidviperproductions-assaultcube-icon', ''),
('racecore24-ignition', 'RaceCore24 Ignition', 'RaceCore24 USB electronics calibration software.', 'Games', 'racecore24-ignition-icon', ''),
('racket-racket', 'Racket', 'Racket is a general-purpose, multi-paradigm programming language.', 'Development', 'racket-racket-icon', ''),
('radiantly-invisiwind', 'Invisiwind', 'Invisiwind is a free, open-source application that allows you to hide windows from being seen when sharing your screen.', 'Development', 'radiantly-invisiwind-icon', ''),
('radmin-vpn', 'Radmin VPN', 'Radmin VPN allows you to create virtual private networks that acts like a LAN.', 'Utilities', 'radmin-vpn-icon', ''),
('rainmeter-rainmeter', 'Rainmeter', 'Rainmeter allows you to display customizable skins on your desktop, from hardware usage meters to fully functional audio visualizers. You are only limited by your imagination and creativity.', 'Audio', 'rainmeter-rainmeter-icon', ''),
('ramsoft-dicomproxy', 'RamSoft DicomProxy', 'DicomProxy is a windows appplication running as a windows service to assists local modalities to transfer dicom studies to a remote PACS server.', 'Utilities', 'ramsoft-dicomproxy-icon', ''),
('ramsoft-omegaailink', 'RamSoft Omega AI Link', 'Omega AI Link is a windows appplication running as a windows service to assists local modalities to transfer dicom studies to a remote PACS server.', 'Utilities', 'ramsoft-omegaailink-icon', ''),
('rambax-simpletransfer', 'SimpleTransfer Desktop', 'Simple Transfer is the easiest way of transferring your Photos and Videos to computer and other iOS devices wirelessly or USB. No need for cable, iTunes or extra softwares on your computer!', 'Development', 'rambax-simpletransfer-icon', ''),
('rambox-rambox', 'Rambox', 'Rambox is a workspace organizer that allows you to unify as many applications as you want, all in one place. 
It is perfect for those who care about productivity while working with many business and personal apps. ', 'Utilities', 'rambox-rambox-icon', ''),
('rambox-rambox-community', 'Rambox', 'Rambox is a workspace browser that allows you to manage as many applications as you want, all in one place. It is perfect for people who care about productivity and work with many applications, both business and personal.', 'Office', 'rambox-rambox-community-icon', ''),
('ramensoftware-7+taskbartweaker', '7+ Taskbar Tweaker', 'Customize the Windows taskbar with dozens of exclusive options. Adapt the taskbar to your workflow, not the other way around.', 'Utilities', 'ramensoftware-7+taskbartweaker-icon', ''),
('ramensoftware-windhawk', 'Windhawk', 'The customization marketplace for Windows programs. Customize your programs with available code snippets or create your own customizations.', 'Development', 'ramensoftware-windhawk-icon', ''),
('randomengy-vidcoder', 'VidCoder', 'VidCoder is an open-source DVD/Blu-ray ripping and video transcoding application for Windows. It uses HandBrake as its encoding engine.', 'Development', 'randomengy-vidcoder-icon', ''),
('randomengy-vidcoder-beta', 'VidCoder Beta (Portable)', 'VidCoder is an open-source DVD/Blu-ray ripping and video transcoding application for Windows. It uses HandBrake as its encoding engine.', 'Development', 'randomengy-vidcoder-beta-icon', ''),
('randyrants-sharpkeys', 'SharpKeys', 'SharpKeys is a utility that manages a Registry key that allows Windows to remap one key to any other key. Included in the application is a list of common keyboard keys and a Type Key feature to automatically recognize most keyboard keys.', 'Utilities', 'randyrants-sharpkeys-icon', ''),
('raspberrypifoundation-raspberrypiimager', 'Raspberry Pi Imager', 'Raspberry Pi Imager is the quick and easy way to install Raspberry Pi OS and other operating systems to a microSD card, ready to use with your Raspberry Pi.', 'Design', 'raspberrypifoundation-raspberrypiimager-icon', ''),
('ravenproject-ravencore', 'Raven Core', 'Ravencoin Core is the original Ravencoin client and it builds the backbone of the network. It downloads and, by default, stores the entire history of Ravencoin transactions; depending on the speed of your computer and network connection, the synchronization process is typically complete in under an hour.', 'Utilities', 'ravenproject-ravencore-icon', ''),
('rawtherapee-rawtherapee', 'RawTherapee', 'RawTherapee is a powerful, cross-platform raw photo processing system, released as Free Software (GPLv3). It is designed for developing raw files from a broad range of digital cameras and targeted at users ranging from enthusiast newcomers who wish to broaden their understanding of how digital imaging works to professional photographers.', 'Development', 'rawtherapee-rawtherapee-icon', ''),
('rawtherapee-rawtherapee-dev', 'RawTherapee', 'RawTherapee is a free, cross-platform raw image processing program', 'Design', 'rawtherapee-rawtherapee-dev-icon', ''),
('rawns-reddit-wallpaper-changer', 'Reddit Wallpaper Changer', 'Reddit Wallpaper Changer is a lightweight C# application for Windows that will scrape Reddit for fresh desktop wallpapers. You can specify which subs to scrape from and how often to rotate your wallpaper.', 'Utilities', 'rawns-reddit-wallpaper-changer-icon', ''),
('raynersec-hyper-v-switch', 'Hyper-V-Switch', 'This Program Enables And Disables Hyper-V Hypervisor So You Can Use Other Virtualization Tools Such As (VMware, VirtualBox) Simultaneously.', 'Utilities', 'raynersec-hyper-v-switch-icon', ''),
('rclone-rclone', 'Rclone', 'Rclone ("rsync for cloud storage") is a command-line program to sync files and directories to and from different cloud storage providers.', 'Development', 'rclone-rclone-icon', ''),
('readdle-spark', 'Spark Desktop', 'Fast, cross-platform email designed to filter out the noise - so you can focus on what''s important.', 'Design', 'readdle-spark-icon', ''),
('realvnc-vncserver', 'VNC Server', 'Virtual network computing (VNC) is a type of remote-control software that makes it possible to control another computer over a network connection.', 'Utilities', 'realvnc-vncserver-icon', ''),
('realvnc-vncviewer', 'VNC Viewer', 'Virtual network computing (VNC) is a type of remote-control software that makes it possible to control another computer over a network connection.', 'Utilities', 'realvnc-vncviewer-icon', ''),
('realtimesoft-ultramon', 'UltraMon', 'Window management utility for multi-monitor systems', 'Utilities', 'realtimesoft-ultramon-icon', ''),
('receitafederaldobrasil-irpf2023', 'IRPF 2023', 'IRPF 2023 - Declaração de Ajuste Anual, Final de Espólio e Saída Definitiva do País', 'Utilities', 'receitafederaldobrasil-irpf2023-icon', ''),
('reckel-cantara', 'Cantara', 'Cantara Song is a song presentation software which can be used for presenting songs in churches, small groups or karaoke parties. It supports various input formats and can create beautiful presentation slides or copies the lyrics into the clipboard so that they can easily shared via chat messengers.', 'Development', 'reckel-cantara-icon', '');

INSERT INTO apps (id, name, description, category, icon, linux_alternative) VALUES
('recoupler-audiobookconverter', 'AudioBookConverter', 'AudioBookConverter was originally designed as simple and lightweigh application to convert set of mp3 files to single m4b (aac) file to be played on your i-device (or any device now) Overtime AudioBookConverter evolved and currently can support converion of most of popular formats to m4b, it also can handle existing m4b files and process them. AudioBookConverter can working smart to find relevant artwork and can do avanced chapter management.', 'Audio', 'recoupler-audiobookconverter-icon', ''),
('redducks-cemui', 'CemUI', 'Front end launcher for the WiiU emulator, Cemu', 'Games', 'redducks-cemui-icon', ''),
('redhat-podman', 'Podman', 'Podman is a daemonless, open source, Linux native tool designed to make it easy to find, run, build, share and deploy applications using Open Containers Initiative (OCI) Containers and Container Images. Podman provides a command line interface (CLI) familiar to anyone who has used the Docker Container Engine. Most users can simply alias Docker to Podman (alias docker=podman) without any problems. Similar to other common Container Engines (Docker, CRI-O, containerd), Podman relies on an OCI compliant Container Runtime (runc, crun, runv, etc) to interface with the operating system and create the running containers. This makes the running containers created by Podman nearly indistinguishable from those created by any other common container engine.', 'Development', 'redhat-podman-icon', ''),
('redhat-podman-desktop', 'Podman Desktop', 'Manage different container engines from a single UI and tray icon', 'Utilities', 'redhat-podman-desktop-icon', ''),
('redhat-virtviewer', 'VirtViewer', 'Virt Viewer provides a graphical viewer for the guest OS display. At this time is supports guest OS using the VNC or SPICE protocols. Further protocols may be supported in the future as user demand dictates. The viewer can connect directly to both local and remotely hosted guest OS, optionally using SSL/TLS encryption.', 'Development', 'redhat-virtviewer-icon', ''),
('redisant-littletips', 'Little Tips', 'Display keyboard shortcuts list for active window', 'Utilities', 'redisant-littletips-icon', ''),
('reginald-reginald', 'Reginald', 'An application launcher and productivity app for Windows 10', 'Games', 'reginald-reginald-icon', ''),
('regressi-regressi', 'Regressi', 'Regressi est un logiciel, Libre d''utilisation, sous Windows, Mac et Linux, de traitements de données expérimeentales. Ils permet de calculer des grandeurs combinées (avec les incertitudes associées) et de faire des ajustements (fit) par régression linéaire ou non, à une fonction différentielles. ', 'Utilities', 'regressi-regressi-icon', ''),
('reincubateltd-camostudio', 'Camo Studio', 'Use your phone as a webcam', 'Utilities', 'reincubateltd-camostudio-icon', ''),
('reincubateltd-iphonebackupextractorsetup', 'iPhone Backup Extractor Setup', 'Extract iPhone backups and download iCloud backups', 'Utilities', 'reincubateltd-iphonebackupextractorsetup-icon', ''),
('rejminetgroupinc-pdfshow', 'PDFShow', 'Present slide shows from a PDF of the slide deck', 'Development', 'rejminetgroupinc-pdfshow-icon', ''),
('remnote-remnote', 'RemNote', 'The all-in-one tool for thinking and learning', 'Design', 'remnote-remnote-icon', ''),
('remixdev-deemix-gui', 'deemix-gui', 'An electron app that wraps deemix-webui and lets you use the deemix-js library', 'Utilities', 'remixdev-deemix-gui-icon', ''),
('remixteam-remixide', 'Remix IDE', 'Remix Desktop is an Electron version of Remix IDE', 'Development', 'remixteam-remixide-icon', ''),
('remoteutilities-viewer', 'Remote Utilities - Viewer', 'Viewer is a single "command center" used by a support technician/admin. The Viewer is where you keep your address book, start remote sessions and manage your licenses.', 'Design', 'remoteutilities-viewer-icon', ''),
('renewedvision-propresenter', 'ProPresenter', 'ProPresenter is a cross-platform (Mac and Windows) presentation & production application for live events. It seamlessly displays lyrics, slides, and media, making high-quality live productions easy. It is the indispensable tool for worship gatherings, sporting events, conferences, trade shows, and studio broadcasts.', 'Development', 'renewedvision-propresenter-icon', ''),
('renode-renode', 'Renode', 'Renode is a development framework which accelerates IoT and embedded systems development by letting you simulate physical hardware systems - including both the CPU, peripherals, sensors, environment and wired or wireless medium between nodes.  It lets you run, debug and test unmodified embedded software on your PC - from bare System-on-Chips, through complete devices to multi-node systems.', 'Development', 'renode-renode-icon', ''),
('renoise-renoise', 'Renoise', 'Renoise is a Digital Audio Workstation (DAW) with a refreshing twist. It lets you record, compose, edit, process and render production-quality audio using a tracker-based approach.', 'Development', 'renoise-renoise-icon', ''),
('reolink-reolink', 'Reolink', 'Get live streaming, play back clips, customize motion detection and more. Connect with your loved ones whenever and wherever you are', 'Utilities', 'reolink-reolink-icon', ''),
('reptarsrage-looking-glass', 'The Looking-Glass', 'Electron application to browse various website content from one app. Built for development practice only.', 'Development', 'reptarsrage-looking-glass-icon', ''),
('rescuetime-desktopapp', 'RescueTime', 'Desktop client for RescueTime time tracking service (rescuetime.com). Automatically track and get insights on how you spend your time on apps and websites. No manual time entry, finicky timers, or start/stop buttons required. Free version available; upgrade required for full feature set.', 'Development', 'rescuetime-desktopapp-icon', ''),
('resilio-resiliosync', 'Resilio Sync', 'Resilio Sync is a fast, reliable, and simple file sync and share solution, powered by P2P technology', 'Utilities', 'resilio-resiliosync-icon', ''),
('resplendence-latencymon', 'LatencyMon', 'LatencyMon checks if a system running Windows is suitable for processing real-time audio and other tasks. LatencyMon analyzes the possible causes of buffer underruns by measuring kernel timer latencies and reporting DPC and ISR execution times as well as hard pagefaults. It will provide a comprehensible report and find the kernel modules and processes responsible for causing audio latencies which result in drop outs. It also provides the functionality of an ISR monitor, DPC monitor and a hard pagefault monitor.', 'Development', 'resplendence-latencymon-icon', ''),
('resplendence-multimon', 'MultiMon', 'Multifunctional application, system, file system, registry and user monitor', 'Utilities', 'resplendence-multimon-icon', ''),
('resplendence-registrarregistrymanager', 'Registrar Registry Manager', 'Advanced Registry Manager for administrators and power users', 'Utilities', 'resplendence-registrarregistrymanager-icon', ''),
('resplendence-sanitycheck', 'Sanity Check', 'Advanced rootkit and malware detector', 'Utilities', 'resplendence-sanitycheck-icon', ''),
('resplendence-undeluxe', 'Undeluxe', 'Advanced file protection and recovery', 'Utilities', 'resplendence-undeluxe-icon', ''),
('resplendence-whocrashed', 'WhoCrashed', '''WhoCrashed reveals the drivers responsible for crashing your computer

Whenever a computer running Windows suddenly reboots without displaying any notice or blue or black screen of death, the first thing that is often thought about is a hardware failure.
In reality, crashes are often caused by malfunctioning device drivers and kernel modules.
In case of a kernel error, computers running Windows do not show a blue or black screen unless they are configured to do so.
Instead these systems suddenly reboot without any notice.

WhoCrashed shows the drivers that have been crashing your computer with a single click.
In most cases it can pinpoint the offending drivers that have been causing misery on your computer system in the past.
It does post-mortem crashdump analysis and presents all gathered information in a comprehensible way.
In case your system has been crashing because of a hardware failure, WhoCrashed will provide you with guidance to trace the root cause of the problem.

Normally, debugging skills and a set of debugging tools are required to do post-mortem crash dump analysis.
Using WhoCrashed you do not need any debugging skills to be able to find out what drivers are causing trouble to your computer.''', 'Development', 'resplendence-whocrashed-icon', ''),
