('sshfs-win-sshfs-win', 'SSHFS-Win', 'SSHFS-Win is a minimal port of SSHFS to Windows. Under the hood it uses Cygwin for the POSIX environment and WinFsp for the FUSE functionality.', 'Utilities', 'sshfs-win-sshfs-win-icon', ''),
('superantispyware-superantispyware', 'SUPERAntiSpyware', 'Detects and remove spyware, adware, malware, trojans, rogue software, worms, rootkits, parasites and other potentially harmful software applications, as well as restore modified system settings.', 'Utilities', 'superantispyware-superantispyware-icon', ''),
('surf-letsconnectclient', 'Let''s Connect! Client', 'Access your institute''s network or the Internet using an encrypted connection.', 'Utilities', 'surf-letsconnectclient-icon', ''),
('surf-eduvpnclient', 'eduVPN Client', 'Access your institute''s network or the Internet using an encrypted connection.', 'Utilities', 'surf-eduvpnclient-icon', '');

INSERT INTO apps (id, name, description, category, icon, linux_alternative) VALUES
('svgexplorerextension-svgexplorerextension', 'SVG See', 'Extension module for Windows Explorer to render SVG thumbnails, so that you can have an overview of your SVG files.', 'Design', 'svgexplorerextension-svgexplorerextension-icon', ''),
('svzsoft-gedkeeper', 'GEDKeeper2', 'GEDKeeper is an open-source and cross-platform genealogy management program. The lightweight, fast and reliable program to offer user friendly but powerful user interface for hobbyist, family historian and serious genealogy researcher. It fully supports the GEDCOM standard, has no restrictions on the number of persons and generations, allows to store, edit, and research genealogical data and offers numerous views like family tree, charts, tables (individuals, families, etc), reports, timeline and more. 
It supports multimedia and allows privacy control; allows you to interactively browse family trees and charts; and make changes, such as adding new people and adding or deleting images or notes and stories.
It provides fast navigation, filtering, searching and adding multimedia materials. 
Supports output of geographic data on maps. Cartography, statistics, dynamic graphical trees and reports can be viewed on screen, send to a printer, or saved as image-files. Extensible base of program provides easy implementation of new features (both plugins and powerful scripts) and localize to new user’s languages.', 'Development', 'svzsoft-gedkeeper-icon', ''),
('swi-prolog-swi-prolog', 'SWI-Prolog', 'SWI-Prolog offers a comprehensive free Prolog environment. Since its start in 1987, SWI-Prolog development has been driven by the needs of real world applications. SWI-Prolog is widely used in research and education as well as commercial applications.', 'Development', 'swi-prolog-swi-prolog-icon', ''),
