('sergeyserkov-tagscanner', 'TagScanner', 'TagScanner is a powerful tool for organizing and managing your music collection. It can edit tags of most modern audio formats, supports ID3v1/v2, Vorbis comments, APEv2, WMA and MP4(iTunes) tags.', 'Audio', 'sergeyserkov-tagscanner-icon', ''),
('serhiislieptsov-utilso', 'Utilso', 'All-in-one tools for developers', 'Development', 'serhiislieptsov-utilso-icon', ''),
