('simbustsoftware-monaminote', 'MonAmi Note', 'Simple yet robust Markdown note-taking app featuring folder/tag organization, stealth data protection, and web app with cloud storage', 'Utilities', 'simbustsoftware-monaminote-icon', ''),
('simon511000-citycraftlauncher', 'Citycraft Launcher', 'Join modded servers without worrying about installing Java, Forge, or other mods. We''ll handle that for you.', 'Games', 'simon511000-citycraftlauncher-icon', ''),
