('sinew-enpass', 'Enpass', 'Enpass is a cross-platform password management app to securely store passwords and other credentials in a virtual vault locked with a master password. Unlike most other popular password managers, Enpass is an offline password manager', 'Office', 'sinew-enpass-icon', ''),
('singularlabs-ccenhancer', 'CCEnhancer', 'CCEnhancer is a small tool which adds support for over 1,000 new programs into the popular program CCleaner. The tool uses the winapp2.ini system built into CCleaner to easily add new rules and definitions for programs.', 'Utilities', 'singularlabs-ccenhancer-icon', ''),
('skaarhoj-keybridge', 'KeyBridge', 'SKAARHOJ KeyBridge', 'Utilities', 'skaarhoj-keybridge-icon', ''),
