('sky-skygo', 'Sky Go', 'The Sky Go desktop app makes it even easier for you to find the programmes you want to watch. And with Sky Mobile, you can watch Sky TV on the go without using your data.', 'Utilities', 'sky-skygo-icon', ''),
('slacktechnologies-slack', 'Slack', 'Slack is a collaboration hub for work, no matter what work you do. It''s a place where conversations happen, decisions are made, and information is always at your fingertips. With Slack, your team is better connected.', 'Social', 'slacktechnologies-slack-icon', ''),
('slacktechnologies-slack-beta', 'Slack Beta', 'Slack is a collaboration hub for work, no matter what work you do. It''s a place where conversations happen, decisions are made, and information is always at your fingertips. With Slack, your team is better connected.', 'Social', 'slacktechnologies-slack-beta-icon', ''),
('slackedlime-timespent', 'TimeSpent', 'A simple GUI rust application that keeps track of how much time you spend on each application', 'Utilities', 'slackedlime-timespent-icon', ''),
('slashedio-inssist', 'Inssist', 'Inssist stands for Instagram Assistant. It is a powerful Chrome Extension (plugin) and a standalone app that brings
Instagram Mobile View to your desktop. It allows posting photos, videos and stories, managing comments and sending DMs
as if you were using a mobile version of Instagram web app, plus scheduling content, finding relevant hashtags and
much more.', 'Development', 'slashedio-inssist-icon', ''),
('sleuthkit-autopsy', 'Autopsy', 'Autopsy is the premier end-to-end open source digital forensics platform.', 'Development', 'sleuthkit-autopsy-icon', ''),
('slik-subversion', 'Slik Subversion', 'Apache Subversion Subversion is a free/open source version control system. This package delivers the commandline tools in an easy to setup way.', 'Utilities', 'slik-subversion-icon', ''),
('slonopotamus-stevedore', 'Stevedore', 'Docker distribution for Windows that Just Works', 'Utilities', 'slonopotamus-stevedore-icon', ''),
('smallstep-step', 'step', 'A Swiss army knife for working with X.509 certificates, JWTs, etc.', 'Utilities', 'smallstep-step-icon', ''),
('smallstep-step-ca', 'step', 'A private certificate authority (X.509 & SSH) & ACME server for secure automated certificate management.', 'Utilities', 'smallstep-step-ca-icon', ''),
('smartbear-soapui', 'SoapUI', 'Description: Built for developers and testers alike, SoapUI is the only open source tool that covers the entire testing spectrum (functional, security, load, mocking). With its easy-to-use graphical interface, SoapUI is the entry point for API testing so you can validate REST & SOAP-based web services with ease.', 'Development', 'smartbear-soapui-icon', ''),
('smartgamebooster-smartgamebooster', 'Smart Game Booster', 'It boosts FPS for better gaming experience. It protects your gaming accounts.', 'Games', 'smartgamebooster-smartgamebooster-icon', ''),
('smartholdemdapps-heads-tails', 'Heads-Tails', 'Heads or Tails is a multiplayer game, based on the DPOS blockchain with instant payments, built-in wallet and exchange platform for popular cryptocurrencies', 'Games', 'smartholdemdapps-heads-tails-icon', ''),
('smartprojects-isobuster', 'IsoBuster', 'The Ultimate data recovery software! Supporting ALL types of media, including CD/DVD, BD/HD DVD, Hard Drives, SSM, USB flash drives, Zip drives, Jaz drives, floppies etc.', 'Design', 'smartprojects-isobuster-icon', ''),
('smartsoft-smartftp', 'SmartFTP Client', 'SmartFTP is a fast and reliable FTP, FTPS, SFTP, HTTP, Amazon S3, WebDAV, Google Drive, Google Cloud Storage, Microsoft OneDrive, Backblaze B2, Telnet, Terminal client with lots of features and a modern user interface.', 'Design', 'smartsoft-smartftp-icon', ''),
('smile-textexpander', 'TextExpander', 'Create snippets of text for support responses, sales outreach, or even common emails and save them in TextExpander.', 'Utilities', 'smile-textexpander-icon', ''),
('smogon-pokemonshowdown', 'Pokemon Showdown', 'Pokémon Showdown is a Pokémon battle simulator. Play Pokémon battles online! Play with randomly generated teams, or build your own! Fully animated!', 'Utilities', 'smogon-pokemonshowdown-icon', ''),
('smokecloud-fdspp', 'FdsPp', 'A pre-processor for FDS (Fire Dynamics Simulator) input files.', 'Utilities', 'smokecloud-fdspp-icon', ''),
('snaildos-fifo', 'Fifo', 'Fifo is a nonprofit, fast free and secure Web Browser. It’s based on Wexond, and includes news and tons of features out of the box. Fifo is resource effecient, and is updated often. Powered by SnailDOS!', 'Utilities', 'snaildos-fifo-icon', ''),
('snaildos-snailfm', 'SnailFM', 'SnailFM-Application, Wonderful electro music in your ears! We provide the best nocopyright music made for your streams! If you are a streamer, please use StreamBop!', 'Development', 'snaildos-snailfm-icon', ''),
('snaildos-streambop', 'StreamBop', 'StreamBop allows you to stream and have this application automatically play music and credit them for you! No copyright music too!', 'Audio', 'snaildos-streambop-icon', ''),
('snapmakerdevteam-snapmakerluban', 'Snapmaker Luban', 'Snapmaker 3-in-1 Software for 3D Printing, Laser Engraving and CNC Cutting.', 'Design', 'snapmakerdevteam-snapmakerluban-icon', ''),
('snaz-snaz', 'Snaz', 'Snaz for OBS', 'Utilities', 'snaz-snaz-icon', ''),
('snoopwpf-snoop', 'Snoop', 'A Windows Presentation Foundation (WPF) tool which allows you to spy/browse the visual tree of a running application (without the need for a debugger) and change properties, view triggers, set breakpoints on property changes and many more things.', 'Office', 'snoopwpf-snoop-icon', ''),
('snyk-snyk', 'Snyk', 'Snyk CLI scans and monitors your projects for security vulnerabilities.', 'Utilities', 'snyk-snyk-icon', ''),
('socialchaininc-pinetwork', 'Pi Network', 'Pi Network desktop app', 'Utilities', 'socialchaininc-pinetwork-icon', '');

INSERT INTO apps (id, name, description, category, icon, linux_alternative) VALUES
('softdeluxe-freedownloadmanager', 'Free Download Manager', 'Free Download Manager (FDM for short) is a free, efficient, and comprehensive solution for managing all your downloads.', 'Utilities', 'softdeluxe-freedownloadmanager-icon', ''),
('softmaker-flexipdf-2022', 'FlexiPDF 2022', 'FlexiPDF is a software for preparing, creating and editing PDF-files. It can be compared to Adobe Acrobat.', 'Design', 'softmaker-flexipdf-2022-icon', ''),
('softmaker-freeoffice-2021', 'SoftMaker FreeOffice 2021', 'The best free alternative to Microsoft Office', 'Office', 'softmaker-freeoffice-2021-icon', ''),
('softmaker-freepdf', 'FreePDF', 'Create, edit, view, print and annotate PDF files... free of charge!', 'Office', 'softmaker-freepdf-icon', ''),
