('softmaker-office-2021', 'SoftMaker Office 2021', 'Your Office suite for Windows, Mac, Linux, Android and iOS', 'Development', 'softmaker-office-2021-icon', ''),
('softperfect-softperfectnetworkscanner', 'SoftPerfect Network Scanner', 'Powerful multipurpose network administration tool for Windows and macOS.', 'Utilities', 'softperfect-softperfectnetworkscanner-icon', ''),
('softerra-ldapbrowser', 'Softerra LDAP Browser', 'Softerra LDAP Browser is a lightweight version of Softerra LDAP Administrator. It supports read-only operations that do not modify LDAP directory data, e.g. browsing, search, export, etc. For complete, fully functional LDAP directory management, you need Softerra LDAP Administrator.', 'Utilities', 'softerra-ldapbrowser-icon', ''),
('softezadevelopment-actualupdater', 'Actual Updater', 'Actual Updater is a simple tool that was designed to help software developers to easily provide latest versions of their applications to users.', 'Development', 'softezadevelopment-actualupdater-icon', ''),
('softouchdevelopment-easyworship', 'EasyWorship', 'Your worship service made easy', 'Utilities', 'softouchdevelopment-easyworship-icon', ''),
('softpointerinc-tag&rename', 'Tag&Rename', 'Tag&Rename is a music files tag editor that easily handles all popular digital audio formats.', 'Development', 'softpointerinc-tag&rename-icon', ''),
('softwarefreedomconservancy-qemu', 'QEMU', 'The QEMU Emulator', 'Utilities', 'softwarefreedomconservancy-qemu-icon', ''),
('softwarefreedomconservancy-qemuguestagent', 'QEMU guest agent', 'Service for Windows guests in QEMU to coordinate snapshot, suspend, and shutdown with the host.', 'Utilities', 'softwarefreedomconservancy-qemuguestagent-icon', ''),
('solidclouds-starborne', 'Starborne', 'Starborne Sovereign Space is not a persistent MMO - instead, new servers are launched regularly, and each game lasts for a few weeks and is then over. Our latest game server is open now. Start playing before it fills up.
', 'Games', 'solidclouds-starborne-icon', ''),
('solidigm-storagetool', 'Solidigm™ Storage Tool', 'The Solidigm™ Storage Tool, also called SST, assists with managing Solidigm™ SSDs.
It provides access to drive information and health, SMART Attributes, Firmware Updates, diagnostic scans, and secure erase.', 'Development', 'solidigm-storagetool-icon', ''),
('solvusoft-winthruster', 'WinThruster', 'Introducing WinThruster, a state-of-the-art technology that detects and repairs hundreds of invalid references that accumulate in your registry-with one click.', 'Design', 'solvusoft-winthruster-icon', ''),
('somepythonthings-elevenclock', 'ElevenClock', 'Have a customizable clock on your Windows 11 taskbar.
When Microsoft''s engineers were creating Windows 11, they forgot to add a clock on the secondary screen taskbar. So I did that. ElevenClock is a simple app that provides the same functionality as in windows 10 secondary taskbar clock.', 'Development', 'somepythonthings-elevenclock-icon', ''),
('somepythonthings-wingetuistore', 'WingetUI', 'The main goal of this project is to give a GUI Store to the most common CLI Package Managers for windows, such as Winget, Scoop and Chocolatey.
 This app allows you to install all the packages published on winget, scoop and appget.', 'Utilities', 'somepythonthings-wingetuistore-icon', ''),
('somepythonthings-zipmanager', 'SomePythonThings Zip Manager', 'SomePythonThings Zip manager is an application that lets you compress and extract files in a clever way. Not as other compression applications, SomePythonThings Zip Manager has been developed to be useful. SomePythonThings Zip Manager is an open-source application, and it''s also 100% free.', 'Development', 'somepythonthings-zipmanager-icon', ''),
('soneliem-waiua', 'WAIUA', 'Who Am I Up Against is simple Windows app that lets you see the ranks, recent games and other info of players in a live Valorant match while you''re still playing it.', 'Games', 'soneliem-waiua-icon', ''),
('sonicpi-sonicpi', 'Sonic Pi', 'Sonic Pi is a code-based music creation and performance tool.', 'Development', 'sonicpi-sonicpi-icon', ''),
('sonicteamjr-sonicroboblast2', 'Sonic Robo Blast 2', 'Sonic Robo Blast 2 is a 3D Sonic the Hedgehog fangame based on a modified version of Doom Legacy.', 'Games', 'sonicteamjr-sonicroboblast2-icon', ''),
('sonicteamjr-sonicroboblast2kart', 'Sonic Robo Blast 2 Kart', 'SRB2Kart is a classic styled kart racer, complete with beautiful courses, and wacky items.', 'Design', 'sonicteamjr-sonicroboblast2kart-icon', ''),
('sonicvisualiser-sonicvisualiser', 'Sonic Visualiser', 'Sonic Visualiser is a free, open source, cross-platform desktop application for music audio visualisation, annotation, and analysis.', 'Audio', 'sonicvisualiser-sonicvisualiser-icon', ''),
('sonicwall-connecttunnel', 'Connect Tunnel', 'Connect Tunnel provides an in-office experience for a remote working world with full access away from the office.', 'Development', 'sonicwall-connecttunnel-icon', ''),
('sonicwall-globalvpn', 'Global VPN Client', 'Dell SonicWALL Global VPN Client', 'Utilities', 'sonicwall-globalvpn-icon', ''),
('sonicwall-netextender', 'SonicWall NetExtender', 'SonicWall SSL VPN Client', 'Utilities', 'sonicwall-netextender-icon', ''),
('sonos-controller', 'Sonos S2 Controller', 'Sonos S2 is a new app and operating system (OS) that will power the next generation of Sonos products and experiences.

Take listening to the next level with Sonos S2. This new generation of the app features support for higher resolution audio, an improved design, increased security, and smarter software to keep your system up to date.', 'Audio', 'sonos-controller-icon', ''),
('sonos-s1controller', 'Sonos Controller', 'Sonos S1 Controller, Control your legacy S1 speakers, group rooms to play in sync, and quickly search for music and more.', 'Audio', 'sonos-s1controller-icon', ''),
('sonosaurus-sonobus', 'SonoBus', 'SonoBus is an easy to use application for streaming high-quality, low-latency peer-to-peer audio between devices over the internet or a local network.', 'Audio', 'sonosaurus-sonobus-icon', ''),
('sonsofexiled-arma3sync', 'ArmA3Sync', 'ARMA 3 Mod Sync Manager', 'Utilities', 'sonsofexiled-arma3sync-icon', ''),
('soroush-soroush+', 'Soroush+ Desktop Application', 'Soroush+ instant messaging app', 'Utilities', 'soroush-soroush+-icon', ''),
('soroushchehresa-unsplashwallpapers', 'Unsplash Wallpapers', 'A menubar application for Mac, Windows and Linux that brings stunning wallpapers from Unsplash right to your desktop. Works on macOS 10.12+, Windows 10+ and Linux.', 'Utilities', 'soroushchehresa-unsplashwallpapers-icon', ''),
('soulseek-soulseekqt', 'SoulseekQt', 'Peer-to-peer file sharing', 'Utilities', 'soulseek-soulseekqt-icon', ''),
('soundly-soundly', 'Soundly', 'Find your perfect sound in the massive Soundly cloud library, use our powerful search engine on your local files, and Drag&Drop sounds to your favorite tools!', 'Audio', 'soundly-soundly-icon', ''),
('sourcefoundry-hackfonts', 'Hack Fonts', 'A Windows installer for the Hack typeface. While it might seem like overkill to use a Windows installer for fonts, there is good reason for this on the Windows platform.', 'Utilities', 'sourcefoundry-hackfonts-icon', ''),
('sourcegear-diffmerge', 'SourceGear DiffMerge', 'DiffMerge is an application to visually compare and merge files and folders on Windows, OS X, and Linux.', 'Utilities', 'sourcegear-diffmerge-icon', ''),
('sovranti-sovranti', 'Sovranti', 'Online board game library', 'Games', 'sovranti-sovranti-icon', ''),
('spacemesh-spacemesh', 'Spacemesh', 'Smesher UI + Wallet', 'Utilities', 'spacemesh-spacemesh-icon', ''),
('spanishgovernment-autofirma', 'Autofirma', 'AutoFirma es una herramienta de escritorio con interfaz gráfica que permite la ejecución de operaciones de firma de ficheros locales en entornos de escritorio (Windows, Linux y Mac OS X). Ofrece la posibilidad de realizar firmas de en cualquier tipo de documento de forma sencilla.', 'Office', 'spanishgovernment-autofirma-icon', ''),
('sparklabs-viscosity', 'Viscosity', 'A first class OpenVPN client that lets you secure your network with ease & style.', 'Utilities', 'sparklabs-viscosity-icon', ''),
('sparklabs-openvpn-configuration-generator', 'OpenVPN Configuration Generator', 'The OpenVPN Configuration Generator is designed to make generating server and client configurations for an OpenVPN server and Viscosity easier.', 'Design', 'sparklabs-openvpn-configuration-generator-icon', ''),
('sparkleshare-sparkleshare', 'SparkleShare', 'SparkleShare is a file sharing and collaboration app. It works just like Dropbox, and you can run it on your own server.', 'Utilities', 'sparkleshare-sparkleshare-icon', ''),
('spatie-ray', 'Ray', 'Ray is a desktop app that vastly improves your debugging experience. It is a dedicated window to send debugging information to.', 'Development', 'spatie-ray-icon', ''),
('specialk-specialk', 'Special K', 'Lovingly referred to as the Swiss Army Knife of PC gaming, Special K does a bit of everything.
It is best known for fixing and enhancing graphics, its many detailed performance analysis and correction mods,
and a constantly growing palette of tools that solve a wide variety of issues affecting PC games.
', 'Games', 'specialk-specialk-icon', ''),
('speedcrunch-speedcrunch', 'SpeedCrunch', 'SpeedCrunch is a high-precision scientific calculator. It features a syntax-highlighted scrollable display and is designed to be fully used via keyboard. Some distinctive features are auto-completion of functions and variables, a formula book, and quick insertion of constants from various fields of knowledge. It is available for Windows, OS X, and Linux in a number of languages.', 'Design', 'speedcrunch-speedcrunch-icon', ''),
('spice-spicewebdavd', 'Spice webdavd', 'SPICE (the Simple Protocol for Independent Computing Environments) is a remote-display system built for virtual environments.  SPICE WebDAVd implements the file sharing protocol based on WebDAV (RFC 4918) for Windows guest virtual machines to share files with the host.', 'Utilities', 'spice-spicewebdavd-icon', ''),
('spice-vdagent', 'Spice agent', 'SPICE (the Simple Protocol for Independent Computing Environments) is a remote-display system built for virtual environments.  The Guest Agent leverages the protocol to provide several features, such as client mouse mode, automatic adjustment of the Windows desktop resolution to the client resolution, and Support of copy and paste (text and images) between the active Windows session and the client.', 'Development', 'spice-vdagent-icon', ''),
('spicebrains-instant-eyedropper', 'Instant Eyedropper', 'Instant Eyedropper is a free color detection tool for webmasters that will identify and automatically paste to the clipboard the HTML color code of any pixel on the screen with just a single mouse click.', 'Development', 'spicebrains-instant-eyedropper-icon', ''),
('spicetify-spicetify', 'Spicetify', 'A command-line tool to customize the official Spotify client.', 'Utilities', 'spicetify-spicetify-icon', ''),
('splashtop-sos', 'Splashtop SOS - On-Demand Remote Support', 'Easily enable IT to provide secure remote support to your devices while you are at your device or computer. Your technician will be able to remotely screen share and guide you through solving issues in real-time.', 'Development', 'splashtop-sos-icon', ''),
('splashtop-splashtopbusiness', 'Splashtop Business', 'Splashtop Business provides secure remote access across your organization. Users can work from anywhere with remote access to their office computer from a laptop or mobile device. IT/Helpdesk teams have all the features they need to manage remote support.', 'Development', 'splashtop-splashtopbusiness-icon', ''),
('splashtop-splashtoppersonal', 'Splashtop Personal', 'Splashtop Personal is the easiest and fastest way to remotely access your computers. Use Splashtop Personal for free on the local network to access your home computer, and use from anywhere across the Internet by subscribing to Anywhere Access Pack.', 'Utilities', 'splashtop-splashtoppersonal-icon', ''),
('splashtop-splashtopstreamer', 'Splashtop Streamer', 'Install the Splashtop Streamer on any computers that you want to remotely access, view, and control from another device using the Splashtop app. Set up the streamer with a Splashtop Account email and password.', 'Office', 'splashtop-splashtopstreamer-icon', ''),
('splashtop-splashtopstreamer-deployment', 'Splashtop Streamer Deployment', 'Install the Splashtop Streamer on any computers that you want to remotely access, view, and control from another device using the Splashtop app. Set up the streamer with a deployment code available on your Splashtop web console.', 'Development', 'splashtop-splashtopstreamer-deployment-icon', ''),
('splashtop-splashtopstreamer-deployment-msi', 'Splashtop Streamer Deployment (MSI)', 'Install the Splashtop Streamer on any computers that you want to remotely access, view, and control from another device using the Splashtop app. Set up the streamer with a deployment code available on your Splashtop web console.', 'Development', 'splashtop-splashtopstreamer-deployment-msi-icon', ''),
('splashtop-splashtopwiredxdisplay', 'Splashtop Wired XDisplay Agent', 'Turn your iPad, Android tablet, Kindle or smartphone into a high performance extra monitor for your computer', 'Design', 'splashtop-splashtopwiredxdisplay-icon', ''),
('splawik-pytigon', 'pytigon', 'The combination of several technologies: python, django, wxWidgets to create one coherent development environment for systems: Windows, Linux and more.', 'Development', 'splawik-pytigon-icon', ''),
('splitcam-splitcam', 'SplitCam', 'Live streaming software with multistreaming & free restreaming. Use it for Live Streaming, Video Recording, Game Streaming, Presentations & Online Classes and for fun.', 'Games', 'splitcam-splitcam-icon', ''),
('splunk-acs', 'ACS', 'Admin Config Service CLI for managing Splunk cloud stacks. ACS is a cloud-native API that provides programmatic self-service administration capabilities for Splunk Cloud Platform. Splunk Cloud Platform administrators can use the ACS CLI to perform common administrative tasks without assistance from Splunk Support.', 'Development', 'splunk-acs-icon', ''),
('splunk-universalforwarder', 'UniversalForwarder', 'The universal forwarder collects data from a data source or another forwarder and sends it to a forwarder or a Splunk deployment. With a universal forwarder, you can send data to Splunk Enterprise, Splunk Light, or Splunk Cloud.', 'Utilities', 'splunk-universalforwarder-icon', ''),
('spongenobody-clashy', 'Clashy', 'A GUI proxy client for Windows based on Clash and Electron.', 'Utilities', 'spongenobody-clashy-icon', ''),
('spotify-spotify', 'Spotify', 'With Spotify, it’s easy to find the right music or podcast for every moment – on your phone, your computer, your tablet and more.
There are millions of tracks and episodes on Spotify. So whether you’re behind the wheel, working out, partying or relaxing, the right music or podcast is always at your fingertips. Choose what you want to listen to, or let Spotify surprise you.
You can also browse through the collections of friends, artists, and celebrities, or create a radio station and just sit back.', 'Audio', 'spotify-spotify-icon', ''),
('spyder-spyder', 'Spyder', 'Scientific Python Development Environment similar to matlab', 'Development', 'spyder-spyder-icon', ''),
('squarecloud-cli', 'Square Cloud CLI', 'Square Cloud CLI is a fast and light command line tool to manage your Square Cloud applications', 'Utilities', 'squarecloud-cli-icon', ''),
('squitch-tess', 'Tess', 'Tess is a hackable, simple, rapid and beautiful terminal for the new era of technology.', 'Utilities', 'squitch-tess-icon', ''),
('stackexchange-dnscontrol', 'DNSControl', 'DNSControl is a system for maintaining DNS zones. It has two parts: a domain specific language (DSL) for describing DNS zones plus software that processes the DSL and pushes the resulting zones to DNS providers such as Route53, Cloudflare, and Gandi. It can send the same DNS records to multiple providers. It even generates the most beautiful BIND zone files ever. It runs anywhere Go runs (Linux, macOS, Windows). The provider model is extensible, so more providers can be added.', 'Development', 'stackexchange-dnscontrol-icon', ''),
('stackers-stack', 'Stack', 'Organize and manage your social media, messenger, email, productivity apps, and anything else you want from one place on a single screen.', 'Social', 'stackers-stack-icon', ''),
('standardnotes-standardnotes', 'Standard Notes', 'Standard Notes is an end-to-end encrypted note-taking app for digitalists and professionals.
Capture your notes, files, and life’s work all in one secure place.', 'Development', 'standardnotes-standardnotes-icon', ''),
('stardock-curtains', 'Stardock Curtains', 'Curtains works similarly to the modes that Microsoft has implemented. Any app that already supports the existing dark and light modes will automatically benefit from Curtains. Stardock Curtains includes several new styles, like Crystal, Sky and Midnight. It also includes styles that let you change Windows to look like previous versions (XP, Windows 95, etc.) as well as alternative operating systems.', 'Utilities', 'stardock-curtains-icon', ''),
('stardock-fences', 'Stardock Fences 4', 'Automatically organize your desktop apps, files, and folders on Windows 10 and 11.', 'Utilities', 'stardock-fences-icon', ''),
('stardock-start10', 'Stardock Start10', 'Start10 software, replaces the Start menu with a classic version. This Windows 7-style look is a comfortable return to the form and function you expect.', 'Design', 'stardock-start10-icon', ''),
('stardock-start11', 'Stardock Start11', 'Customize the Start Menu and Taskbar in Windows 10/11', 'Design', 'stardock-start11-icon', ''),
('starfacegmbh-starfaceucc', 'STARFACE UCC Client', 'The STARFACE UCC Client brings together all communication channels on your desktop, making it an innovative control center for your office communications. STARFACE UCC Client is the desktop user interface for your telephony system. Drag and drop the functions to arrange them exactly how you want them to be laid out.', 'Office', 'starfacegmbh-starfaceucc-icon', ''),
('starfacegmbh-starfaceucc-beta', 'Starface UCC Beta', 'The STARFACE UCC Client brings together all communication channels on your desktop, making it an innovative control center for your office communications. STARFACE UCC Client is the desktop user interface for your telephony system. Drag and drop the functions to arrange them exactly how you want them to be laid out.', 'Office', 'starfacegmbh-starfaceucc-beta-icon', ''),
('starship-starship', 'starship', 'The minimal, blazing-fast, and infinitely customizable prompt for any shell!

- Fast: it''s fast – really really fast! 🚀
- Customizable: configure every aspect of your prompt.
- Universal: works on any shell, on any operating system.
- Intelligent: shows relevant information at a glance.
- Feature rich: support for all your favorite tools.
- Easy: quick to install – start using it in minutes.', 'Design', 'starship-starship-icon', ''),
('startisback-startallback', 'StartAllBack', 'StartAllBack fully integrates with Windows 11 and provides original Windows taskbar and start menu, as well as manu other essential shell enhancements.', 'Development', 'startisback-startallback-icon', ''),
('startisback-startisback', 'StartIsBack++', 'StartIsBack returns Windows 10 and Windows 8 a real fully featured start menu and start button, behaving exactly like the ones in Windows 7.', 'Design', 'startisback-startisback-icon', ''),
('startpack-firework', 'Firework', 'Firework turns web applications and sites into desktop applications.', 'Utilities', 'startpack-firework-icon', ''),
('steamgriddb-rommanager', 'Steam ROM Manager', 'Steam ROM Manager is a super flexible tool for adding non-Steam games to steam in bulk and managing their artwork assets.
