('stefheyenrath-githubreleasenotes', 'GitHubReleaseNotes', 'Generate Release Notes in MarkDown format from a GitHub project.', 'Development', 'stefheyenrath-githubreleasenotes-icon', ''),
('stefanberg-nina', 'N.I.N.A. Nighttime Imaging ''N'' Astronomy', 'N.I.N.A. is a software designed for all deep sky object imagers. Whether you''re new to the world of Deep Sky Object imaging or an experienced veteran, this projects goal is to make your image capture easier, faster, and more convenient.', 'Design', 'stefanberg-nina-icon', ''),
