('stellardatarecovery-stellarextractorforwindowsbackup', 'Stellar Extractor for Windows Backup', 'Stellar Extractor for Windows Backup is a fully automated backup recovery solution, designed to deal with inaccessible backup files created using Windows utilities and help users restore entire content from corrupt or damaged BKF, ZIP, VHDX and .FD files.', 'Design', 'stellardatarecovery-stellarextractorforwindowsbackup-icon', ''),
('stellarium-stellarium', 'Stellarium', 'Stellarium is a free open source planetarium for your computer. It shows a realistic sky in 3D, just like what you see with the naked eye, binoculars or a telescope.', 'Design', 'stellarium-stellarium-icon', ''),
