('swiftyapp-swifty', 'Swifty', 'Modern, Lightweight, Fast and Free Password Manager', 'Office', 'swiftyapp-swifty-icon', ''),
('sylikc-jpegview', 'JPEGView', 'JPEGView is a lean, fast and highly configurable viewer/editor for JPEG, BMP, PNG, WEBP, TGA, GIF, JXL, HEIC, HEIF, AVIF and TIFF images with a minimal GUI. Basic on-the-fly image processing is provided.', 'Development', 'sylikc-jpegview-icon', ''),
('syndicode-infektnfoviewer', 'iNFekt NFO Viewer', 'A text viewer application that has been carefully designed around its main task: viewing and presenting NFO files.', 'Design', 'syndicode-infektnfoviewer-icon', ''),
('syvaidya-openstego', 'OpenStego', 'OpenStego is a steganography application that provides two functionalities: a) Data Hiding: It can hide any data within an image file. b) Watermarking: Watermarking image files with an invisible signature. It can be used to detect unauthorized file copying.', 'Development', 'syvaidya-openstego-icon', ''),
('sztheory-exifcleaner', 'ExifCleaner', 'Desktop app to clean metadata from images, videos, PDFs, and other files.', 'Development', 'sztheory-exifcleaner-icon', ''),
('tedit-tedit', 'TEdit', 'TEdit - Terraria Map Editor is a stand alone, open source map editor for Terraria. It lets you edit maps just like (almost) paint!', 'Games', 'tedit-tedit-icon', ''),
('tgrmnsoftware-bulkrenameutility', 'Bulk Rename Utility', 'Bulk Rename Utility allows you to easily rename files and folders recursively based upon find-replace, character place, fields, sequences, regular expressions, EXIF data, and more.', 'Utilities', 'tgrmnsoftware-bulkrenameutility-icon', ''),
('tidalmusicas-tidal', 'TIDAL', 'TIDAL is a global music streaming service with high fidelity sound, hi-def video quality, and expertly curated playlists.', 'Development', 'tidalmusicas-tidal-icon', ''),
('ttkn-cajviewer', 'CAJViewer', 'CAJViewer is a dedicated full-text format file viewer for China Journal Network that supports TEB, CAJ, NH, KDH and PDF. It can help you read not only the original text on the Internet, but also the full-text files downloaded from China Journal Network. Besides, the documents it printed look the same as the original.', 'Development', 'ttkn-cajviewer-icon', ''),
('ttkn-cajviewer-simple', 'CAJViewer (Simple Edition)', 'CAJViewer is a dedicated full-text format file viewer for China Journal Network that supports TEB, CAJ, NH, KDH and PDF. It can help you read not only the original text on the Internet, but also the full-text files downloaded from China Journal Network. Besides, the documents it printed look the same as the original.', 'Development', 'ttkn-cajviewer-simple-icon', ''),
('ttyplus-mtputty', 'MTPuTTY', 'wrap unlimited number of PuTTY applications in one tabbed GUI interface', 'Utilities', 'ttyplus-mtputty-icon', 'Native Linux Terminal'),
('tug-texworks', 'TeXworks', 'TeXworks is an environment for authoring TeX (LaTeX, ConTeXt, etc) documents, with a Unicode-based, TeX-aware editor, integrated PDF viewer, and a clean, simple interface accessible to casual and non-technical users.', 'Development', 'tug-texworks-icon', ''),
('tuittuwien-tutoolbox', 'TUtoolbox', 'A program to install all needed tools and patches for TU members.', 'Utilities', 'tuittuwien-tutoolbox-icon', ''),
('tableclothproject-tablecloth', 'TableCloth', 'This app helps to run internet services that are only available through the installation of accessories in an isolated environment.', 'Utilities', 'tableclothproject-tablecloth-icon', ''),
('tableplus-tableplus', 'TablePlus', 'Modern, native client with intuitive GUI tools to create, access, query & edit multiple relational databases MySQL, PostgreSQL, SQLite, Microsoft SQL Server, Amazon Redshift, MariaDB, CockroachDB, Vertica, Cassandra, and Redis.', 'Development', 'tableplus-tableplus-icon', ''),
('tableau-desktop', 'Tableau', 'Tableau Desktop is data visualization software that lets you see and understand data in minutes. With other Tableau products, it comprises a complete business intelligence software solution.', 'Design', 'tableau-desktop-icon', ''),
('tableau-public', 'Tableau Public', 'Tableau Public is free software that can allow anyone to connect to a spreadsheet or file and create interactive data visualizations for the web.', 'Office', 'tableau-public-icon', ''),
('tableau-reader', 'Tableau Reader', 'Tableau Reader is a free desktop application that you can use to open and interact with data visualisations built in Tableau Desktop', 'Design', 'tableau-reader-icon', ''),
