('tailwindlabs-tailwindcss', 'Tailwind CSS', 'Tailwind CSS works by scanning all of your HTML files, JavaScript components, and any other templates for class names, generating the corresponding styles and then writing them to a static CSS file. It''s fast, flexible, and reliable — with zero-runtime.', 'Utilities', 'tailwindlabs-tailwindcss-icon', ''),
('talkdesk-callbar', 'Callbar', 'Talkdesk Callbar is an application that allows users to make and receive calls via Talkdesk from their desktop or with an integrated product''s CTI, giving agents the power and the context needed to communicate with customers in real time.', 'Utilities', 'talkdesk-callbar-icon', ''),
('talkdesk-talkdesk', 'Talkdesk', 'Talkdesk', 'Utilities', 'talkdesk-talkdesk-icon', ''),
('taozuhong-kangaroo', 'Kangaroo', 'Modern, native SQL client and admin tool for popular databases MySQL, PostgreSQL, SQLite, MariaDB.', 'Development', 'taozuhong-kangaroo-icon', ''),
